(function(){
var c=document.getElementById('sp-canvas');
if(!c)return;
var ctx=c.getContext('2d');
var W,H,pts=[];
function resize(){W=c.width=window.innerWidth;H=c.height=window.innerHeight;}
resize();
window.addEventListener('resize',resize);
var colors=['rgba(255,255,255,','rgba(200,230,245,','rgba(255,255,255,','rgba(180,220,240,'];
for(var i=0;i<55;i++){
pts.push({
x:Math.random()*1,y:Math.random()*1,
vx:(Math.random()-.5)*.0003,vy:(Math.random()-.5)*.0003,
r:Math.random()*1.8+.4,
c:colors[Math.floor(Math.random()*colors.length)],
a:Math.random()*.5+.1,
pa:Math.random()*Math.PI*2,
ps:Math.random()*.015+.005
});
}
var raf;
function draw(){
ctx.clearRect(0,0,W,H);
for(var i=0;i<pts.length;i++){
var p=pts[i];
p.x+=p.vx;p.y+=p.vy;
if(p.x<0)p.x=1;if(p.x>1)p.x=0;
if(p.y<0)p.y=1;if(p.y>1)p.y=0;
p.pa+=p.ps;
var alpha=p.a*(0.5+0.5*Math.sin(p.pa));
ctx.beginPath();
ctx.arc(p.x*W,p.y*H,p.r,0,Math.PI*2);
ctx.fillStyle=p.c+alpha+')';
ctx.fill();
}
var sp=document.getElementById('splash');
if(sp&&!sp.classList.contains('out'))raf=requestAnimationFrame(draw);
else ctx.clearRect(0,0,W,H);
}
setTimeout(function(){draw();},100);
document.getElementById('splash').addEventListener('transitionend',function(){
if(raf)cancelAnimationFrame(raf);
},{once:true});
})();
