// Maps Plaid's Personal Finance Category taxonomy (primary + detailed) to this
// app's own category list. Plaid's legacy `category` field (which the old
// resolveParentCategory function below expected) is entirely absent for any
// account enabling Transactions on or after May 5, 2025 — this account has
// never had Transactions enabled before, so real production data will only
// ever include personal_finance_category, never the legacy field.
// See: https://plaid.com/documents/transactions-personal-finance-category-taxonomy.csv
function resolvePFCCategory(pfc) {
if(!pfc) return 'Other';
var primary  = (pfc.primary || '').toUpperCase();
var detailed = (pfc.detailed || '').toUpperCase();

if(primary === 'FOOD_AND_DRINK') return 'Food & Dining';

if(primary === 'TRANSPORTATION') {
if(detailed === 'TRANSPORTATION_GAS') return 'Auto & Gas';
return 'Transport';
}

if(primary === 'TRAVEL') return 'Travel';

if(primary === 'RENT_AND_UTILITIES') {
if(detailed === 'RENT_AND_UTILITIES_RENT') return 'Housing';
return 'Utilities';
}

if(primary === 'HOME_IMPROVEMENT') return 'Housing';

if(primary === 'LOAN_PAYMENTS') {
if(detailed === 'LOAN_PAYMENTS_MORTGAGE_PAYMENT') return 'Housing';
if(detailed === 'LOAN_PAYMENTS_CAR_PAYMENT') return 'Auto & Gas';
return 'Other';
}

if(primary === 'MEDICAL') return 'Health & Fitness';

if(primary === 'PERSONAL_CARE') {
if(detailed === 'PERSONAL_CARE_GYMS_AND_FITNESS_CENTERS') return 'Health & Fitness';
return 'Personal Care';
}

if(primary === 'GENERAL_MERCHANDISE') return 'Shopping';

if(primary === 'ENTERTAINMENT') return 'Entertainment';

if(primary === 'GENERAL_SERVICES') {
if(detailed === 'GENERAL_SERVICES_EDUCATION') return 'Education';
if(detailed === 'GENERAL_SERVICES_AUTOMOTIVE') return 'Auto & Gas';
if(detailed === 'GENERAL_SERVICES_INSURANCE') return 'Housing';
if(detailed === 'GENERAL_SERVICES_CHILDCARE') return 'Personal Care';
return 'Other';
}

if(primary === 'GOVERNMENT_AND_NON_PROFIT') {
if(detailed === 'GOVERNMENT_AND_NON_PROFIT_DONATIONS') return 'Gifts & Donations';
if(detailed === 'GOVERNMENT_AND_NON_PROFIT_TAX_PAYMENT') return 'Investments & Tax Accruals';
return 'Other';
}

if(primary === 'BANK_FEES') return 'Other';

if(primary === 'TRANSFER_OUT') {
if(detailed === 'TRANSFER_OUT_INVESTMENT_AND_RETIREMENT_FUNDS' || detailed === 'TRANSFER_OUT_SAVINGS')
return 'Investments & Tax Accruals';
return 'Other';
}

// INCOME and TRANSFER_IN are handled separately by mapPlaidTransaction's
// amount-sign check (Plaid uses negative amounts for money coming in), so
// they should rarely reach here on an expense transaction — but return a
// reasonable fallback if they somehow do.
if(primary === 'INCOME' || primary === 'TRANSFER_IN') return 'Other';

return 'Other';
}
// Retained for any other caller still passing the legacy string-array shape
// (e.g. historical transactions imported before this fix, or CSV imports that
// mimic the old format). Real Plaid API calls no longer produce this shape.
function resolveParentCategory(plaidCats) {
if(!plaidCats || !plaidCats.length) return 'Other';
var top = (plaidCats[0] || '').toLowerCase();
var sub = (plaidCats[1] || '').toLowerCase();
if(top === 'food and drink')                    return 'Food & Dining';
if(top === 'shops' && sub === 'groceries')      return 'Food & Dining';
if(top === 'shops')                             return 'Shopping';
if(top === 'travel' && sub === 'gas stations')  return 'Auto & Gas';
if(top === 'travel' && sub === 'airlines')      return 'Travel';
if(top === 'travel' && sub === 'hotels')        return 'Travel';
if(top === 'travel')                            return 'Transport';
if(top === 'payment' || top === 'bank fees')    return 'Housing';
if(top === 'recreation')                        return 'Entertainment';
if(top === 'healthcare')                        return 'Health & Fitness';
if(top === 'service')                           return 'Subscriptions';
if(top === 'transfer')                          return 'Investments & Tax Accruals';
if(top === 'tax')                               return 'Investments & Tax Accruals';
if(top === 'community')                         return 'Gifts & Donations';
if(top === 'cash advance')                      return 'Other';
return 'Other';
}
function mapPlaidTransaction(raw) {
if(!raw || !raw.transaction_id) return null;
var date = (raw.authorized_date || raw.date || '').trim();
var merchantRaw = (raw.merchant_name || raw.name || 'Unknown').trim();
var merchantNorm = normalizeMerchantOnIngest(merchantRaw);
var isIncome = typeof raw.amount === 'number' && raw.amount < 0;
var amount   = normalizeAmountOnIngest(raw.amount);
// Plaid's personal_finance_category is the only category field present on
// real transactions in production (the legacy `category` array was removed
// for any account enabling Transactions on/after May 5, 2025 — this app's
// account has never had Transactions enabled before, so it will only ever
// receive PFC data). raw.category is kept as a fallback purely in case any
// historical cached data still has the old shape.
var pfcResolved = raw.personal_finance_category
? resolvePFCCategory(raw.personal_finance_category)
: (raw.category ? resolveParentCategory(raw.category) : null);
var finalCat  = assignCategoryOnIngest(merchantRaw, null, null, 'Other', pfcResolved);
return normalizeTransactionShape({
id:           'plaid_' + raw.transaction_id,
type:         isIncome ? 'income' : 'expense',
amount:       amount,
date:         date,
merchantRaw:  merchantRaw,
merchantNorm: merchantNorm,
category:     finalCat,
note:        raw.pending ? 'Pending' : '',
importBatch: 'plaid_' + Date.now(),
_plaid_account_id:      raw.account_id      || null,
_plaid_payment_channel: raw.payment_channel || null,
_plaid_pending:         !!raw.pending
});
}
function dedupeTransactions(incomingTxs) {
if(!incomingTxs || !incomingTxs.length) return [];
var existingSigs = {};
(AppState.transactions||[]).forEach(function(t) {
if(t.sig) existingSigs[t.sig] = true;
if(t.id)  existingSigs[t.id]  = true;
});
return incomingTxs.filter(function(tx) {
if(!tx) return false;
if(tx.sig && existingSigs[tx.sig]) return false;
if(tx.id && existingSigs[tx.id]) return false;
if(isDuplicateTx(tx)) return false;
return true;
});
}
function dedupeByPlaidId(incomingTxs) {
if(!incomingTxs || !incomingTxs.length) return [];
var existingIds = {};
(AppState.transactions||[]).forEach(function(t) {
if(t.id) existingIds[t.id] = true;
});
return incomingTxs.filter(function(tx) {
if(!tx || !tx.id) return false;
return !existingIds[tx.id];
});
}
function dedupeAll() {
var txs = AppState.transactions || [];
if(txs.length < 2) return { removed: 0 };
var seenSigs = {};
var removed  = 0;
txs.forEach(function(tx, idx) {
if(!tx || tx._deleted) return;
if(tx.sig) {
if(seenSigs[tx.sig]) {
tx._deleted    = true;
tx._updated_at = new Date().toISOString();
if(typeof saveTxToDB === 'function') saveTxToDB(tx);
removed++;
return;
}
seenSigs[tx.sig] = true;
}
var earlier = txs.slice(0, idx).filter(function(t){ return t && !t._deleted; });
var norm    = normalizeMerchant(tx.merchantRaw || tx.merchant || '');
var d       = new Date((tx.date||'') + 'T12:00:00');
var dMinStr = getLocalDateStr(new Date(d.getTime() - 86400000)); // -1 day
var dMaxStr = getLocalDateStr(new Date(d.getTime() + 86400000)); // +1 day
var isFuzzyDupe = earlier.some(function(t) {
if(Math.abs(t.amount - tx.amount) > 0.01)        return false;
if(t.date < dMinStr || t.date > dMaxStr)          return false;
var tNorm = normalizeMerchant(t.merchantRaw || t.merchant || '');
return tNorm === norm;
});
if(isFuzzyDupe) {
tx._deleted    = true;
tx._updated_at = new Date().toISOString();
if(typeof saveTxToDB === 'function') saveTxToDB(tx);
removed++;
}
});
if(removed) {
invalidateAllCaches();
lsSave();
}
return { removed: removed };
}

function runPostSyncStateUpdate(result) {
var hasChanges = result && (
(result.added    && result.added    > 0) ||
(result.modified && result.modified > 0) ||
(result.removed  && result.removed  > 0) ||
(result.mode === 'initial')
);
if(!hasChanges) return result;
try {
if(typeof invalidateAllCaches === 'function') invalidateAllCaches();
if(typeof lsSave === 'function') lsSave();
if(typeof renderSyncStatus === 'function') renderSyncStatus();
if(typeof renderAll === 'function') renderAll();
if(typeof rAlerts === 'function') {
try { rAlerts(); } catch(e) {}
}
if(typeof rGoals === 'function') {
try { rGoals(); } catch(e) {}
}
} catch(e) {
}
return result;
}
function autoSyncOnLoad(minIntervalMs) {
if(typeof PlaidLinkManager === 'undefined' || !PlaidLinkManager.getState().linked) return;
var interval = typeof minIntervalMs === 'number' ? minIntervalMs : 300000; // 5 min default
var lastSync = AppState.lastSync || AppState.lastAccountSync;
if(lastSync) {
var msSinceLast = Date.now() - new Date(lastSync).getTime();
if(msSinceLast < interval) return; // too soon — skip
}
sync().catch(function(e) {
recordSyncError(e, 'autoSyncOnLoad');
});
}
function attachSyncButtonHandler(selector) {
var sel = selector || '#sync-now-btn';
var btn = document.querySelector(sel);
if(!btn || btn._syncHandlerAttached) return;
btn._syncHandlerAttached = true;
btn.addEventListener('click', function() {
if(AppState.syncStatus === 'syncing') {
toast('&#128257; Sync already in progress...');
return;
}
sync().then(function(result) {
if(typeof _renderConnectedUI === 'function') _renderConnectedUI();
}).catch(function(e) {
toast('&#9888; Sync failed: ' + (e && e.message || 'unknown error'));
});
}, { passive: true });
}
function recordSyncError(err, context) {
var msg = (err && (err.message || String(err))) || 'Unknown sync error';
var ctx = context || 'sync';
AppState.syncStatus    = 'error';
AppState.lastSyncError = msg;
if(typeof renderSyncStatus === 'function') {
try { renderSyncStatus(); } catch(re) {}
}
var banner = document.getElementById('sync-error-banner');
if(banner) {
banner.textContent = '\u26A0 ' + msg;
banner.style.display = 'block';
if(banner._hideTimer) clearTimeout(banner._hideTimer);
banner._hideTimer = setTimeout(function() {
banner.style.display = 'none';
}, 8000);
}
}
function renderSyncStatus() {
var el = document.getElementById('sync-status');
if(!el) return;
var status = AppState.syncStatus || 'idle';
el.className = '';
if(status === 'syncing') {
el.className  = 'syncing';
el.innerHTML = '&#128257; Syncing&hellip;';
el.innerHTML   = '&#128257; Syncing\u2026';
return;
}
if(status === 'error') {
el.className  = 'error';
var errMsg    = AppState.lastSyncError || 'Sync failed';
el.textContent = '\u26A0 ' + errMsg;
return;
}
if(status === 'success') {
var timeStr = '';
if(AppState.lastSync) {
try {
var d   = new Date(AppState.lastSync);
timeStr = ' \u00B7 ' + d.toLocaleTimeString([], { hour:'2-digit', minute:'2-digit' });
} catch(e) {}
}
el.className  = 'success';
el.innerHTML  = '&#10003; Synced' + timeStr;
if(el._hideTimer) clearTimeout(el._hideTimer);
el._hideTimer = setTimeout(function() {
el.className  = '';
el.textContent = '';
}, 5000);
return;
}
el.textContent = '';
}
function renderCloudSyncStatus() {
var el = document.getElementById('cloud-sync-status');
if(!el) return;
// Suppress all sync status banners — internal info, not user-facing
el.className = '';
el.innerHTML = '';
}
