// ══════════════════════════════════════════════════════════════════════════
// NAVIGATION STORE  (Boardwalk Master Spec — App-Wide Navigation System)
// Zustand-pattern client-side store. Exposes: currentRoute, setRoute()
// All screens subscribe via NavStore.subscribe(); BottomNav uses NavStore.
// ══════════════════════════════════════════════════════════════════════════

// ── Route Registry — all top-level routes + their page IDs ───────────────
var NAV_ROUTES = [
  // LOCKED ORDER: Insights | Autopilot | [Home-center] | Accounts | Settings
  { route: '/home',         page: 'Analytics',  label: 'Home',      navItem: 'home'      },
  { route: '/insights',     page: 'Budget',     label: 'Insights',  navItem: 'insights'  },
  { route: '/autopilot',    page: 'Autopilot',  label: 'Autopilot', navItem: 'autopilot' },
  { route: '/accounts',     page: 'Import',     label: 'Accounts',  navItem: 'accounts'  },
  { route: '/settings',     page: 'Settings',   label: 'Settings',  navItem: 'settings'  },
  // Secondary routes (no nav item)
  { route: '/budget',       page: 'Budget',     label: 'Budget',    navItem: 'insights'  },
  { route: '/transactions', page: 'Home',       label: 'Txns',      navItem: null        },
  { route: '/bills',        page: 'Recurring',  label: 'Bills',     navItem: null        },
  { route: '/goals',        page: 'Goals',      label: 'Goals',     navItem: null        },
  { route: '/alerts',       page: 'Alerts',     label: 'Alerts',    navItem: null        },
  { route: '/household',    page: 'Household',  label: 'Household', navItem: null        }
];

// ── NavigationStore (Zustand-pattern, vanilla JS module) ─────────────────
var NavStore = (function() {
  var _state = {
    currentRoute:  '/home',
    currentPage:   'Analytics',
    prevRoute:     null,
    prevPage:      null,
    listeners:     []
  };

  // Resolve page name → canonical route
  function _pageToRoute(pageName) {
    var entry = NAV_ROUTES.find(function(r){ return r.page === pageName; });
    return entry ? entry.route : '/home';
  }
  // Resolve route → page name
  function _routeToPage(route) {
    var entry = NAV_ROUTES.find(function(r){ return r.route === route; });
    return entry ? entry.page : 'Analytics';
  }
  // Notify all subscribers
  function _emit() {
    _state.listeners.forEach(function(fn){ try{ fn(_state); }catch(e){} });
  }

  return {
    // ── getState ──────────────────────────────────────────────────────────
    getState: function() {
      return {
        currentRoute: _state.currentRoute,
        currentPage:  _state.currentPage,
        prevRoute:    _state.prevRoute,
        prevPage:     _state.prevPage
      };
    },

    // ── setRoute(route) — primary navigation entry point ─────────────────
    setRoute: function(route) {
      var pageName = _routeToPage(route);
      _state.prevRoute  = _state.currentRoute;
      _state.prevPage   = _state.currentPage;
      _state.currentRoute = route;
      _state.currentPage  = pageName;
      _emit();
      // Delegate to existing gp() engine
      gp(pageName, null);
    },

    // ── navigate(page, btn) — called by nav buttons (page-first) ─────────
    navigate: function(pageName, btn) {
      var route = _pageToRoute(pageName);
      _state.prevRoute  = _state.currentRoute;
      _state.prevPage   = _state.currentPage;
      _state.currentRoute = route;
      _state.currentPage  = pageName;
      _emit();
      gp(pageName, btn);
    },

    // ── syncFromPage(page) — called by gp() to keep store in sync ────────
    syncFromPage: function(pageName) {
      _state.currentRoute = _pageToRoute(pageName);
      _state.currentPage  = pageName;
      _emit();
    },

    // ── subscribe(fn) — fn receives state on every navigation ────────────
    subscribe: function(fn) {
      _state.listeners.push(fn);
      return function unsubscribe() {
        _state.listeners = _state.listeners.filter(function(l){ return l !== fn; });
      };
    },

    // ── updateActiveNav(pageName) — update BottomNav active states ────────
    updateActiveNav: function(pageName) {
      // Clear all active states
      document.querySelectorAll('.nb').forEach(function(b){
        b.classList.remove('on');
        b.setAttribute('aria-current','false');
      });
      var homeBtn = document.getElementById('nav-home');
      if(homeBtn) {
        homeBtn.classList.remove('on');
        homeBtn.setAttribute('aria-current','false');
      }

      // HOME (Analytics) → center #nav-home button
      // LOCKED: nav-home is always Home. Never reassigned.
      if(pageName === 'Analytics') {
        if(homeBtn) {
          homeBtn.classList.add('on');
          homeBtn.setAttribute('aria-current','page');
        }
      } else {
        // Match by data-page attribute on .nb buttons
        var match = document.querySelector('.nb[data-page="'+pageName+'"]');
        if(match) {
          match.classList.add('on');
          match.setAttribute('aria-current','page');
        }
      }
    },

    // ── registerRoutes() — wire all nav buttons to NavStore ──────────────
    registerRoutes: function() {
      var btns = document.querySelectorAll('.nb[data-page]');
      dbg('[NavStore] registering ' + btns.length + ' nav buttons');
      btns.forEach(function(btn) {
        var page  = btn.getAttribute('data-page');
        var route = btn.getAttribute('data-route') || _pageToRoute(page);

        btn.addEventListener('touchend', function(e) {
          // Don't intercept touch when a compass modal is open
          if (document.body.classList.contains('cmodal-open')) return;
          e.preventDefault();
          e.stopPropagation();
          haptic(8);
          NavStore.navigate(page, btn);
        }, {passive: false});

        btn.addEventListener('click', function(e) {
          // Don't intercept click when a compass modal is open
          if (document.body.classList.contains('cmodal-open')) return;
          e.preventDefault();
          e.stopPropagation();
          NavStore.navigate(page, btn);
        }, true);
      });

      // Subscribe to keep nav highlighted on every route change
      NavStore.subscribe(function(state) {
        NavStore.updateActiveNav(state.currentPage);
      });

      dbg('[NavStore] routes registered');
    }
  };
})();

