if(currentPageName !== name) {
editId = null;
_routerState.editingId = null;
dbg('[ROUTER] Reset edit context on navigation to '+name);
// Unmount Goals UI Shell when leaving Goals page
if (currentPageName === 'Goals' && typeof GoalsShell !== 'undefined') {
try { GoalsShell.unmount(); } catch(e) {}
}
}
