var active = crits.length ? crits : warns.length ? warns : [];
if(!active.length){ ab.style.display='none'; return; }
var isCrit = crits.length > 0;
ab.style.display='flex';
ab.style.flexDirection='column';
ab.style.background='rgba(126,200,227,.18)';
