var summaryHtml = '<div style="display:flex;align-items:center;gap:var(--xs);width:100%">'+'<span style="flex-shrink:0;display:flex;align-items:center;"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="'+strokeColor+'" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg></span>'+'<span id="atxt" style="flex:1;color:'+titleColor+';font-weight:600;">'+active[0].title+(active.length>1?' (+' + (active.length-1) + ' more)':'')+'</span>'+'<span style="font-size:var(--fs-caption);color:'+chevronColor+';">'+chevron+'</span>'+'</div>';
