+'<div class="srow"><span style="color:var(--sub)">Worst month</span><span style="font-weight:700;color:var(--red)">'+formatMk(worstMonth.key)+' ('+fmt(Math.abs(worstMonth.net))+')</span></div>'
+'<div class="srow"><span style="color:var(--sub)">Positive net streak</span><span style="font-weight:700">'+streak+' month'+(streak===1?'':'s')+'</span></div>'
+'<div class="srow"><span style="color:var(--sub)">Top category</span><span style="font-weight:700">'+(CEM[topCat]||'')+' '+esc(topCat)+'</span></div>'
+(largestExp&&largestExp.amount?'<div class="srow"><span style="color:var(--sub)">Largest expense</span><span style="font-weight:700;color:var(--red)">'+fmt(largestExp.amount)+(largestExp.merchantNorm?' &middot; '+esc(largestExp.merchantNorm):'')+'</span></div>':'')
+(velPct!==null?'<div class="srow"><span style="color:var(--sub)">vs last month</span><span style="font-weight:700;color:'+(parseFloat(velPct)>0?'var(--red)':'var(--em)')+'">'+( parseFloat(velPct)>0?'+':'')+velPct+'%</span></div>':'')
+'<div class="srow"><span style="color:var(--sub)">Merchants learned</span><span style="font-weight:700">'+Object.keys(AppState.merchantMem).length+'</span></div>'
+'</div>'
+'<div class="stitle">All-Time Category Breakdown</div>'
