function saveRecurRule(){
var name=document.getElementById('rmod-name').value.trim();
var amt =parseFloat(document.getElementById('rmod-amt').value);
if(!name){toast('Enter a rule name');return;}
if(!amt||amt<=0){toast('Enter a valid amount');return;}
var newCat = document.getElementById('rmod-cat').value;

// Capture original rule snapshot BEFORE modifying
var _origRule = _recurEditId ? AppState.recurRules.find(function(r){return r.id===_recurEditId;}) : null;
var _origRuleSnap = _origRule ? Object.assign({}, _origRule) : null;
var _oldBillCat = _origRuleSnap ? (_origRuleSnap.category || '') : '';
var _billCatChanged = !!_recurEditId && _oldBillCat !== newCat;

var rule={
id:         _recurEditId||String(Date.now()),
name:       name,
type:       _recurType,
amount:     amt,
category:   newCat,
_updated_at: new Date().toISOString(),
freq:       document.getElementById('rmod-freq').value,
dayOfMonth: (function(){ var v=parseInt(document.getElementById('rmod-day').value); return isFinite(v) ? Math.min(31, Math.max(1, v)) : null; })(),
keyword:    document.getElementById('rmod-kw').value.trim().toLowerCase(),
tolerance:  Math.min(50, Math.max(0, parseFloat(document.getElementById('rmod-tol').value)||10)),
active:     true,
lastMatched:null
};
if(_recurEditId){
var existing=AppState.recurRules.find(function(r){return r.id===_recurEditId;});
if(existing){
rule.lastMatched=existing.lastMatched;
rule.nextDue    =existing.nextDue    ||null;
rule.lastPaid   =existing.lastPaid   ||null;
rule.payHistory =existing.payHistory ||[];
rule.autoGenerate=existing.autoGenerate||false;
rule.autoDetected=existing.autoDetected||false;
rule.confidence  =existing.confidence  ||null;
}
AppState.recurRules=AppState.recurRules.map(function(r){return r.id===_recurEditId?rule:r;});
} else {
AppState.recurRules.push(rule);
}

// ── BILL CATEGORY-CHANGE BRANCH ─────────────────────────────────────────────
if(_billCatChanged && rule.keyword) {
var _billNorm = rule.keyword;
var _otherBillCount = AppState.recurRules.filter(function(r){
return r.id !== rule.id &&
(r.keyword === _billNorm || r.name.toLowerCase().trim() === name.toLowerCase().trim()) &&
(r.category || '') !== newCat;
}).length;
if(_otherBillCount > 0) {
// Save this rule first, then close sheet, then show modal
saveMeta();
disableScrollLock();
document.getElementById('rov').style.display='none';
showBulkBillCatModal(
_billNorm,
name,
newCat,
_oldBillCat,
_otherBillCount,
// onAll
function(){ _doBulkBillUpdate('all', _billNorm, name, newCat, rule.id); },
// onYear
function(){ _doBulkBillUpdate('year', _billNorm, name, newCat, rule.id); },
// onOne
function(){ _doBulkBillUpdate('one', _billNorm, name, newCat, rule.id); },
// onCancel
function(){
AppState.recurRules = AppState.recurRules.map(function(r){
return r.id === rule.id ? Object.assign({}, r, {category: _oldBillCat}) : r;
});
saveMeta(); rRecurring(); toast('Bill edit cancelled');
}
);
return;
}
// Category changed but no other bills to update — still remember + finish
rememberBillVendor(_billNorm, newCat);
}

saveMeta();
disableScrollLock();
document.getElementById('rov').style.display='none';
rRecurring();
toast(_recurEditId?'Rule updated!':'Rule created!');
}
function delRecurRule(id){
var delId=id||_recurEditId;
if(!delId)return;
if(!confirm('Delete this recurring rule?'))return;
var today=getTodayStr();
var removedCount=0;
AppState.transactions=AppState.transactions.filter(function(t){
if(t.recurRuleId===delId && t.date>today){ removedCount++; return false; }
return true;
});
AppState.recurRules=AppState.recurRules.filter(function(r){return r.id!==delId;});
saveMeta();
if(removedCount) lsSave();
disableScrollLock();
document.getElementById('rov').style.display='none';
rRecurring();toast('Rule deleted'+(removedCount?' — removed '+removedCount+' upcoming transaction'+(removedCount>1?'s':''):''));
}
function toggleRecurActive(id){
var rule=AppState.recurRules.find(function(r){return r.id===id;});
if(!rule)return;
rule.active=!rule.active;
saveMeta();rRecurring();
toast(rule.active?'Rule resumed':'Rule paused');
}
