var _inpCb = null;
var _cfmCb = null;
function showInp(title, placeholder, cb, showAmt, amtPlaceholder) {
document.getElementById('inp-title').textContent = title;
var v = document.getElementById('inp-val');
v.placeholder = placeholder || '';
v.value = '';
var v2 = document.getElementById('inp-val2');
if (showAmt) {
v2.style.display = 'block';
v2.placeholder = amtPlaceholder || 'Amount';
v2.value = '';
} else {
v2.style.display = 'none';
v2.value = '';
}
_inpCb = cb;
document.getElementById('inp-ov').style.display = 'flex';
setTimeout(function(){ v.focus(); }, 150);
}
function showInpPrefill(title, prefill, cb) {
document.getElementById('inp-title').textContent = title;
var v = document.getElementById('inp-val');
v.placeholder = '';
v.value = prefill || '';
document.getElementById('inp-val2').style.display = 'none';
_inpCb = cb;
document.getElementById('inp-ov').style.display = 'flex';
setTimeout(function(){ v.focus(); v.select(); }, 150);
}
function inpConfirm() {
var val = document.getElementById('inp-val').value.trim();
var val2 = document.getElementById('inp-val2').value;
document.getElementById('inp-ov').style.display = 'none';
if (_inpCb && val) _inpCb(val, val2);
_inpCb = null;
}
function inpCancel() {
document.getElementById('inp-ov').style.display = 'none';
_inpCb = null;
}
var _cfmTrigger = null;
function showCfm(msg, okLabel, cb) {
document.getElementById('cfm-msg').textContent = msg;
document.getElementById('cfm-ok').textContent = okLabel || 'Delete';
document.getElementById('cfm-ok').style.background = (okLabel && okLabel !== 'Delete') ? 'var(--gd)' : 'var(--red)';
_cfmCb = cb;
_cfmTrigger = _captureFocusTrigger();
enableScrollLock();
document.getElementById('cfm-ov').style.display = 'flex';
var cancelBtn = document.getElementById('cfm-cancel');
if (cancelBtn) cancelBtn.focus();
}
function _cfmRestoreFocus() {
if (_cfmTrigger && typeof _cfmTrigger.focus === 'function' && document.contains(_cfmTrigger)) _cfmTrigger.focus();
_cfmTrigger = null;
}
function cfmConfirm() {
document.getElementById('cfm-ov').style.display = 'none';
disableScrollLock();
_cfmRestoreFocus();
if (_cfmCb) _cfmCb();
_cfmCb = null;
}
function cfmCancel() {
document.getElementById('cfm-ov').style.display = 'none';
disableScrollLock();
_cfmRestoreFocus();
_cfmCb = null;
}
// --- Bulk category update ---
// ── BILL VENDOR MEMORY ──────────────────────────────────────────────────────
// ═══════════════════════════════════════════════════════════════════════════
// UNIFIED BULK CATEGORY UPDATE SYSTEM — Transactions + Bills
// ═══════════════════════════════════════════════════════════════════════════

// ── Vendor memory ────────────────────────────────────────────────────────────
function rememberBillVendor(billNorm, category) {
if (!billNorm) return;
if (!AppState.merchantMem) AppState.merchantMem = {};
var existing = AppState.merchantMem['bill:'+billNorm] || {count:0};
AppState.merchantMem['bill:'+billNorm] = {
category: category, count: existing.count + 1,
lastSeen: new Date().toISOString().split('T')[0]
};
saveMeta();
}

// ── Transaction bulk helpers ─────────────────────────────────────────────────
function bulkUpdateAll(merchantNorm, newCat) {
var ts = new Date().toISOString(); var count = 0;
AppState.transactions.forEach(function(t) {
if (t.merchantNorm !== merchantNorm) return;
if (t.category === newCat) return;
t.category = newCat; t._updated_at = ts;
dbPut('transactions', t); count++;
});
rememberMerchant(merchantNorm, newCat);
return count;
}
function bulkUpdateRecent(merchantNorm, newCat) {
var ts = new Date().toISOString();
var cutoff = (function(){ var d=new Date(); d.setFullYear(d.getFullYear()-1);
return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0'); })();
var count = 0;
AppState.transactions.forEach(function(t) {
if (t.merchantNorm !== merchantNorm) return;
if (t.category === newCat) return;
if (t.date < cutoff) return;
t.category = newCat; t._updated_at = ts;
dbPut('transactions', t); count++;
});
rememberMerchant(merchantNorm, newCat);
return count;
}
function bulkUpdateOne(merchantNorm, newCat) {
rememberMerchant(merchantNorm, newCat); return 0;
}

// ── Bill bulk helpers ─────────────────────────────────────────────────────────
function bulkUpdateBillsAll(billNorm, billName, newCat, excludeId) {
var ts = new Date().toISOString(); var count = 0;
AppState.recurRules.forEach(function(r) {
if (r.id === excludeId) return;
var nm = r.name && r.name.toLowerCase().trim() === billName.toLowerCase().trim();
var kw = r.keyword && r.keyword === billNorm;
if (!nm && !kw) return;
if ((r.category||'') === newCat) return;
r.category = newCat; r._updated_at = ts; count++;
});
rememberBillVendor(billNorm, newCat);
return count;
}
function bulkUpdateBillsRecent(billNorm, billName, newCat, excludeId) {
var ts = new Date().toISOString();
var cutoffMs = Date.now() - (365*24*60*60*1000); var count = 0;
AppState.recurRules.forEach(function(r) {
if (r.id === excludeId) return;
var nm = r.name && r.name.toLowerCase().trim() === billName.toLowerCase().trim();
var kw = r.keyword && r.keyword === billNorm;
if (!nm && !kw) return;
if ((r.category||'') === newCat) return;
var ref = r.lastPaid || r.lastMatched || null;
if (ref) { var ms = new Date(ref).getTime(); if (!isNaN(ms) && ms < cutoffMs) return; }
r.category = newCat; r._updated_at = ts; count++;
});
rememberBillVendor(billNorm, newCat);
return count;
}
function bulkUpdateBillsOne(billNorm, newCat) {
rememberBillVendor(billNorm, newCat); return 0;
}

// ── Goal bulk-category helpers ────────────────────────────────────────────────
function bulkUpdateGoalAll(goalId, newCat) {
var ts = new Date().toISOString(); var count = 0;
var src = AppState.goals.find(function(g){ return g.id === goalId; });
if(!src) return count;
var oldCat = src.linkedCat || null;
(AppState.goals||[]).forEach(function(g) {
if (g.id === goalId) return;
if ((g.linkedCat||null) !== oldCat) return;
if (g.linkedCat === newCat) return;
g.linkedCat = newCat;
if ('_updated_at' in g) g._updated_at = ts;
saveGoalToDB(g); count++;
});
return count;
}
function bulkUpdateGoalRecent(goalId, newCat) {
var ts = new Date().toISOString();
var cutoff = (function(){
var d = new Date(); d.setFullYear(d.getFullYear()-1);
return d.toISOString().split('T')[0];
}());
var count = 0;
var src = AppState.goals.find(function(g){ return g.id === goalId; });
if(!src) return count;
var oldCat = src.linkedCat || null;
(AppState.goals||[]).forEach(function(g) {
if (g.id === goalId) return;
if ((g.linkedCat||null) !== oldCat) return;
if (g.linkedCat === newCat) return;
var ref = (g.createdAt || '').split('T')[0];
if (ref && ref < cutoff) return;
g.linkedCat = newCat;
if ('_updated_at' in g) g._updated_at = ts;
saveGoalToDB(g); count++;
});
return count;
}
function bulkUpdateGoalOne(goalId, newCat) {
var ts = new Date().toISOString();
var g = AppState.goals.find(function(g){ return g.id === goalId; });
if(!g) return 0;
g.linkedCat = newCat;
if ('_updated_at' in g) g._updated_at = ts;
saveGoalToDB(g);
return 1;
}
function rememberGoalCategory(goalId, newCat) {
if (!goalId || !newCat) return;
if (!AppState.merchantMem) AppState.merchantMem = {};
AppState.merchantMem['goal:'+goalId] = {
category: newCat,
lastSeen: new Date().toISOString().split('T')[0]
};
saveMeta();
}

// ── Goal Progress Engine ──────────────────────────────────────────────────────
function computeDailyVelocity(goal) {
var contribs = goal.contributions || [];
if (!contribs.length) return 0;
var now = new Date();
now.setHours(0, 0, 0, 0);
var cutoff = new Date(now.getTime() - 30 * 86400000);
var total = 0;
contribs.forEach(function(c) {
if (!c.date || !c.amount) return;
var d = new Date(c.date + 'T00:00:00');
if (isNaN(d.getTime())) return;
if (d >= cutoff) total += parseFloat(c.amount) || 0;
});
return total / 30;
}

function computeGoalProgress(goal) {
var saved     = parseFloat(goal.saved)  || 0;
var target    = parseFloat(goal.target) || 0;
var percent   = target > 0 ? Math.min(100, Math.round((saved / target) * 100)) : 0;
var remaining = Math.max(0, target - saved);
var vDay      = computeDailyVelocity(goal);
var vWeek     = vDay * 7;
var vMonth    = vDay * 30;
var daysToTarget = null;
var projectedCompletionDate = null;
if (vDay > 0 && remaining > 0) {
daysToTarget = Math.ceil(remaining / vDay);
projectedCompletionDate = new Date(Date.now() + daysToTarget * 86400000);
} else if (remaining <= 0) {
daysToTarget = 0;
projectedCompletionDate = new Date();
}
return {
percent:                 percent,
saved:                   saved,
target:                  target,
remaining:               remaining,
velocityDaily:           vDay,
velocityWeekly:          vWeek,
velocityMonthly:         vMonth,
daysToTarget:            daysToTarget,
projectedCompletionDate: projectedCompletionDate
};
}

function computeGoalStatus(progress) {
if (progress.saved <= 0)                          return 'not_started';
if (progress.saved >= progress.target)            return 'completed';
return 'in_progress';
}

function computeGoalHealth(goal, progress) {
if (!goal.targetDate)                             return 'no_deadline';
if (!progress.projectedCompletionDate)            return 'insufficient_data';
var deadline = new Date(goal.targetDate + 'T00:00:00');
if (isNaN(deadline.getTime()))                    return 'no_deadline';
var proj = progress.projectedCompletionDate;
var diffDays = Math.round((proj.getTime() - deadline.getTime()) / 86400000);
if (diffDays < -1)  return 'ahead';
if (diffDays <= 1)  return 'on_track';
return 'behind';
}

function computeAllGoalProgress(goals) {
return (goals || []).map(function(g) {
var progress = computeGoalProgress(g);
return {
id:           g.id,
name:         g.name,
target:       g.target,
saved:        g.saved,
targetDate:   g.targetDate || null,
linkedCat:    g.linkedCat  || null,
color:        g.color,
icon:         g.icon,
contributions: g.contributions || [],
createdAt:    g.createdAt,
progress:     progress,
status:       computeGoalStatus(progress),
health:       computeGoalHealth(g, progress)
};
});
}
// ── End Goal Progress Engine ──────────────────────────────────────────────────

// ── Goal Forecasting System ───────────────────────────────────────────────────
function computeBehavioralVelocity(goal) {
var contribs = goal.contributions || [];
var now = new Date();
now.setHours(0,0,0,0);
var cutoff = new Date(now.getTime() - 90 * 86400000);
var daily = {};
contribs.forEach(function(c) {
if (!c.date || !c.amount) return;
var d = new Date(c.date + 'T00:00:00');
if (isNaN(d.getTime()) || d < cutoff) return;
var key = c.date;
daily[key] = (daily[key] || 0) + (parseFloat(c.amount) || 0);
});
var days = Object.keys(daily);
if (!days.length) return { meanDaily: 0, stddev: 0, consistency: 0 };
var total = 0;
days.forEach(function(k) { total += daily[k]; });
var mean = total / 90;
var variance = 0;
for (var i = 0; i < 90; i++) {
var key2 = new Date(cutoff.getTime() + i * 86400000).toISOString().slice(0,10);
var val = daily[key2] || 0;
variance += Math.pow(val - mean, 2);
}
var stddev = Math.sqrt(variance / 90);
var consistency = 1 / (1 + stddev);
return { meanDaily: mean, stddev: stddev, consistency: consistency };
}

function computeProjectedCompletion(meanDaily, remaining) {
if (meanDaily <= 0 || remaining <= 0) return null;
var days = Math.ceil(remaining / meanDaily);
return new Date(Date.now() + days * 86400000);
}

function computeConfidenceInterval(meanDaily, stddev, remaining) {
var lowVelocity  = Math.max(0, meanDaily - stddev);
var highVelocity = meanDaily + stddev;
var low  = null;
var high = null;
if (highVelocity > 0) {
var lowDays = Math.ceil(remaining / highVelocity);
low = new Date(Date.now() + lowDays * 86400000);
}
if (lowVelocity > 0) {
var highDays = Math.ceil(remaining / lowVelocity);
high = new Date(Date.now() + highDays * 86400000);
}
return { low: low, high: high };
}

function computeDeadlineRequirements(goal, remaining) {
if (!goal.targetDate) return { requiredDaily: null, requiredWeekly: null };
var deadline = new Date(goal.targetDate + 'T00:00:00');
if (isNaN(deadline.getTime())) return { requiredDaily: null, requiredWeekly: null };
var now = new Date(); now.setHours(0,0,0,0);
var daysLeft = Math.max(1, Math.ceil((deadline.getTime() - now.getTime()) / 86400000));
var requiredDaily  = remaining / daysLeft;
var requiredWeekly = requiredDaily * 7;
return { requiredDaily: requiredDaily, requiredWeekly: requiredWeekly };
}

function computeForecastStatus(projectedDate, deadline) {
if (!deadline) return 'no_deadline';
if (!projectedDate) return 'insufficient_data';
var dl = new Date(deadline + 'T00:00:00');
if (isNaN(dl.getTime())) return 'no_deadline';
var diffDays = Math.round((projectedDate.getTime() - dl.getTime()) / 86400000);
if (diffDays < -1) return 'ahead';
if (diffDays <= 1)  return 'on_track';
return 'behind';
}

function computeRiskLevel(stddev, consistency) {
if (stddev > 20 || consistency < 0.05) return 'high';
if (stddev > 5  || consistency < 0.15) return 'medium';
return 'low';
}

function forecastGoal(goal, progress) {
var remaining = progress ? progress.remaining : Math.max(0, (parseFloat(goal.target)||0) - (parseFloat(goal.saved)||0));
var bv       = computeBehavioralVelocity(goal);
var projected = computeProjectedCompletion(bv.meanDaily, remaining);
var ci        = computeConfidenceInterval(bv.meanDaily, bv.stddev, remaining);
var dr        = computeDeadlineRequirements(goal, remaining);
var status    = computeForecastStatus(projected, goal.targetDate || null);
var riskLevel = computeRiskLevel(bv.stddev, bv.consistency);
return {
projectedDate:               projected,
confidenceLow:               ci.low,
confidenceHigh:              ci.high,
requiredDailyToHitDeadline:  dr.requiredDaily,
requiredWeeklyToHitDeadline: dr.requiredWeekly,
status:                      status,
risk: {
volatility:       bv.stddev,
consistencyScore: bv.consistency,
riskLevel:        riskLevel
}
};
}

function forecastAllGoals(goals, progressMap) {
return (goals || []).map(function(g) {
var progress = progressMap && progressMap[g.id] ? progressMap[g.id] : computeGoalProgress(g);
var forecast = forecastGoal(g, progress);
return Object.assign({}, g, { forecast: forecast });
});
}
// ── End Goal Forecasting System ───────────────────────────────────────────────

// ── Goal Analytics Dashboard ──────────────────────────────────────────────────
function computeGoalTrend(goal) {
var contribs = goal.contributions || [];
var now = new Date(); now.setHours(0,0,0,0);
var cutoff = new Date(now.getTime() - 180 * 86400000);
var daily = [], weekly = {}, monthly = {};
contribs.forEach(function(c) {
if (!c.date || !c.amount) return;
var d = new Date(c.date + 'T00:00:00');
if (isNaN(d.getTime()) || d < cutoff) return;
var amt = parseFloat(c.amount) || 0;
daily.push({ date: c.date, amount: amt });
// ISO week key: year + week number
var jan1 = new Date(d.getFullYear(), 0, 1);
var weekNum = Math.ceil(((d - jan1) / 86400000 + jan1.getDay() + 1) / 7);
var weekStart = new Date(d.getTime() - d.getDay() * 86400000);
var wk = weekStart.toISOString().slice(0,10);
weekly[wk] = (weekly[wk] || 0) + amt;
var mo = c.date.slice(0,7);
monthly[mo] = (monthly[mo] || 0) + amt;
});
daily.sort(function(a,b){ return a.date < b.date ? -1 : 1; });
var weeklyArr = Object.keys(weekly).sort().map(function(k){ return { weekStart: k, total: weekly[k] }; });
var monthlyArr = Object.keys(monthly).sort().map(function(k){ return { month: k, total: monthly[k] }; });
return { daily: daily, weekly: weeklyArr, monthly: monthlyArr };
}

function computeContributionBreakdown(goal) {
var contribs = goal.contributions || [];
if (!contribs.length) return { totalContributions: 0, avgContribution: 0, largestContribution: 0, smallestContribution: 0, contributionCount: 0 };
var amounts = contribs.map(function(c){ return parseFloat(c.amount) || 0; }).filter(function(a){ return a > 0; });
if (!amounts.length) return { totalContributions: 0, avgContribution: 0, largestContribution: 0, smallestContribution: 0, contributionCount: 0 };
var total = amounts.reduce(function(s,a){ return s+a; }, 0);
return {
totalContributions:  total,
avgContribution:     total / amounts.length,
largestContribution: Math.max.apply(null, amounts),
smallestContribution:Math.min.apply(null, amounts),
contributionCount:   amounts.length
};
}

function computeCategoryBreakdown(goals) {
var map = {};
(goals || []).forEach(function(g) {
var cat = g.linkedCat || g.category || 'Uncategorized';
if (!map[cat]) map[cat] = { category: cat, totalSaved: 0, goalCount: 0 };
map[cat].totalSaved += parseFloat(g.saved) || 0;
map[cat].goalCount  += 1;
});
return Object.keys(map).map(function(k){ return map[k]; });
}

function computeVelocityHistory(goal) {
var contribs = goal.contributions || [];
var now = new Date(); now.setHours(0,0,0,0);
// daily velocity: rolling 30-day window per day over last 30 days
var dailyVelocity = [];
for (var i = 29; i >= 0; i--) {
var dayEnd = new Date(now.getTime() - i * 86400000);
var dayStart = new Date(dayEnd.getTime() - 30 * 86400000);
var sum = 0;
contribs.forEach(function(c) {
if (!c.date || !c.amount) return;
var d = new Date(c.date + 'T00:00:00');
if (d >= dayStart && d <= dayEnd) sum += parseFloat(c.amount) || 0;
});
dailyVelocity.push({ date: dayEnd.toISOString().slice(0,10), velocity: sum / 30 });
}
// weekly velocity: rolling 12-week windows
var weeklyVelocity = [];
for (var w = 11; w >= 0; w--) {
var wEnd = new Date(now.getTime() - w * 7 * 86400000);
var wStart = new Date(wEnd.getTime() - 12 * 7 * 86400000);
var wSum = 0;
contribs.forEach(function(c) {
if (!c.date || !c.amount) return;
var d = new Date(c.date + 'T00:00:00');
if (d >= wStart && d <= wEnd) wSum += parseFloat(c.amount) || 0;
});
weeklyVelocity.push({ weekStart: wEnd.toISOString().slice(0,10), velocity: wSum / 12 });
}
return { dailyVelocity: dailyVelocity, weeklyVelocity: weeklyVelocity };
}

function computeGoalSummary(goal, progress, forecast) {
return {
name:           goal.name,
percent:        progress.percent,
remaining:      progress.remaining,
projectedDate:  forecast.projectedDate,
status:         forecast.status,
riskLevel:      forecast.risk.riskLevel,
requiredDaily:  forecast.requiredDailyToHitDeadline,
requiredWeekly: forecast.requiredWeeklyToHitDeadline
};
}

function computePortfolioSummary(goals, progressMap, forecastMap) {
var list = goals || [];
var totalGoals      = list.length;
var completedGoals  = 0;
var inProgressGoals = 0;
var upcomingGoals   = 0;
var totalSaved      = 0;
var totalRemaining  = 0;
var percentSum      = 0;
var velDaySum       = 0;
var velWeekSum      = 0;
list.forEach(function(g) {
var p = progressMap && progressMap[g.id] ? progressMap[g.id] : computeGoalProgress(g);
totalSaved     += p.saved;
totalRemaining += p.remaining;
percentSum     += p.percent;
velDaySum      += p.velocityDaily;
velWeekSum     += p.velocityWeekly;
var status = computeGoalStatus(p);
if (status === 'completed')   completedGoals++;
else if (status === 'in_progress') inProgressGoals++;
else upcomingGoals++;
});
var n = totalGoals || 1;
return {
totalGoals:        totalGoals,
completedGoals:    completedGoals,
inProgressGoals:   inProgressGoals,
upcomingGoals:     upcomingGoals,
totalSaved:        totalSaved,
totalRemaining:    totalRemaining,
avgPercentComplete:percentSum / n,
avgVelocityDaily:  velDaySum  / n,
avgVelocityWeekly: velWeekSum / n
};
}

function computeAnalyticsForAllGoals(goals, progressMap, forecastMap) {
return (goals || []).map(function(g) {
var progress = progressMap && progressMap[g.id] ? progressMap[g.id] : computeGoalProgress(g);
var forecast = forecastMap && forecastMap[g.id] ? forecastMap[g.id] : forecastGoal(g, progress);
var trend         = computeGoalTrend(g);
var breakdown     = computeContributionBreakdown(g);
var velocityHistory = computeVelocityHistory(g);
var summary       = computeGoalSummary(g, progress, forecast);
return Object.assign({}, g, {
analytics: {
trend:           trend,
breakdown:       breakdown,
velocityHistory: velocityHistory,
summary:         summary
}
});
});
}
// ── End Goal Analytics Dashboard ─────────────────────────────────────────────

// ── Goal Autopilot Contributions Engine ──────────────────────────────────────
function computeGoalPriorityScore(goal, progress, forecast) {
var score = 0;
var risk = forecast && forecast.risk ? forecast.risk.riskLevel : 'low';
var status = forecast ? forecast.status : 'no_deadline';
var consistency = forecast && forecast.risk ? forecast.risk.consistencyScore : 1;
var remaining = progress ? progress.remaining : Math.max(0, (parseFloat(goal.target)||0) - (parseFloat(goal.saved)||0));
var velocityDaily = progress ? progress.velocityDaily : 0;
var requiredDaily = forecast ? (forecast.requiredDailyToHitDeadline || 0) : 0;
if (risk === 'high')        score += 30;
else if (risk === 'medium') score += 15;
if (status === 'behind')    score += 25;
else if (status === 'on_track') score += 10;
if (consistency < 0.05)     score += 20;
else if (consistency < 0.15) score += 10;
var remainingPts = Math.min(15, Math.floor(remaining / 1000) * 1.5);
score += remainingPts;
if (requiredDaily > 0 && velocityDaily >= 0) {
var deficit = requiredDaily - velocityDaily;
if (deficit > 0) score += Math.min(10, Math.floor(deficit / 2));
}
if (goal.targetDate) {
var now = new Date(); now.setHours(0,0,0,0);
var dl = new Date(goal.targetDate + 'T00:00:00');
if (!isNaN(dl.getTime())) {
var daysLeft = Math.ceil((dl - now) / 86400000);
if (daysLeft <= 30)       score += 20;
else if (daysLeft <= 90)  score += 10;
else if (daysLeft <= 180) score += 5;
}
}
return Math.min(100, Math.max(0, score));
}

function computeAutopilotAllocation(goal, progress, forecast) {
var remaining     = progress ? progress.remaining : Math.max(0, (parseFloat(goal.target)||0) - (parseFloat(goal.saved)||0));
var risk          = forecast && forecast.risk ? forecast.risk.riskLevel : 'low';
var status        = forecast ? forecast.status : 'no_deadline';
var consistency   = forecast && forecast.risk ? forecast.risk.consistencyScore : 1;
var recommendedDaily, recommendedWeekly, recommendedMonthly;
if (!goal.targetDate || status === 'no_deadline') {
recommendedDaily   = progress ? progress.velocityDaily   : 0;
recommendedWeekly  = progress ? progress.velocityWeekly  : 0;
recommendedMonthly = progress ? progress.velocityMonthly : 0;
} else {
recommendedDaily   = forecast && forecast.requiredDailyToHitDeadline  != null ? forecast.requiredDailyToHitDeadline  : (progress ? progress.velocityDaily  : 0);
recommendedWeekly  = forecast && forecast.requiredWeeklyToHitDeadline != null ? forecast.requiredWeeklyToHitDeadline : (progress ? progress.velocityWeekly : 0);
recommendedMonthly = recommendedDaily * 30;
}
var priority = computeGoalPriorityScore(goal, progress, forecast);
var parts = [];
if (risk === 'high')           parts.push('high contribution volatility');
if (risk === 'medium')         parts.push('moderate contribution volatility');
if (status === 'behind')       parts.push('behind schedule');
if (status === 'on_track')     parts.push('on track for deadline');
if (status === 'ahead')        parts.push('ahead of schedule');
if (consistency < 0.05)        parts.push('very low contribution consistency');
else if (consistency < 0.15)   parts.push('low contribution consistency');
if (remaining > 0 && !goal.targetDate) parts.push('no deadline set');
var rationale = parts.length ? parts.join(', ') : 'on track';
rationale = rationale.charAt(0).toUpperCase() + rationale.slice(1) + '.';
return {
recommendedDaily:   Math.max(0, recommendedDaily),
recommendedWeekly:  Math.max(0, recommendedWeekly),
recommendedMonthly: Math.max(0, recommendedMonthly),
priority:           priority,
rationale:          rationale
};
}

function computePortfolioAutopilot(goals, progressMap, forecastMap) {
var result = (goals || []).map(function(g) {
var progress = progressMap && progressMap[g.id] ? progressMap[g.id] : computeGoalProgress(g);
var forecast = forecastMap && forecastMap[g.id] ? forecastMap[g.id] : forecastGoal(g, progress);
var autopilot = computeAutopilotAllocation(g, progress, forecast);
return Object.assign({}, g, { autopilot: autopilot });
});
result.sort(function(a, b) { return b.autopilot.priority - a.autopilot.priority; });
return result;
}

function computeAutopilotSummary(autopilotGoals) {
var list = autopilotGoals || [];
var highestPriorityGoal   = null;
var highestScore          = -1;
var totalRecommendedDaily   = 0;
var totalRecommendedWeekly  = 0;
var totalRecommendedMonthly = 0;
var riskDistribution = { low: 0, medium: 0, high: 0 };
list.forEach(function(g) {
var ap = g.autopilot || {};
totalRecommendedDaily   += ap.recommendedDaily   || 0;
totalRecommendedWeekly  += ap.recommendedWeekly  || 0;
totalRecommendedMonthly += ap.recommendedMonthly || 0;
if ((ap.priority || 0) > highestScore) {
highestScore = ap.priority || 0;
highestPriorityGoal = g.id || null;
}
var riskLevel = 'low';
if (g.forecast && g.forecast.risk) riskLevel = g.forecast.risk.riskLevel || 'low';
if (riskDistribution[riskLevel] !== undefined) riskDistribution[riskLevel]++;
});
return {
highestPriorityGoal:     list.length ? highestPriorityGoal : null,
totalRecommendedDaily:   totalRecommendedDaily,
totalRecommendedWeekly:  totalRecommendedWeekly,
totalRecommendedMonthly: totalRecommendedMonthly,
riskDistribution:        riskDistribution
};
}
// ── End Goal Autopilot Contributions Engine ───────────────────────────────────

// ── Goal Notifications + Alerts Engine ───────────────────────────────────────
function detectGoalCompletion(goal, progress) {
if (!progress || progress.percent < 100) return null;
return {
type: 'goal_completed',
goalId: goal.id,
message: 'Goal completed!',
timestamp: new Date()
};
}

function detectMilestoneReached(goal, milestones) {
var alerts = [];
(milestones || []).forEach(function(m) {
if (m.status === 'completed' && m.notified !== true) {
alerts.push({
type: 'milestone_reached',
goalId: goal.id,
milestoneId: m.id,
message: 'Milestone reached',
timestamp: new Date()
});
}
});
return alerts;
}

function detectFallingBehind(goal, forecast) {
if (!forecast) return null;
if (forecast.status === 'behind' && forecast.risk && forecast.risk.riskLevel !== 'low') {
return {
type: 'goal_behind',
goalId: goal.id,
message: 'You are falling behind on this goal',
timestamp: new Date()
};
}
return null;
}

function detectOnTrack(goal, forecast) {
if (!forecast || forecast.status !== 'on_track') return null;
return {
type: 'goal_on_track',
goalId: goal.id,
message: 'You are on track',
timestamp: new Date()
};
}

function detectAhead(goal, forecast) {
if (!forecast || forecast.status !== 'ahead') return null;
return {
type: 'goal_ahead',
goalId: goal.id,
message: 'You are ahead of schedule',
timestamp: new Date()
};
}

function detectLowVelocity(goal, progress) {
if (!progress) return null;
var target = progress.target || 0;
if (target <= 0) return null;
var threshold = target / 180;
if (progress.velocityDaily < threshold && progress.percent < 80) {
return {
type: 'low_velocity',
goalId: goal.id,
message: 'Your saving velocity is low',
timestamp: new Date()
};
}
return null;
}

function detectContributionStreaks(goalId, contributions) {
var contribs = (contributions || []).filter(function(c) { return c.goalId === goalId || !goalId; });
if (!contribs.length) return null;
var now = new Date(); now.setHours(0,0,0,0);
var dateSet = {};
contribs.forEach(function(c) {
if (c.date) dateSet[c.date] = true;
});
// Count current streak backward from today
var streak = 0;
for (var i = 0; i < 365; i++) {
var d = new Date(now.getTime() - i * 86400000);
var key = d.toISOString().slice(0,10);
if (dateSet[key]) { streak++; }
else { break; }
}
// Count longest prior streak to detect broken streak
var priorStreak = 0;
var counting = false;
var sortedDates = Object.keys(dateSet).sort();
if (sortedDates.length) {
var run = 1;
for (var j = 1; j < sortedDates.length; j++) {
var prev = new Date(sortedDates[j-1] + 'T00:00:00');
var curr = new Date(sortedDates[j]   + 'T00:00:00');
var diff = Math.round((curr - prev) / 86400000);
if (diff === 1) { run++; }
else { if (run > priorStreak) priorStreak = run; run = 1; }
}
if (run > priorStreak) priorStreak = run;
}
if (streak >= 7) {
return {
type: 'streak_active',
goalId: goalId,
message: streak + '-day contribution streak — keep it up!',
timestamp: new Date()
};
}
if (streak === 0 && priorStreak >= 7) {
return {
type: 'streak_broken',
goalId: goalId,
message: 'Your ' + priorStreak + '-day contribution streak has ended',
timestamp: new Date()
};
}
return null;
}

function generateGoalAlerts(goal, progress, forecast, milestones, contributions) {
var alerts = [];
var goalContribs = (contributions || []).filter(function(c) { return c.goalId === goal.id; });
var a;
a = detectGoalCompletion(goal, progress);
if (a) alerts.push(a);
var ma = detectMilestoneReached(goal, milestones);
if (ma && ma.length) ma.forEach(function(m){ alerts.push(m); });
a = detectFallingBehind(goal, forecast);
if (a) alerts.push(a);
a = detectOnTrack(goal, forecast);
if (a) alerts.push(a);
a = detectAhead(goal, forecast);
if (a) alerts.push(a);
a = detectLowVelocity(goal, progress);
if (a) alerts.push(a);
a = detectContributionStreaks(goal.id, goalContribs);
if (a) alerts.push(a);
return alerts;
}

function generateAllGoalAlerts(goals, progressMap, forecastMap, milestoneMap, contributions) {
return (goals || []).map(function(g) {
var progress  = progressMap  && progressMap[g.id]  ? progressMap[g.id]  : computeGoalProgress(g);
var forecast  = forecastMap  && forecastMap[g.id]  ? forecastMap[g.id]  : forecastGoal(g, progress);
var milestones = milestoneMap && milestoneMap[g.id] ? milestoneMap[g.id] : (g.milestones || []);
var alerts = generateGoalAlerts(g, progress, forecast, milestones, contributions || []);
return { goalId: g.id, alerts: alerts };
});
}
// ── End Goal Notifications + Alerts Engine ────────────────────────────────────

// ── Goal category-update modal state ─────────────────────────────────────────
var _gcmGoal         = null;
var _gcmOldCat       = null;
var _gcmNewCat       = null;
var _gcmOriginalGoal = null;

var _gcmTrigger = null;
function openGoalCategoryModal(g, oldCat, newCat, originalGoal) {
_gcmTrigger = _captureFocusTrigger();
_gcmGoal         = g;
_gcmOldCat       = oldCat;
_gcmNewCat       = newCat;
_gcmOriginalGoal = originalGoal || null;
var otherCount = 0;
(AppState.goals||[]).forEach(function(og) {
if (og.id !== g.id && (og.linkedCat||null) === oldCat && oldCat) otherCount++;
});
var msg = 'Changed linked category for <strong>'+esc(g.name)+'</strong>'
+ ' from <strong>'+esc(oldCat||'—')+'</strong> → <strong>'+esc(newCat)+'</strong>.<br><br>'
+ (otherCount > 0
? '<strong>'+otherCount+'</strong> other goal'+(otherCount===1?'':'s')+' still linked to the old category. Update those too?'
: 'Apply this category to all goals currently sharing this link?');
document.getElementById('gcm-msg').innerHTML = msg;
document.getElementById('gcm-ov').style.display = 'flex';
var gcmCancelBtn = document.getElementById('gcm-cancel-btn');
if (gcmCancelBtn) gcmCancelBtn.focus();
}
function closeGoalCategoryModal() {
document.getElementById('gcm-ov').style.display = 'none';
_gcmGoal = null; _gcmOldCat = null; _gcmNewCat = null; _gcmOriginalGoal = null;
if (_gcmTrigger && typeof _gcmTrigger.focus === 'function' && document.contains(_gcmTrigger)) _gcmTrigger.focus();
_gcmTrigger = null;
}
function onGoalBulkUpdateAll() {
if (!_gcmGoal) return;
var g = _gcmGoal; var goalId = g.id; var newCat = _gcmNewCat;
var count = bulkUpdateGoalAll(goalId, newCat);
rememberGoalCategory(goalId, newCat);
saveGoalToDB(g);
invalidateAllCaches(); lsSave(); renderAll();
disableScrollLock(); document.getElementById('gov').style.display = 'none';
closeGoalCategoryModal();
toast('✅ Updated '+(count+1)+' goal'+(count>0?'s':'')+' to '+newCat);
}
function onGoalBulkUpdateRecent() {
if (!_gcmGoal) return;
var g = _gcmGoal; var goalId = g.id; var newCat = _gcmNewCat;
var count = bulkUpdateGoalRecent(goalId, newCat);
rememberGoalCategory(goalId, newCat);
saveGoalToDB(g);
invalidateAllCaches(); lsSave(); renderAll();
disableScrollLock(); document.getElementById('gov').style.display = 'none';
closeGoalCategoryModal();
toast('✅ Updated '+(count+1)+' goal'+(count>0?'s':'')+' (last 12 mo) to '+newCat);
}
function onGoalBulkUpdateOne() {
if (!_gcmGoal) return;
var g = _gcmGoal; var goalId = g.id; var newCat = _gcmNewCat;
bulkUpdateGoalOne(goalId, newCat);
rememberGoalCategory(goalId, newCat);
invalidateAllCaches(); lsSave(); renderAll();
disableScrollLock(); document.getElementById('gov').style.display = 'none';
closeGoalCategoryModal();
toast('✅ Goal updated to '+newCat);
}
function onGoalCategoryCancel() {
if (_gcmGoal && _gcmOriginalGoal) Object.assign(_gcmGoal, _gcmOriginalGoal);
closeGoalCategoryModal();
}

// ── Shared finish pipelines ───────────────────────────────────────────────────
function _doBulkUpdate(scope, tx, newCat) {
var count = 0;
if      (scope==='all')  count = bulkUpdateAll(tx.merchantNorm, newCat);
else if (scope==='year') count = bulkUpdateRecent(tx.merchantNorm, newCat);
else                      count = bulkUpdateOne(tx.merchantNorm, newCat);
invalidateAllCaches(); lsSave(); renderAll(); haptic([15,10,15,10,15]);
toast('\u2705 ' + (count > 0 ? 'Updated '+count+' transaction'+(count===1?'':'s') : 'Transaction updated') + ' to ' + newCat);
}
function _doBulkBillUpdate(scope, billNorm, billName, newCat, excludeId) {
var count = 0;
if      (scope==='all')  count = bulkUpdateBillsAll(billNorm, billName, newCat, excludeId);
else if (scope==='year') count = bulkUpdateBillsRecent(billNorm, billName, newCat, excludeId);
else                      count = bulkUpdateBillsOne(billNorm, newCat);
saveMeta(); invalidateAllCaches(); rRecurring(); renderAll(); haptic([15,10,15,10,15]);
toast('\u2705 ' + (count > 0 ? 'Updated '+count+' bill'+(count===1?'':'s') : 'Bill updated') + ' to ' + newCat);
}

