function rAnExtras(txs, el){
if(!txs||!txs.length||!el) return '';
var exp=txs.filter(function(t){return t.type==='expense';});
var totalExp=exp.reduce(function(s,t){return s+t.amount;},0);
var byCat={};
exp.forEach(function(t){byCat[t.category]=(byCat[t.category]||0)+t.amount;});
var top3=Object.keys(byCat).map(function(k){return[k,byCat[k]];})
.sort(function(a,b){return b[1]-a[1];}).slice(0,3);
var pm=cM-1, py=cY; if(pm<0){pm=11;py--;}
var prevExp=AppState.transactions.filter(function(t){
return t.mk===mk(py,pm)&&t.type==='expense';
}).reduce(function(s,t){return s+t.amount;},0);
var trendPct=prevExp>0?((totalExp-prevExp)/prevExp*100):null;
var today=new Date();
var dayOfMonth=(cY===today.getFullYear()&&cM===today.getMonth())?today.getDate():new Date(cY,cM+1,0).getDate();
var daysInMonth=new Date(cY,cM+1,0).getDate();
var projected=dayOfMonth>0?(totalExp/dayOfMonth*daysInMonth):0;
return '<div class="card" style="margin-bottom:var(--sm)">'
+'<div style="font-weight:700;font-size:var(--fs-subtext);margin-bottom:var(--sm)">&#128202; This Month\'s Insights</div>'
+'<div style="display:grid;grid-template-columns:1fr 1fr;gap:var(--sm);margin-bottom:var(--sm)">'
+'<div style="background:var(--card2);border-radius:var(--r-sm);padding:var(--sm)">'
+'<div style="font-size:var(--fs-micro);color:var(--sub);text-transform:uppercase;letter-spacing:.4px;margin-bottom:3px">vs Last Month</div>'
+(trendPct!==null
?'<div style="font-size:var(--fs-row-label);font-weight:800;color:'+(trendPct>10?'var(--red)':trendPct<-10?'var(--em)':'var(--amb)')+';">'
+(trendPct>0?'+':'')+trendPct.toFixed(1)+'%</div>'
:'<div style="font-size:var(--fs-row-label);font-weight:700;color:var(--sub)">No data</div>'
)
+'</div>'
+'<div style="background:var(--card2);border-radius:var(--r-sm);padding:var(--sm)">'
+'<div style="font-size:var(--fs-micro);color:var(--sub);text-transform:uppercase;letter-spacing:.4px;margin-bottom:3px">Projected</div>'
+'<div style="font-size:var(--fs-row-label);font-weight:800;color:var(--text)">'+fmt(projected)+'</div>'
+'</div>'
+'</div>'
+(top3.length
?'<div style="font-size:var(--fs-caption);font-weight:700;color:var(--sub);text-transform:uppercase;letter-spacing:.4px;margin-bottom:var(--xs)">Top Categories</div>'
+top3.map(function(item,i){
var cat=item[0],amt=item[1];
var medals=['&#129351;','&#129352;','&#129353;'];
return '<div style="display:flex;align-items:center;gap:var(--sm);padding:5px 0;border-bottom:1px solid var(--border2)">'
+'<span style="font-size:14px">'+(medals[i]||'')+'</span>'
+'<span style="font-size:var(--fs-subtext);font-weight:600;flex:1">'+(CEM[cat]||'')+' '+esc(cat)+'</span>'
+'<span style="font-size:var(--fs-subtext);font-weight:700;color:var(--red)">'+fmt(amt)+'</span>'
+'</div>';
}).join('')
:'')
+'</div>';
}
function exportDataJSON(){
try{
var payload={
exportDate: new Date().toISOString(),
schemaVersion: SCHEMA_VERSION,
transactions: AppState.transactions,
goals: AppState.goals,
budgets: AppState.budgets,
budgetItems: AppState.budgetItems,
recurRules: AppState.recurRules,
merchantMem: AppState.merchantMem,
budgetGroups: BUDGET_GROUPS,
assets: AppState.assets,
liabilities: AppState.liabilities,
customCats: AppState.customCats
};
var blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'});
var url=URL.createObjectURL(blob);
var a=document.createElement('a');
a.href=url;
a.download='peak-finance-export-'+new Date().toISOString().split('T')[0]+'.json';
document.body.appendChild(a);
a.click();
setTimeout(function(){document.body.removeChild(a);URL.revokeObjectURL(url);},1000);
toast('Data exported!');
}catch(e){
toast('Export failed: '+e.message);
}
}
(function(){
var ptr       = document.getElementById('ptr-indicator');
var ptrText   = document.getElementById('ptr-text');
var content   = document.getElementById('content');
if(!ptr || !content) return;
var startY    = 0;
var currentY  = 0;
var pulling   = false;
var refreshing= false;
var THRESHOLD = 72;   // px drag needed to trigger refresh
var MAX_PULL  = 110;  // max drag distance tracked
function getScrollTop(){
return content.scrollTop || 0;
}
content.addEventListener('touchstart', function(e){
if(refreshing) return;
if(getScrollTop() > 4) return;
startY = e.touches[0].clientY;
pulling = true;
}, {passive:true});
content.addEventListener('touchmove', function(e){
if(!pulling || refreshing) return;
if(getScrollTop() > 4){ pulling=false; return; }
currentY = e.touches[0].clientY;
var dy = Math.min(currentY - startY, MAX_PULL);
if(dy <= 0){ ptr.className=''; return; }
ptr.className = dy >= THRESHOLD ? 'ready' : 'pulling';
ptrText.textContent = dy >= THRESHOLD ? 'Release to refresh' : 'Pull to refresh';
}, {passive:true});
content.addEventListener('touchend', function(){
if(!pulling || refreshing) return;
pulling = false;
var dy = currentY - startY;
if(dy >= THRESHOLD){
refreshing = true;
ptr.className = 'refreshing';
ptrText.textContent = 'Refreshing…';
if(navigator.vibrate) navigator.vibrate(10);
setTimeout(function(){
try{ if(typeof autoGenerateRecurring==='function') autoGenerateRecurring(); renderAll(); } catch(e){}
ptr.className = '';
ptrText.textContent = 'Pull to refresh';
refreshing = false;
startY = 0; currentY = 0;
toast('Refreshed');
}, 800);
} else {
ptr.className = '';
startY = 0; currentY = 0;
}
}, {passive:true});
})();
function drawNavNotch(){
var svg = document.getElementById('nav-svg');
var path = document.getElementById('nav-path');
if(!svg || !path) return;
var W = svg.getBoundingClientRect().width || 430;
var H = svg.getBoundingClientRect().height || 58;
svg.setAttribute('viewBox','0 0 '+W+' '+H);
var cx = W/2;
var r  = 36;  // notch radius
var dip = 14; // how deep the curve dips
var d = [
'M 0 0',
'L '+(cx-r-20)+' 0',
'C '+(cx-r-4)+' 0 '+(cx-r)+' '+dip+' '+cx+' '+dip,
'C '+(cx+r)+' '+dip+' '+(cx+r+4)+' 0 '+(cx+r+20)+' 0',
'L '+W+' 0',
'L '+W+' '+H,
'L 0 '+H,
'Z'
].join(' ');
path.setAttribute('d', d);
path.setAttribute('stroke-width','1');
}
