// Default values for all bill settings keys
var _BSET_DEFAULTS = {
billNotifDue:       true,
billNotifAutopay:   true,
billNotifLarge:     true,
billNotifHeavyWeek: false,
billAutopayRecs:    true,
billAutopayRisk:    true,
billShowYearly:     true,
billShowIrregular:  true,
billGroupByCategory:false
};

// Read a bill setting — falls back to default
function getBillSetting(key) {
if (!_prefs) return _BSET_DEFAULTS[key];
return (key in _prefs) ? !!_prefs[key] : !!_BSET_DEFAULTS[key];
}

// Update bill settings — merges into _prefs and persists
function updateBillSettings(partial) {
if (!_prefs) _prefs = {};
Object.keys(partial).forEach(function(k){ _prefs[k] = !!partial[k]; });
try { localStorage.setItem(PREFS_KEY, JSON.stringify(_prefs)); } catch(e){}
}

function _bsetToggle(key) {
var val = !getBillSetting(key);
var upd = {};
upd[key] = val;
updateBillSettings(upd);
// Update toggle visual
var inp = document.getElementById('bset-'+key);
if (inp) inp.checked = val;
toast(val ? '&#10003; Enabled' : 'Disabled');
}

