+'<div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:4px"><div style="display:flex;align-items:center;gap:4px;flex-wrap:wrap"><span class="bstatus '+st.status+'">'+st.label+'</span>'+(rule.autoGenerate?'<span class="bstatus autopay">&#9889; AutoPay</span>':'')+autoTag+'</div></div>'
+'<div class="bcard-row"><div class="bcard-icon" style="background:'+(isBill?'var(--redbg)':'var(--embg)')+';">'+(isBill?'&#128184;':'&#128176;')+'</div>'
