+'<div class="bcard-sub" style="display:flex;align-items:center;gap:4px;flex-wrap:wrap">'+freqHtml+(rule.dayOfMonth?' &middot; Day '+rule.dayOfMonth:'')+confHtml+'</div></div>'
+'<div class="bcard-right"><div class="bcard-amt" style="color:'+(isBill?'var(--red)':'var(--em)')+';">'+(isBill?'-':'+')+''+fmt(rule.amount)+'</div>'+(safeNextDue?'<div class="bcard-due" style="color:'+(st.status==='overdue'?'var(--red)':st.status==='due'?'var(--amb)':'var(--sub)')+'">'+safeNextDue+'</div>':'')+'</div></div>'
