+(isBill&&st.status!=='paid'?'<button class="gqf-btn" style="flex:2" onclick="markBillPaid(\''+rule.id+'\')" aria-label="Mark '+esc(rule.name)+' as paid">&#10003; Mark Paid</button>':'')
