var PREFS_KEY = 'kevt_prefs_v1';
var _prefs = null;
var ACCENT_COLORS = {
green:  {gd:'#1a3d5c', gm:'#2a6a9a', gold:'#5ab4e0'},
blue:   {gd:'#1a2a4a', gm:'#2d4a7a', gold:'#5ab4e0'},
purple: {gd:'#2d1a4a', gm:'#5a2d8a', gold:'#a87de0'},
orange: {gd:'#4a2a1a', gm:'#8a4a2d', gold:'#e0a87d'},
pink:   {gd:'#4a1a2a', gm:'#8a2d5a', gold:'#e07da8'}
};
function loadPrefs() {
try {
var raw = localStorage.getItem(PREFS_KEY);
_prefs = raw ? JSON.parse(raw) : {};
} catch(e) { _prefs = {}; }
applyPrefs();
return _prefs;
}
function savePrefs() {
var name = (document.getElementById('set-name')||{value:''}).value||'';
var cur  = (document.getElementById('set-currency')||{value:'USD'}).value||'USD';
var ws   = (document.getElementById('set-weekstart')||{value:'0'}).value||'0';
var dc   = (document.getElementById('set-defcat')||{value:'Other'}).value||'Other';
_prefs.userName     = name;
_prefs.currency     = cur;
_prefs.weekStart    = ws;
_prefs.defaultCat   = dc;
try { localStorage.setItem(PREFS_KEY, JSON.stringify(_prefs)); } catch(e){}
}
function applyPrefs() {
if(!_prefs) return;
if(_prefs.accent) applyAccentCss(_prefs.accent);
if(_prefs.fontSize) applyFontSizeCss(_prefs.fontSize);
document.body.classList.toggle('hi-contrast', !!_prefs.highContrast);
if(_prefs.reduceMotion) document.body.style.setProperty('--reduce-motion','1');
else document.body.style.removeProperty('--reduce-motion');
// Restore dark/light theme from persisted prefs — nothing else in the boot
// sequence applies the 'dim' class the whole dark-mode CSS system keys off,
// so without this, dark mode silently reverted to light on every reload.
if(_prefs.theme==='dim') document.body.classList.add('dim');
else if(_prefs.theme==='auto') {
var prefersDark = window.matchMedia && window.matchMedia('(prefers-color-scheme:dark)').matches;
document.body.classList.toggle('dim', !!prefersDark);
} else if(_prefs.theme==='light') {
document.body.classList.remove('dim');
}
}
function applyAccentCss(accent) {
var c = ACCENT_COLORS[accent];
if(!c) return;
var r = document.documentElement.style;
r.setProperty('--gd', c.gd);
r.setProperty('--gm', c.gm);
_prefs.accent = accent;
try { localStorage.setItem(PREFS_KEY, JSON.stringify(_prefs)); } catch(e){}
}
function applyFontSizeCss(sz) {
var sizes = {sm:'90%', md:'100%', lg:'115%'};
document.documentElement.style.fontSize = sizes[sz]||'100%';
_prefs.fontSize = sz;
try { localStorage.setItem(PREFS_KEY, JSON.stringify(_prefs)); } catch(e){}
}
function setTheme(mode) {
var body = document.body;
if(mode==='dim')        body.classList.add('dim');
else if(mode==='light') body.classList.remove('dim');
else { // auto
var prefersDark = window.matchMedia && window.matchMedia('(prefers-color-scheme:dark)').matches;
prefersDark ? body.classList.add('dim') : body.classList.remove('dim');
}
_prefs.theme = mode;
try { localStorage.setItem(THEME_KEY, mode==='dim'?'dim':''); } catch(e){}
try { localStorage.setItem(PREFS_KEY, JSON.stringify(_prefs)); } catch(e){}
syncSettingsUI();
}
function setAccent(accent) {
applyAccentCss(accent);
syncSettingsUI();
}
function setFontSize(sz) {
applyFontSizeCss(sz);
syncSettingsUI();
}
function togglePref(key) {
if(!_prefs) _prefs = {};
_prefs[key] = !_prefs[key];
var el = document.getElementById('set-'+key.replace(/([A-Z])/g,'-$1').toLowerCase().replace('notif-','')); // try
var idMap = {
reduceMotion:'set-reduce-motion', highContrast:'set-hi-contrast',
notifBills:'set-notif-bills', notifBudget:'set-notif-budget',
notifGoals:'set-notif-goals', notifWeekly:'set-notif-weekly'
};
var btn = document.getElementById(idMap[key]);
if(btn) { if(_prefs[key]) btn.classList.add('on'); else btn.classList.remove('on'); btn.setAttribute('aria-checked', !!_prefs[key]); }
applyPrefs();
try { localStorage.setItem(PREFS_KEY, JSON.stringify(_prefs)); } catch(e){}
}
function setToggleDev() {
var body = document.getElementById('set-dev-body');
var chev = document.getElementById('set-dev-chev');
var hdr  = document.getElementById('set-dev-hdr');
if(!body) return;
var open = body.classList.toggle('open');
if(chev) chev.textContent = open ? '\u2039' : '\u203A';
if(hdr)  hdr.setAttribute('aria-expanded', open);
}
function syncSettingsUI() {
if(!_prefs) _prefs = {};
['light','dim','auto'].forEach(function(t){
var b = document.getElementById('theme-'+t);
if(b) b.className = 'theme-mode-btn'+(_prefs.theme===t?' on':'');
});
document.querySelectorAll('.accent-swatch').forEach(function(s){
s.className = 'accent-swatch'+(_prefs.accent===s.getAttribute('data-accent')?' on':'');
});
['sm','md','lg'].forEach(function(sz){
var b = document.getElementById('fsz-'+sz);
if(b) b.className = 'fsz-btn'+(_prefs.fontSize===sz?' on':'');
});
var toggles = {reduceMotion:'set-reduce-motion',highContrast:'set-hi-contrast',notifBills:'set-notif-bills',notifBudget:'set-notif-budget',notifGoals:'set-notif-goals',notifWeekly:'set-notif-weekly'};
Object.keys(toggles).forEach(function(k){
var b = document.getElementById(toggles[k]);
if(b){ if(_prefs[k]) b.classList.add('on'); else b.classList.remove('on'); b.setAttribute('aria-checked',!!_prefs[k]); }
});
var nm = document.getElementById('set-name'); if(nm) nm.value = _prefs.userName||'';
var cur = document.getElementById('set-currency'); if(cur) cur.value = _prefs.currency||'USD';
var ws = document.getElementById('set-weekstart'); if(ws) ws.value = _prefs.weekStart||'0';
var dc = document.getElementById('set-defcat');
if(dc && CATS) {
if(!dc.options.length || dc.options.length<2) {
dc.innerHTML = CATS.expense.map(function(c){return '<option>'+c+'</option>';}).join('');
}
if(_prefs.defaultCat) dc.value = _prefs.defaultCat;
}
}
function resetSection(what) {
var labels = {budgets:'Reset all budgets?',goals:'Reset all goals?',bills:'Reset all bills and rules?',catmem:'Reset categorization memory?',onboard:'Reset onboarding and tutorial?'};
showCfm(labels[what]||'Reset '+what+'?', 'Confirm Reset', function(){
pushSnapshot('Reset '+what);
if(what==='budgets'){
AppState.budgets={};AppState.budgetItems={};
} else if(what==='goals'){
AppState.goals=[];
} else if(what==='bills'){
AppState.recurRules=(AppState.recurRules||[]).filter(function(r){return r.type==='income';});
} else if(what==='catmem'){
AppState.merchantMem={};
} else if(what==='onboard'){
try{localStorage.removeItem(TUTORIAL_KEY);localStorage.removeItem(STARTER_KEY);localStorage.removeItem(STARTER_TX_KEY);}catch(e){}
}
lsSave();saveMeta();renderAll();
toast(what+' reset!');
});
}
function exportCSVFull() {
var txs = AppState.transactions||[];
if(!txs.length){toast('No transactions to export');return;}
var rows = ['Date,Merchant,Amount,Type,Category,Note'];
txs.forEach(function(t){
rows.push([
t.date||'',
'"'+(t.merchantNorm||t.merchantRaw||t.merchant||'').replace(/"/g,'""')+'"',
t.amount||0,
t.type||'expense',
'"'+(t.category||'').replace(/"/g,'""')+'"',
'"'+(t.note||'').replace(/"/g,'""')+'"'
].join(','));
});
var csv = rows.join('\n');
var blob = new Blob([csv],{type:'text/csv'});
var a = document.createElement('a');
a.href = URL.createObjectURL(blob);
a.download = 'peak-finance-transactions-'+new Date().toISOString().slice(0,10)+'.csv';
a.click();
toast('Exported '+txs.length+' transactions!');
}
function getPrefsUserName() {
if(!_prefs) loadPrefs();
return _prefs.userName||'';
}
var _anInsightIdx = 0;
var _anInsightTimer = null;
var _anCache = {};
function anGetMonthTxs(y, m) {
var mk2 = y+'-'+String(m+1).padStart(2,'0');
return (AppState.transactions||[]).filter(function(t){return t.mk===mk2;});
}
function anMonthKey(y, m) { return y+'-'+String(m+1).padStart(2,'0'); }
function anLastNMonths(n) {
var months = [];
for(var i=n-1; i>=0; i--) {
var d = new Date(cY, cM-i, 1);
months.push({y:d.getFullYear(), m:d.getMonth(), key:anMonthKey(d.getFullYear(),d.getMonth())});
}
return months;
}
function anMonthExp(txs) {
return txs.filter(function(t){return t.type==='expense';}).reduce(function(s,t){return s+t.amount;},0);
}
function anMonthInc(txs) { return getIncome(txs); }
function anBuildInsights() {
var txs = mTx();
var allTxs = AppState.transactions||[];
var insights = [];
var now = new Date();
var thisExp = anMonthExp(txs);
var lastMo = new Date(cY, cM-1, 1);
var lastTxs = anGetMonthTxs(lastMo.getFullYear(), lastMo.getMonth());
var lastExp = anMonthExp(lastTxs);
if(lastExp>0 && thisExp>0) {
var diff = ((thisExp-lastExp)/lastExp*100);
if(Math.abs(diff)>3) insights.push('Spending is '+Math.abs(diff).toFixed(0)+'% '+(diff<0?'lower &#9660;':'higher &#9650;')+' than last month.');
}
var byCat={};
txs.filter(function(t){return t.type==='expense';}).forEach(function(t){byCat[t.category]=(byCat[t.category]||0)+t.amount;});
var lastByCat={};
lastTxs.filter(function(t){return t.type==='expense';}).forEach(function(t){lastByCat[t.category]=(lastByCat[t.category]||0)+t.amount;});
var topSpike=null, topSpikeRatio=1.3;
Object.keys(byCat).forEach(function(c){if(lastByCat[c]>10&&byCat[c]/lastByCat[c]>topSpikeRatio){topSpikeRatio=byCat[c]/lastByCat[c];topSpike=c;}});
if(topSpike) insights.push(esc(topSpike)+' is up '+((topSpikeRatio-1)*100).toFixed(0)+'% vs last month.');
var goalContrib = allTxs.filter(function(t){return t.merchantNorm==='Goal Contribution'&&t.mk===anMonthKey(cY,cM);}).reduce(function(s,t){return s+t.amount;},0);
if(goalContrib>0) insights.push('You\'ve put '+fmt(goalContrib)+' toward goals this month!');
var bh = computeBudgetHealth ? computeBudgetHealth() : null;
if(bh && bh.score>=80) insights.push('Budget Health is strong at '+bh.score+'/100. &#127881;');
else if(bh && bh.score<50) insights.push('Budget Health needs attention: '+bh.score+'/100.');
var dueSoon = computeBillsDueSoon ? computeBillsDueSoon() : [];
var overdueCount = dueSoon.filter(function(x){return x.st.status==='overdue';}).length;
if(overdueCount>0) insights.push(overdueCount+' bill'+(overdueCount>1?'s':'')+(overdueCount>1?' are':' is')+' overdue.');
var net = anMonthInc(txs) - thisExp;
if(net<0) insights.push('You\'re over budget by '+fmt(Math.abs(net))+' this month.');
else if(net>0 && txs.length>3) insights.push('On track to save '+fmt(net)+' this month. &#127775;');
if(!insights.length) { var _emptyInsEl = document.getElementById('an-insight-panel'); if(_emptyInsEl) _emptyInsEl.innerHTML = renderBillsEmptyInsights(); return; }
return insights;
}
function anStartInsightRotator(insights, el) {
if(!insights.length || !el) return;
_anInsightIdx = 0;
el.innerHTML = insights[0];
if(_anInsightTimer) clearInterval(_anInsightTimer);
if(insights.length < 2) return;
_anInsightTimer = setInterval(function(){
if(!document.getElementById(el.id)) { clearInterval(_anInsightTimer); return; }
el.classList.add('fade-out');
setTimeout(function(){
_anInsightIdx = (_anInsightIdx+1) % insights.length;
el.innerHTML = insights[_anInsightIdx];
el.classList.remove('fade-out');
el.classList.add('fade-in');
setTimeout(function(){ el.classList.remove('fade-in'); }, 400);
}, 400);
}, 10000);
}
function anBuildSparkbars(txs) {
var months = anLastNMonths(6);
var data = months.map(function(mo){
var t = anGetMonthTxs(mo.y, mo.m);
return { label: new Date(mo.y,mo.m,1).toLocaleString('default',{month:'short'}), exp: anMonthExp(t), inc: anMonthInc(t) };
});
var maxVal = Math.max.apply(null, data.map(function(d){return Math.max(d.exp,d.inc);}));
if(maxVal===0) return '';
var html = '<div class="an-sparkbar-wrap" role="img" aria-label="6-month spending chart">';
data.forEach(function(d){
var expH = Math.round(d.exp/maxVal*56);
var incH = Math.round(d.inc/maxVal*56);
html += '<div style="flex:1;display:flex;align-items:flex-end;gap:1px;" title="'+d.label+': Exp '+fmt(d.exp)+' Inc '+fmt(d.inc)+'">'
+'<div class="an-sparkbar" style="height:'+expH+'px;background:var(--red);opacity:.8" aria-label="'+d.label+' expenses '+fmt(d.exp)+'"></div>'
+'<div class="an-sparkbar" style="height:'+incH+'px;background:var(--em);opacity:.8" aria-label="'+d.label+' income '+fmt(d.inc)+'"></div>'
+'</div>';
});
html += '</div>';
html += '<div class="an-sparkbar-lbl">'+data.map(function(d){return'<span>'+d.label+'</span>';}).join('')+'</div>';
html += '<div style="display:flex;gap:var(--sm);margin-top:4px;font-size:9px;">'
+'<span style="display:flex;align-items:center;gap:3px;"><span style="width:8px;height:8px;border-radius:2px;background:var(--red);display:inline-block"></span>Expenses</span>'
+'<span style="display:flex;align-items:center;gap:3px;"><span style="width:8px;height:8px;border-radius:2px;background:var(--em);display:inline-block"></span>Income</span>'
+'</div>';
return html;
}
function anBuildLineChart(metric) {
var months = anLastNMonths(6);
var vals = months.map(function(mo){
var t = anGetMonthTxs(mo.y, mo.m);
return metric==='income' ? anMonthInc(t) : anMonthExp(t);
});
var maxV = Math.max.apply(null, vals.concat([1]));
var W=280, H=70, pad=8;
var pts = vals.map(function(v,i){ return { x: pad+(i*(W-pad*2)/(vals.length-1)), y: H-pad-Math.round((v/maxV)*(H-pad*2)) }; });
var d = 'M'+pts[0].x+','+pts[0].y;
for(var i=1;i<pts.length;i++){
var cp1x=(pts[i-1].x+pts[i].x)/2, cp1y=pts[i-1].y;
var cp2x=(pts[i-1].x+pts[i].x)/2, cp2y=pts[i].y;
d+=' C'+cp1x+','+cp1y+' '+cp2x+','+cp2y+' '+pts[i].x+','+pts[i].y;
}
var areaD = d+' L'+pts[pts.length-1].x+','+(H-pad)+' L'+pts[0].x+','+(H-pad)+' Z';
var color = metric==='income'?'var(--em)':'var(--red)';
var labels = months.map(function(mo){ return new Date(mo.y,mo.m,1).toLocaleString('default',{month:'short'}); });
var labelHtml = pts.map(function(p,i){
var pct = (p.x/W)*100;  // Convert SVG x-coordinate to percentage
return '<span style="position:absolute;left:'+pct+'%;transform:translateX(-50%);text-align:center;">'+labels[i]+'</span>';
}).join('');
return '<div class="an-line-chart-wrap" role="img" aria-label="6-month '+metric+' line chart">'
+'<svg width="100%" viewBox="0 0 '+W+' '+H+'" preserveAspectRatio="none" style="display:block">'
+'<defs><linearGradient id="anLG_'+metric+'" x1="0" y1="0" x2="0" y2="1">'
+'<stop offset="0%" stop-color="'+color+'" stop-opacity=".18"/>'
+'<stop offset="100%" stop-color="'+color+'" stop-opacity="0"/>'
+'</linearGradient></defs>'
+'<path d="'+areaD+'" fill="url(#anLG_'+metric+')" class="an-line-area"/>'
+'<path d="'+d+'" stroke="'+color+'" class="an-line-path"/>'
+pts.map(function(p,i){return'<circle cx="'+p.x+'" cy="'+p.y+'" r="3" fill="'+color+'" class="an-line-dot" aria-label="'+labels[i]+': '+fmt(vals[i])+'"><title>'+labels[i]+': '+fmt(vals[i])+'</title></circle>';}).join('')
+'</svg>'
+'<div class="an-sparkbar-lbl" style="position:relative;height:14px;">'+labelHtml+'</div>'
+'</div>';
}
function anBuildCashFlow() {
var rules = AppState.recurRules||[];
var bills = rules.filter(function(r){return r.type==='bill'&&r.active!==false;});
var incomeRules = rules.filter(function(r){return r.type==='income'&&r.active!==false;});
var monthlyBillsAmt = bills.reduce(function(s,r){return s+(r.amount||0);},0);
var monthlyIncAmt   = incomeRules.reduce(function(s,r){return s+(r.amount||0);},0);
var nStr = getNDaysAgoStr(90);
var varSpend = (AppState.transactions||[]).filter(function(t){
return t.type==='expense'&&t.date>=nStr&&t.merchantNorm!=='Goal Contribution';
}).reduce(function(s,t){return s+t.amount;},0);
var avgDailyVar = varSpend/90;
var items = [];
var net = monthlyIncAmt - monthlyBillsAmt - (avgDailyVar*30);
items.push({label:'Monthly income (recurring)', amt:monthlyIncAmt, sign:1});
items.push({label:'Monthly bills', amt:monthlyBillsAmt, sign:-1});
items.push({label:'Est. variable spend (30d)', amt:Math.round(avgDailyVar*30), sign:-1});
items.push({label:'Projected net', amt:Math.abs(net), sign:net>=0?1:-1, isNet:true});
var maxAmt = Math.max.apply(null, items.map(function(x){return x.amt;}));
var riskDays = [];
if(net<0) riskDays.push('Projected expenses may exceed income by '+fmt(Math.abs(net))+'.');
else if(net>0) riskDays.push('Projected to save '+fmt(net)+' next 30 days.');
return '<div class="an-card-s3 card" style="margin-bottom:var(--md)" aria-label="Cash flow projection">'
+'<div class="dash-card-hdr"><span class="dash-card-title">Cash Flow Projection</span><span style="font-size:var(--fs-caption);color:var(--sub)">Next 30 days</span></div>'
+items.map(function(item){
var barPct = maxAmt>0 ? Math.round(item.amt/maxAmt*100) : 0;
var color = item.isNet ? (net>=0?'var(--em)':'var(--red)') : (item.sign>0?'var(--em)':'var(--red)');
return '<div class="an-cf-row'+(item.isNet?' '+((net>=0)?'':'risk'):'')+'">'
+'<span style="flex:1.5;font-weight:'+(item.isNet?'800':'600')+'">'+item.label+'</span>'
+'<div class="an-cf-bar-wrap"><div class="an-cf-bar-fill" style="width:'+barPct+'%;background:'+color+'"></div></div>'
+'<span style="font-weight:700;color:'+color+';text-align:right;min-width:60px">'+(item.sign>0?'+':'-')+fmt(item.amt)+'</span>'
+'</div>';
}).join('')
+(riskDays.length?'<div style="font-size:var(--fs-caption);color:'+(net>=0?'var(--em)':'var(--red)')+';padding-top:var(--xs);font-style:italic;">'+riskDays[0]+'</div>':'')
+'</div>';
}
