function anBuild6MonthCatChart(cat) {
var months = anLastNMonths(6);
var vals = months.map(function(mo){
var t = anGetMonthTxs(mo.y,mo.m).filter(function(t){return t.type==='expense'&&t.category===cat;});
return t.reduce(function(s,tx){return s+tx.amount;},0);
});
var labels = months.map(function(mo){return new Date(mo.y,mo.m,1).toLocaleString('default',{month:'short'});});
return anBuildLineChartFromVals(vals, labels, 'var(--red)');
}
function anBuildLineChartFromVals(vals, labels, color) {
var maxV = Math.max.apply(null, vals.concat([1]));
var W=280, H=60, pad=6;
var pts = vals.map(function(v,i){ return {x:pad+(i*(W-pad*2)/(Math.max(vals.length-1,1))),y:H-pad-Math.round((v/maxV)*(H-pad*2))}; });
var d = 'M'+pts[0].x+','+pts[0].y;
for(var i=1;i<pts.length;i++){var cp1x=(pts[i-1].x+pts[i].x)/2;d+=' C'+cp1x+','+pts[i-1].y+' '+cp1x+','+pts[i].y+' '+pts[i].x+','+pts[i].y;}
var labelHtml = pts.map(function(p,i){
var pct = (p.x/W)*100;  // Convert SVG x-coordinate to percentage
return '<span style="position:absolute;left:'+pct+'%;transform:translateX(-50%);text-align:center;white-space:nowrap;overflow:hidden;">'+labels[i]+'</span>';
}).join('');
return '<div class="an-line-chart-wrap">'
+'<svg width="100%" viewBox="0 0 '+W+' '+H+'" preserveAspectRatio="none" style="display:block">'
+'<path d="'+d+'" stroke="'+(color||'var(--red)')+'" class="an-line-path"/>'
+pts.map(function(p,i){return'<circle cx="'+p.x+'" cy="'+p.y+'" r="3" fill="'+(color||'var(--red)')+'" class="an-line-dot"><title>'+labels[i]+': '+fmt(vals[i])+'</title></circle>';}).join('')
+'</svg>'
+'<div class="an-sparkbar-lbl" style="position:relative;height:14px;">'+labelHtml+'</div>'
+'</div>';
}
