var avgTx = txs.length>0?total/txs.length:0;
var recur = txs.length>1 ? detectRecurring ? detectRecurring(txs[0]) : null : null;
var html = '<div class="bsheet"><div class="bsheet-handle"></div><div style="max-width:430px;margin:0 auto">'
