function cpFuzzy(str, q) {
if(!q) return true;
str = str.toLowerCase(); q = q.toLowerCase();
if(str.indexOf(q) >= 0) return {score:10, pos:str.indexOf(q)};
var si=0, qi=0, score=0;
while(si<str.length && qi<q.length) {
if(str[si]===q[qi]){score++;qi++;}
si++;
}
return qi===q.length ? {score:score} : false;
}
function cpHighlight(str, q) {
if(!q) return esc(str);
var idx = str.toLowerCase().indexOf(q.toLowerCase());
if(idx>=0) return esc(str.slice(0,idx))+'<span class="cp-match">'+esc(str.slice(idx,idx+q.length))+'</span>'+esc(str.slice(idx+q.length));
return esc(str);
}
function cpBuildResults(q) {
var results = [];
var ql = (q||'').toLowerCase().trim();
var matchedActions = CP_ACTIONS.filter(function(a){
if(!ql) return true;
return cpFuzzy(a.title, ql) || cpFuzzy(a.sub, ql);
});
if(matchedActions.length) {
results.push({type:'section', label:'Quick Actions'});
matchedActions.slice(0,6).forEach(function(a,i){
results.push({type:'action', icon:a.icon, title:a.title, sub:a.sub, action:a.action});
});
}
if(ql) {
var idx = buildSearchIndex();
var txMatchIds = idx.txs.filter(function(entry){ return entry.tokens.indexOf(ql)>=0; })
.slice(0,5).map(function(e){ return e.id; });
var txMatches = txMatchIds.length
? txMatchIds.map(function(id){ return (AppState.transactions||[]).find(function(t){return t.id===id;}); }).filter(Boolean)
: (AppState.transactions||[]).filter(function(t){
var name = t.merchantNorm||t.merchantRaw||t.merchant||t.category||'';
return cpFuzzy(name,ql)||cpFuzzy(t.category||'',ql)||(t.amount&&String(t.amount).indexOf(ql)>=0);
}).slice(0,5);
if(txMatches.length){
results.push({type:'section', label:'Transactions'});
txMatches.forEach(function(t){
var name = t.merchantNorm||t.merchantRaw||t.merchant||t.category;
results.push({type:'tx', icon:CEM[t.category]||'&#128230;', title:name, sub:t.date+' · '+esc(t.category), right:(t.type==='income'?'+':'-')+fmt(t.amount), action:function(){showTxDetail(t.id);}});
});
}
var catMatches = CATS.expense.filter(function(c){return cpFuzzy(c,ql);});
if(catMatches.length){
results.push({type:'section', label:'Categories'});
catMatches.slice(0,4).forEach(function(c){
results.push({type:'cat', icon:CEM[c]||'&#128230;', title:c, sub:'View category', action:function(){showAnCatDetail(c);gp('Analytics',null);}});
});
}
var billMatches = (AppState.recurRules||[]).filter(function(r){return r.type==='bill'&&cpFuzzy(r.name||'',ql);});
if(billMatches.length){
results.push({type:'section', label:'Bills'});
billMatches.slice(0,3).forEach(function(r){
var st = billStatus(r);
results.push({type:'bill', icon:'&#128184;', title:r.name, sub:fmt(r.amount)+'/mo · '+st.label.replace(/&[^;]+;/g,''), action:function(){showBillDetail(r.id);}});
});
}
var goalMatches = (AppState.goals||[]).filter(function(g){return cpFuzzy(g.name||'',ql);});
if(goalMatches.length){
results.push({type:'section', label:'Goals'});
goalMatches.slice(0,3).forEach(function(g){
var pct = g.target>0?Math.min((g.saved||0)/g.target*100,100):0;
results.push({type:'goal', icon:g.icon||'&#127919;', title:g.name, sub:Math.round(pct)+'% · '+fmt(g.saved||0)+' of '+fmt(g.target), action:function(){showGoalDetail(g.id);}});
});
}
var alertMatches = buildAlerts ? buildAlerts(mTx()).filter(function(a){
return !isResolved(a.id)&&(cpFuzzy(a.title||'',ql)||cpFuzzy(a.detail||'',ql));
}) : [];
if(alertMatches.length){
results.push({type:'section', label:'Alerts'});
alertMatches.slice(0,3).forEach(function(a){
results.push({type:'alert', icon:a.icon||'&#128276;', title:a.title, sub:a.detail||'', action:function(){gp('Alerts',null);resolveAlert&&null;}});
});
}
var merchMatches = Object.keys(AppState.merchantMem||{}).filter(function(m){return cpFuzzy(m,ql);});
if(merchMatches.length){
results.push({type:'section', label:'Merchants'});
merchMatches.slice(0,3).forEach(function(m){
var cat = AppState.merchantMem[m].category||'';
results.push({type:'merch', icon:CEM[cat]||'&#127978;', title:m, sub:cat, action:function(){showAnMerchDetail(m);gp('Analytics',null);}});
});
}
}
return results;
}
function cpRender(q) {
var el = document.getElementById('cp-results');
if(!el) return;
var results = cpBuildResults(q);
_cpItems = results.filter(function(r){return r.type!=='section';});
_cpSel   = 0;
if(!results.length || (!q && !_cpItems.length)){
el.innerHTML = '<div class="cp-empty" aria-live="polite">&#128270; Type to search transactions, bills, goals, and more…<br><span style="font-size:var(--fs-caption)">Or try: "Add transaction", "Budget", "Dark mode"</span></div>';
return;
}
var html = '';
var itemIdx = 0;
results.forEach(function(r){
if(r.type==='section'){
html += '<div class="cp-section-hdr" aria-label="'+esc(r.label)+' results">'+r.label+'</div>';
} else {
var isActive = itemIdx===_cpSel;
html += '<div class="cp-item'+(isActive?' active':'')+'" tabindex="0" role="option"'
+' aria-selected="'+(isActive?'true':'false')+'"'
+' aria-label="'+esc(r.title)+(r.sub?', '+esc(r.sub.replace(/&[^;]+;/g,'')):'')+'  — press Enter to open"'
+' data-cpidx="'+itemIdx+'"'
+' onclick="cpExec('+itemIdx+')"'
+' onmouseenter="cpSetSel('+itemIdx+')">'
+'<div class="cp-icon" aria-hidden="true">'+r.icon+'</div>'
+'<div class="cp-item-body">'
+'<div class="cp-item-title">'+(q?cpHighlight(r.title,q):esc(r.title))+'</div>'
+(r.sub?'<div class="cp-item-sub">'+esc(r.sub.replace(/&[^;]+;/g,''))+'</div>':'')
+'</div>'
+(r.right?'<div class="cp-item-right">'+esc(r.right)+'</div>':'')
+'</div>';
itemIdx++;
}
});
el.innerHTML = html;
}
function cpSetSel(idx) {
_cpSel = idx;
document.querySelectorAll('.cp-item').forEach(function(el,i){
el.classList.toggle('active', i===idx);
el.setAttribute('aria-selected', i===idx);
});
}
function cpExec(idx) {
var item = _cpItems[idx];
if(!item || !item.action) return;
cpClose();
setTimeout(function(){ try{ item.action(); }catch(e){} }, 80);
}
function cpOnKey(e) {
if(e.key==='Escape'){ cpClose(); return; }
if(e.key==='ArrowDown'){ e.preventDefault(); cpSetSel(Math.min(_cpSel+1, _cpItems.length-1)); cpScrollSel(); return; }
if(e.key==='ArrowUp'){   e.preventDefault(); cpSetSel(Math.max(_cpSel-1, 0)); cpScrollSel(); return; }
if(e.key==='Enter'){ e.preventDefault(); cpExec(_cpSel); return; }
}
function cpScrollSel() {
var active = document.querySelector('.cp-item.active');
if(active) active.scrollIntoView({block:'nearest'});
}
function cpOnInput(q) {
if(_cpTimer) clearTimeout(_cpTimer);
_cpTimer = setTimeout(function(){
_cpLastQ = q;
cpRender(q);
}, 80);
}
