var _recurDetectCache = null; // { key, patterns }
function detectAllRecurringPatterns() {
var cacheKey = (AppState.transactions||[]).length + '_' + (AppState.recurRules||[]).length;
if(_recurDetectCache && _recurDetectCache.key === cacheKey) return _recurDetectCache.patterns;
var txs = AppState.transactions||[];
var groups = {};
txs.filter(function(t){return t.type==='expense';}).forEach(function(t){
var norm = normalizeMerchant(t.merchantRaw||t.merchant||'');
if(!norm) return;
if(!groups[norm]) groups[norm] = [];
groups[norm].push(t);
});
var patterns = [];
Object.keys(groups).forEach(function(norm){
var grpTxs = groups[norm].slice().sort(function(a,b){return a.date.localeCompare(b.date);});
if(grpTxs.length < 3) return;
var avgAmt = grpTxs.reduce(function(s,t){return s+t.amount;},0) / grpTxs.length;
var amtConsistent = grpTxs.every(function(t){return Math.abs(t.amount-avgAmt)<=2;});
if(!amtConsistent) return;
var diffs = [];
for(var i=1;i<grpTxs.length;i++){
var d1=new Date(grpTxs[i-1].date+'T12:00:00');
var d2=new Date(grpTxs[i].date+'T12:00:00');
diffs.push(Math.round((d2-d1)/(1000*86400)));
}
var avgDiff = diffs.reduce(function(s,d){return s+d;},0)/diffs.length;
var diffVariance = diffs.reduce(function(s,d){return s+Math.pow(d-avgDiff,2);},0)/diffs.length;
var diffStdDev = Math.sqrt(diffVariance);
var freq = null;
if(avgDiff>=6  && avgDiff<=8   && diffStdDev<=1)  freq='weekly';
if(avgDiff>=12 && avgDiff<=16  && diffStdDev<=2)  freq='biweekly';
if(avgDiff>=27 && avgDiff<=33  && diffStdDev<=3)  freq='monthly';
if(avgDiff>=85 && avgDiff<=95  && diffStdDev<=5)  freq='quarterly';
if(avgDiff>=355&& avgDiff<=375 && diffStdDev<=10) freq='annual';
if(!freq) return;
var amtConf   = amtConsistent ? 0.35 : 0.10;
var dateConf  = Math.max(0, 0.35 - diffStdDev*0.02);
var countConf = Math.min(0.30, grpTxs.length * 0.06);
var confidence = Math.min(0.99, amtConf + dateConf + countConf);
if(confidence < 0.60) return; // skip low-confidence
var exists = (AppState.recurRules||[]).some(function(r){
var rn = normalizeMerchant(r.name||r.keyword||'');
return rn === norm;
});
patterns.push({
norm: norm,
amount: avgAmt,
frequency: freq,
confidence: confidence,
category: grpTxs[grpTxs.length-1].category || 'Other',
lastDate: grpTxs[grpTxs.length-1].date,
txCount: grpTxs.length,
alreadyHasRule: exists
});
});
patterns.sort(function(a,b){return b.confidence-a.confidence;});
_recurDetectCache = {key:cacheKey, patterns:patterns};
dbg('[DBG] Recurring patterns detected: '+patterns.length);
return patterns;
}
function recurConfBadge(conf) {
var cls = conf>=0.85?'hi':conf>=0.60?'md':'lo';
var label = conf>=0.85?'High':conf>=0.60?'Medium':'Low';
return '<span class="recur-conf '+cls+'" aria-label="Confidence: '+label+'">'+label+'</span>';
}
function autoCreateRecurRules() {
var patterns = detectAllRecurringPatterns();
var created = 0;
patterns.forEach(function(p){
if(p.alreadyHasRule || p.confidence < 0.80) return;
var nextDue = calcNextDue ? calcNextDue(p.lastDate, p.frequency) : p.lastDate;
var rule = {
id: 'auto_'+String(Date.now())+'_'+created,
type: 'bill',
name: p.norm,
amount: Math.round(p.amount*100)/100,
category: p.category,
freq: p.frequency,
dayOfMonth: parseInt(p.lastDate.split('-')[2])||1,
keyword: p.norm.toLowerCase().split(' ')[0],
tolerance: 2,
active: true,
autoGenerate: false,
lastMatched: p.lastDate,
nextDue: nextDue,
lastPaid: p.lastDate,
payHistory: [],
confidence: p.confidence,
autoDetected: true
};
AppState.recurRules = AppState.recurRules||[];
AppState.recurRules.push(rule);
created++;
dbg('[DBG] Auto-created recurring rule: '+p.norm+' ('+p.frequency+', conf='+p.confidence.toFixed(2)+')');
});
if(created > 0) {
saveMeta(); lsSave();
toast('&#128260; '+created+' recurring pattern'+(created>1?'s':'')+(created>1?' detected':' detected')+'!');
_recurDetectCache = null;
}
return created;
}
function maintainNextDueDates() {
var today = getTodayStr();
var changed = false;
(AppState.recurRules||[]).forEach(function(rule){
if(!rule.active) return;
if(!rule.nextDue || rule.nextDue < today) {
var base = rule.lastPaid || rule.lastMatched || today;
if(calcNextDue) rule.nextDue = calcNextDue(base, rule.freq||'monthly');
changed = true;
}
});
if(changed) { saveMeta(); dbg('[DBG] Next-due dates maintained'); }
}
function rBillsDetectionPanel() {
var patterns = detectAllRecurringPatterns();
var newPatterns = patterns.filter(function(p){return !p.alreadyHasRule && p.confidence>=0.80;});
if(!newPatterns.length) return '';
return '<div class="recur-detect-section">'
+'<div class="dash-card-title" style="margin-bottom:var(--xs)">&#128270; Patterns Detected</div>'
+newPatterns.slice(0,3).map(function(p){
return '<div class="recur-detected-banner">'
+'<span style="flex:1">&#128260; <b>'+esc(p.norm)+'</b> &mdash; '+BILL_FREQ_LABELS[p.frequency]||p.frequency+' &middot; '+fmt(p.amount)+'</span>'
+recurConfBadge(p.confidence)
+'<button class="bsc-qf-btn" style="flex:0 0 auto;padding:4px 10px;margin-left:4px;" onclick="createRuleFromPattern(\''+encodeURIComponent(JSON.stringify(p))+'\')" aria-label="Create rule for '+esc(p.norm)+'">+ Rule</button>'
+'</div>';
}).join('')
+(newPatterns.length>3?'<div class="sm" style="padding:4px var(--sm)">+'+( newPatterns.length-3)+' more patterns — <button style="background:none;border:none;cursor:pointer;color:var(--gd);font-family:inherit;font-size:inherit;font-weight:700;padding:0" onclick="autoCreateRecurRules()">Auto-add all</button></div>':'')
+'</div>';
}
function createRuleFromPattern(encoded) {
var p;
try { p = JSON.parse(decodeURIComponent(encoded)); }
catch(e) { toast('&#9888; Could not create rule — pattern data was corrupted.'); return; }
var nextDue = calcNextDue ? calcNextDue(p.lastDate, p.frequency) : p.lastDate;
pushSnapshot('Create recurring rule from pattern');
AppState.recurRules = AppState.recurRules||[];
AppState.recurRules.push({
id:'auto_'+String(Date.now()),type:'bill',
name:p.norm, amount:Math.round(p.amount*100)/100,
category:p.category, freq:p.frequency,
dayOfMonth:parseInt(p.lastDate.split('-')[2])||1,
keyword:p.norm.toLowerCase().split(' ')[0],
tolerance:2, active:true, autoGenerate:false,
lastMatched:p.lastDate, nextDue:nextDue,
lastPaid:p.lastDate, payHistory:[],
confidence:p.confidence, autoDetected:true
});
_recurDetectCache = null;
saveMeta(); lsSave(); rRecurring();
toast('&#10003; Rule created for '+esc(p.norm)+'!');
}
