function classifyCloudError(err) {
var raw = (err && (err.message || String(err))) || 'Unknown error';
var low = raw.toLowerCase();
if(/jwt|token|auth|unauthorized|403|401/.test(low))
return { type:'auth',       message:raw, retryable:false, userMsg:'Sign in required' };
if(/network|fetch|failed to fetch|offline|timeout|504|503/.test(low))
return { type:'network',    message:raw, retryable:true,  userMsg:'Network error — will retry' };
if(/rate.?limit|429|too many/.test(low))
return { type:'rate_limit', message:raw, retryable:true,  userMsg:'Rate limited — will retry' };
if(/conflict|version|duplicate/.test(low))
return { type:'conflict',   message:raw, retryable:false, userMsg:'Sync conflict detected' };
if(/quota|storage|size/.test(low))
return { type:'quota',      message:raw, retryable:false, userMsg:'Storage limit reached' };
if(/permission|rls|policy|violates row.level|insufficient_privilege|42501|not.*owner/.test(low))
return { type:'permission', message:raw, retryable:false, userMsg:'Permission denied — check your household role' };
return   { type:'unknown',    message:raw, retryable:true,  userMsg:'Sync error' };
}
function recordCloudSyncError(err, context) {
var classified = classifyCloudError(err);
var now        = new Date().toISOString();
var entry      = { ts: now, message: classified.message, type: classified.type,
context: context || 'unknown', userMsg: classified.userMsg };
if(!Array.isArray(AppState.cloudErrorHistory)) AppState.cloudErrorHistory = [];
AppState.cloudErrorHistory.push(entry);
if(AppState.cloudErrorHistory.length > 10) AppState.cloudErrorHistory.shift();
AppState.cloudErrorCount = (AppState.cloudErrorCount || 0) + 1;
AppState.lastCloudSyncError = classified.userMsg + (classified.type !== 'unknown' ? ' (' + classified.type + ')' : '');
logCloudActivity('error', classified.userMsg + ' [' + context + ']', { type: classified.type, context: context, retryable: classified.retryable });
var windowMs   = 60000;
var cutoff     = new Date(Date.now() - windowMs).toISOString();
var recentSame = AppState.cloudErrorHistory.filter(function(e) {
return e.context === context && e.ts >= cutoff;
}).length;
var throttled  = recentSame > 3;
dbg('[recordCloudSyncError] type=' + classified.type + ' context=' + context
+ ' count=' + AppState.cloudErrorCount + ' throttled=' + throttled);
if(typeof renderCloudSyncError === 'function') try{ renderCloudSyncError(throttled); }catch(ex){}
return { classified: classified, throttled: throttled };
}
function renderCloudSyncError(throttled) {
var el = document.getElementById('cloud-sync-error');
if(!el) return;
var msg   = AppState.lastCloudSyncError;
var count = AppState.cloudErrorCount || 0;
if(!msg || count === 0) {
el.className   = '';
el.textContent = '';
return;
}
var isPermissionError = AppState.cloudErrorHistory.length > 0 &&
AppState.cloudErrorHistory[AppState.cloudErrorHistory.length - 1].type === 'permission';
el.className = isPermissionError ? 'permission' : (throttled ? 'throttled' : 'visible');
var countBadge = count > 1
? '<span class="cse-count">&#215;' + count + '</span>'
: '';
el.innerHTML = '&#9888; ' + esc(msg) + countBadge;
if(!el._errDismissAttached) {
el._errDismissAttached = true;
el.addEventListener('click', function() {
AppState.lastCloudSyncError = null;
AppState.cloudErrorCount    = 0;
el.className   = '';
el.textContent = '';
if(el._hideTimer) clearTimeout(el._hideTimer);
}, { passive: true });
}
if(el._hideTimer) clearTimeout(el._hideTimer);
el._hideTimer = setTimeout(function() {
el.className   = '';
el.textContent = '';
}, 12000);
}
function logCloudActivity(type, message, meta) {
if(!Array.isArray(AppState.cloudActivityFeed)) AppState.cloudActivityFeed = [];
var entry = {
ts:      new Date().toISOString(),
type:    type    || 'info',
message: message || '',
meta:    meta    || null
};
AppState.cloudActivityFeed.push(entry);
if(AppState.cloudActivityFeed.length > 50) AppState.cloudActivityFeed.shift();
dbg('[cloudActivity] ' + type + ': ' + message);
}
function renderCloudActivityFeed(showCount) {
var el = document.getElementById('cloud-activity-feed');
if(!el) return;
var feed = AppState.cloudActivityFeed || [];
if(!feed.length) { el.className = ''; el.innerHTML = ''; return; }
var n    = typeof showCount === 'number' ? showCount : 5;
var rows = feed.slice(-n).reverse(); // kept for potential future use
el.className = ''; // suppressed — sync logs are internal, not user-facing
el.innerHTML = '';
}
window.addEventListener('online', function() {
var now = new Date().toISOString();
AppState.isOnline        = true;
AppState.lastOnlineChange= now;
var netEl = document.getElementById('network-status');
if(netEl) netEl._showOnlineFlash = true;
if(typeof render === 'function') try{ render(); }catch(e){}
dbg('[online] network restored at ' + now);
processOfflineQueue().then(function(r) {
if(r && r.sent > 0) toast('&#9729; Back online — ' + r.sent + ' queued write' + (r.sent===1?'':'s') + ' synced.');
}).catch(function(e) {
dbg('[online] queue flush error: ' + e.message);
});
if(shouldTriggerReconnectSync()) {
if(typeof runCloudSync === 'function') {
runCloudSync().catch(function(e){ dbg('[online] runCloudSync error: ' + e.message); });
} else if(typeof syncEngine !== 'undefined') {
syncEngine.run('incremental').catch(function(e){ dbg('[online] syncEngine error: ' + e.message); });
}
}
});
window.addEventListener('offline', function() {
var now = new Date().toISOString();
AppState.isOnline        = false;
AppState.lastOnlineChange= now;
dbg('[offline] network lost at ' + now);
if(typeof render === 'function') try{ render(); }catch(e){}
});
