async function renameHousehold(newName) {
var sb = sbInit(); if(!sb || !_v2Household || !_v2User) return;
if(AppState.currentUserRole !== 'owner') { toast('Only the household owner can rename the household.'); return; }
if(!newName || !newName.trim()) { toast('Enter a household name.'); return; }
var name = newName.trim();
try {
var r = await sb.from('households')
.update({ name: name, updated_at: new Date().toISOString() })
.eq('id', _v2Household.id)
.eq('owner_user_id', _v2User.id); // only owner can rename
if(r.error) throw r.error;
_v2Household.name = name;
safeSet(V2_HH_KEY, JSON.stringify(_v2Household));
toast('&#10003; Household renamed!');
dbg('[HH] Renamed to: '+name);
writeAudit('household_renamed', null, { name: name });
writeNotification('household_renamed', 'Household renamed', 'Your household was renamed to "' + name + '".', null);
var nameEl = document.getElementById('hh-name-display');
if(nameEl){ nameEl.classList.remove('hh-name-saved'); void nameEl.offsetWidth; nameEl.classList.add('hh-name-saved'); }
hhRenderSettings();
} catch(e) { toast('Rename failed: '+e.message); dbg('[HH] rename error: '+e.message); }
}
