async function acceptInvite(inviteId) {
var sb = sbInit(); if(!sb || !_v2User) { toast('Sign in first to accept invite.'); return; }
dbg('[HH] Accepting invite: '+inviteId);
try {
var ir = await sb.from('invites').select('*').eq('id', inviteId).single();
if(ir.error) throw ir.error;
var invite = ir.data;
if(!invite) throw new Error('Invite not found.');
if(invite.status !== 'pending') throw new Error('Invite already '+invite.status+'.');
var mr = await sb.from('household_members').insert({
household_id: invite.household_id,
user_id: _v2User.id,
role: 'member'
});
if(mr.error) throw mr.error;
await sb.from('invites').update({ status:'accepted', updated_at:new Date().toISOString() }).eq('id', inviteId);
var hr = await sb.from('households').select('*').eq('id', invite.household_id).single();
if(!hr.error && hr.data) {
_v2Household = hr.data;
safeSet(V2_HH_KEY, JSON.stringify(_v2Household));
}
toast('&#127881; Joined household! Syncing…');
dbg('[HH] Invite accepted — joined '+(_v2Household?_v2Household.name:'household'));
await syncEngine.run('full');
renderAll();
} catch(e) {
toast('Could not accept invite: '+e.message);
dbg('[HH] acceptInvite error: '+e.message);
}
}
