var okEl  = document.getElementById('hh-invite-ok');
var btn   = document.getElementById('hh-invite-send-btn');
if(errEl) errEl.className='auth-err';
if(okEl)  okEl.className='auth-ok';
if(!email || !/\S+@\S+\.\S+/.test(email)) {
if(errEl){ errEl.textContent='Enter a valid email.'; errEl.className='auth-err show'; }
return;
}
