var _hspTrigger = null;
function hspOpen() {
var panel    = document.getElementById('household-settings-panel');
var backdrop = document.getElementById('hsp-backdrop');
var toggle   = document.getElementById('hsp-toggle');
_hspTrigger = _captureFocusTrigger();
if(panel)    { panel.classList.add('open'); }
if(backdrop) { backdrop.classList.add('open'); }
if(toggle)   { toggle.classList.add('open'); }
if(typeof enableScrollLock === 'function') enableScrollLock();
renderHouseholdSettingsPanel();
setTimeout(function(){ var closeBtn=panel&&panel.querySelector('.hsp-close'); if(closeBtn) closeBtn.focus(); }, 50);
// Populate insights-tools section (rendered into page-Budget IDs)
var _toolFns=[renderAIInsights,renderForecast,renderFinancialHealthScore,renderNetWorth,
  renderAdvisorThread,renderAIMemory,renderAnomalies,renderSubscriptions,renderTaxPrep,
  renderInvestmentInsights,renderBillNegotiations,renderInsuranceInsights,
  renderRetirementInsights,renderCashInsights,renderEstateInsights,
  renderLongTermRiskInsights,renderLifeEventInsights,renderMilestones,renderVault];
_toolFns.forEach(function(fn){try{if(typeof fn==='function')fn();}catch(e){}});
}
function hspClose() {
var panel    = document.getElementById('household-settings-panel');
var backdrop = document.getElementById('hsp-backdrop');
var toggle   = document.getElementById('hsp-toggle');
if(panel)    { panel.classList.remove('open'); }
if(backdrop) { backdrop.classList.remove('open'); }
if(toggle)   { toggle.classList.remove('open'); }
if(typeof disableScrollLock === 'function') disableScrollLock();
if (_hspTrigger && typeof _hspTrigger.focus === 'function' && document.contains(_hspTrigger)) _hspTrigger.focus();
_hspTrigger = null;
}
function writeAudit(action, targetId, meta) {
var client = sb || sbInit();
if(!client || !_v2Household) return;
var hhId = _v2Household.id;
var catEntry = typeof ACTIVITY_ACTION_MAP !== 'undefined' && ACTIVITY_ACTION_MAP[action];
var category = (catEntry && catEntry.category) || 'general';
client.rpc('write_audit_log', {
p_household_id: hhId,
p_action:       action,
p_target_id:    targetId  || null,
p_meta:         meta      || null,
p_category:     category
}).then(function(r) {
if(r && r.error) dbg('[writeAudit] rpc error: ' + r.error.message);
else              dbg('[writeAudit] ' + action + ' (' + category + ') logged');
}).catch(function(e) {
dbg('[writeAudit] catch: ' + e.message);
});
}
async function loadBillingPlan() {
if(_v2Household && _v2Household.plan) {
AppState.billingPlan      = _v2Household.plan || 'free';
AppState.stripeCustomerId = _v2Household.stripe_customer_id || null;
dbg('[loadBillingPlan] fast-path: ' + AppState.billingPlan);
return AppState.billingPlan;
}
var client = sb || sbInit();
if(!client || !_v2Household) return AppState.billingPlan;
try {
var r = await client
.from('households')
.select('plan, stripe_customer_id')
.eq('id', _v2Household.id)
.single();
if(r.error) throw r.error;
var row = r.data || {};
AppState.billingPlan      = row.plan || 'free';
AppState.stripeCustomerId = row.stripe_customer_id || null;
if(_v2Household) {
var _prevPlan = _v2Household.plan;
_v2Household.plan               = AppState.billingPlan;
_v2Household.stripe_customer_id = AppState.stripeCustomerId;
if(_prevPlan && _prevPlan !== AppState.billingPlan) {
writeNotification('billing_changed', 'Plan updated', 'Your household plan changed to ' + AppState.billingPlan + '.', null);
writeAudit('billing_plan_changed', null, { oldPlan: _prevPlan, newPlan: AppState.billingPlan });
triggerWebhookEvent('billing_plan_changed', { oldPlan: _prevPlan, newPlan: AppState.billingPlan });
sendPushEventAdvanced('billing_plan_changed', 'Plan updated', 'Your household plan changed to ' + AppState.billingPlan + '.', null, null, { actions: [{ id:'view', label:'View billing' }] });
}
}
dbg('[loadBillingPlan] plan=' + AppState.billingPlan);
return AppState.billingPlan;
} catch(e) {
dbg('[loadBillingPlan] error: ' + e.message);
return AppState.billingPlan;
}
}
function requireProFeature(featureName) {
var plan = AppState.billingPlan || (_v2Household && _v2Household.plan) || 'free';
if(plan === 'pro' || plan === 'team') return true;
var msg = (featureName || 'This feature') + ' is available on the Pro plan.';
toast('&#128274; ' + msg + ' Open Household Settings to upgrade.');
setTimeout(function() { if(typeof hspOpen === 'function') hspOpen(); }, 2400);
dbg('[requireProFeature] blocked: ' + featureName + ' (plan=' + plan + ')');
return false;
}
async function startCheckoutSession() {
if(AppState.currentUserRole !== 'owner') {
toast('Only the household owner can upgrade the plan.');
return;
}
var client = sb || sbInit();
if(!client || !_v2Household) { toast('Sign in to upgrade.'); return; }
var upgradeBtn = document.getElementById('hsp-upgrade-btn');
if(upgradeBtn) { upgradeBtn.disabled = true; upgradeBtn.textContent = 'Redirecting…'; }
try {
var r = await client.rpc('create_checkout_session', {
p_household_id: _v2Household.id,
p_success_url:  window.location.href + '?billing=success',
p_cancel_url:   window.location.href + '?billing=cancel'
});
if(r.error) throw r.error;
var data = r.data || {};
if(data.url) {
window.location.href = data.url;
} else {
toast('&#9888; ' + (data.error || 'Billing not configured yet.'));
}
} catch(e) {
toast('&#9888; Checkout failed: ' + e.message);
dbg('[startCheckoutSession] error: ' + e.message);
}
if(upgradeBtn) { upgradeBtn.disabled = false; upgradeBtn.innerHTML = '&#9889; Upgrade to Pro'; }
}
function renderBillingPlan() {
var el = document.getElementById('hsp-billing');
if(!el) return;
var plan    = AppState.billingPlan || 'free';
var isOwner = AppState.currentUserRole === 'owner';
var PLAN_LABELS = { free: 'Free', pro: 'Pro', team: 'Team' };
var label = PLAN_LABELS[plan] || plan;
var html = '<div class="hsp-plan-row">'
+ '<span style="font-size:var(--fs-subtext);font-weight:600">Current Plan</span>'
+ '<span class="hsp-plan-badge ' + esc(plan) + '">'
+ (plan === 'pro' || plan === 'team' ? '&#9889; ' : '')
+ esc(label)
+ '</span>'
+ '</div>';
if(plan === 'free') {
html += '<div style="font-size:var(--fs-caption);color:var(--sub);margin-bottom:var(--sm)">'
+ 'Pro unlocks multi-device sync, advanced analytics, and priority support.'
+ '</div>';
if(isOwner) {
html += '<button id="hsp-upgrade-btn" class="hsp-upgrade-btn" onclick="startCheckoutSession()" aria-label="Upgrade to Pro">&#9889; Upgrade to Pro</button>';
} else {
html += '<div class="hsp-pro-feature-lock">&#128274; Ask your household owner to upgrade</div>';
}
} else {
html += '<div style="font-size:var(--fs-caption);color:var(--sub)">'
+ '&#10003; All Pro features are active.'
+ '</div>';
if(isOwner) {
html += '<div style="margin-top:var(--xs);font-size:var(--fs-caption);color:var(--sub)">'
+ 'Manage subscription at <a href="https://billing.stripe.com/p/login" target="_blank" rel="noopener" style="color:var(--gm)">billing.stripe.com</a>.'
+ '</div>';
}
}
el.innerHTML = html;
}
var _notifications      = [];   // cache — array of notification rows
var _notifUnreadCount   = 0;    // unread badge count
function writeNotification(type, title, body, userId) {
var client = sb || sbInit();
if(!client || !_v2Household) return;
client.rpc('write_notification', {
p_household_id: _v2Household.id,
p_type:         type,
p_title:        title,
p_body:         body  || null,
p_user_id:      userId || null
}).then(function(r) {
if(r && r.error) dbg('[writeNotification] rpc error: ' + r.error.message);
else              dbg('[writeNotification] sent: ' + type);
}).catch(function(e) {
dbg('[writeNotification] catch: ' + e.message);
});
}
async function fetchNotifications(limit) {
var client = sb || sbInit();
if(!client || !_v2User) return [];
var n = typeof limit === 'number' ? limit : 30;
try {
var r = await client
.from('household_notifications')
.select('id, type, title, body, read, created_at, actor_id')
.eq('household_id', _v2Household ? _v2Household.id : AppState.householdId)
.order('created_at', { ascending: false })
.limit(n);
if(r.error) throw r.error;
_notifications    = r.data || [];
_notifUnreadCount = _notifications.filter(function(n){ return !n.read; }).length;
dbg('[fetchNotifications] loaded ' + _notifications.length + ' (' + _notifUnreadCount + ' unread)');
return _notifications;
} catch(e) {
dbg('[fetchNotifications] error: ' + e.message);
return [];
}
}
async function markNotificationRead(id) {
var client = sb || sbInit();
if(!client || !id) return;
try {
var r = await client
.from('household_notifications')
.update({ read: true })
.eq('id', id)
.eq('user_id', _v2User ? _v2User.id : null);  // RLS guard
if(r.error) throw r.error;
_notifications.forEach(function(n){ if(n.id === id) n.read = true; });
_notifUnreadCount = _notifications.filter(function(n){ return !n.read; }).length;
renderNotifications();
} catch(e) {
dbg('[markNotificationRead] error: ' + e.message);
}
}
async function markAllNotificationsRead() {
var client = sb || sbInit();
if(!client || !_v2User) return;
var unreadIds = _notifications.filter(function(n){ return !n.read; }).map(function(n){ return n.id; });
if(!unreadIds.length) return;
try {
var r = await client
.from('household_notifications')
.update({ read: true })
.in('id', unreadIds)
.eq('user_id', _v2User.id);
if(r.error) throw r.error;
_notifications.forEach(function(n){ n.read = true; });
_notifUnreadCount = 0;
renderNotifications();
} catch(e) {
dbg('[markAllNotificationsRead] error: ' + e.message);
}
}
function notifOpen() {
var panel    = document.getElementById('notification-panel');
var backdrop = document.getElementById('notif-backdrop');
if(backdrop) backdrop.classList.add('open');
requestAnimationFrame(function(){
if(panel) panel.classList.add('open');
});
if(typeof enableScrollLock === 'function') enableScrollLock();
fetchNotifications().then(function() { renderNotifications(); });
dbg('[NOTIF] Panel opened');
}
function notifClose() {
var panel    = document.getElementById('notification-panel');
var backdrop = document.getElementById('notif-backdrop');
if(panel)    panel.classList.remove('open');
if(backdrop) backdrop.classList.remove('open');
if(typeof disableScrollLock === 'function') disableScrollLock();
dbg('[NOTIF] Panel closed');
}
