function checkLimit(dimension, current) {
var plan  = AppState.billingPlan || 'free';
var limits = PLAN_LIMITS[plan] || PLAN_LIMITS.free;
var cap   = limits[dimension];
if(cap === undefined) return { ok: true, pct: 0, warn: false, reached: false };
if(cap === Infinity)  return { ok: true, pct: 0, warn: false, reached: false };
var DIM_MAP = {
transactions: 'transactions_count',
accounts:     'accounts_count',
members:      'members_count',
invites_30d:  'invites_sent_30d',
exports_30d:  'exports_count_30d'
};
var used = (current !== undefined)
? current
: (_usageCache[DIM_MAP[dimension]] || 0);
var pct     = cap > 0 ? Math.min(1, used / cap) : 0;
var warn    = pct >= 0.8;
var reached = used >= cap;
return { ok: !reached, pct: pct, warn: warn, reached: reached, used: used, cap: cap };
}
function _checkUsageWarnings() {
var dims = ['transactions', 'accounts', 'members', 'invites_30d'];
var LABELS = { transactions:'Transactions', accounts:'Accounts',
members:'Members', invites_30d:'Invites (30d)' };
dims.forEach(function(dim) {
var r = checkLimit(dim);
if(r.reached && r._lastNotified !== 'reached_' + r.used) {
r._lastNotified = 'reached_' + r.used;
writeNotification('limit_reached',
LABELS[dim] + ' limit reached',
'You\'ve used all ' + r.cap + ' ' + LABELS[dim].toLowerCase() + ' on the '
+ (AppState.billingPlan || 'free') + ' plan. Upgrade to continue.',
null);
} else if(r.warn && !r.reached && r._lastNotified !== 'warn_' + Math.floor(r.pct * 10)) {
r._lastNotified = 'warn_' + Math.floor(r.pct * 10);
writeNotification('limit_warning',
LABELS[dim] + ' limit approaching',
'You\'ve used ' + r.used + ' of ' + r.cap + ' ' + LABELS[dim].toLowerCase() + '.',
null);
}
});
}
