+ (!inactive ? '<div class="sharing-link-url" onclick="navigator.clipboard&&navigator.clipboard.writeText(\'' + esc(url) + '\').then(function(){toast(\'Link copied!\');})" title="Click to copy">' + esc(url.replace(/https?:\/\/[^/]+/, '')) + '</div>' : '')
+ '</div>'
