+ (!inactive
? '<button class="sl-btn copy" onclick="navigator.clipboard&&navigator.clipboard.writeText(\'' + esc(url) + '\').then(function(){toast(\'Link copied!\');})" aria-label="Copy link">&#128203;</button>'
: '')
