async function fetchActivityFeed(limit, category) {
var client = sb || sbInit();
if(!client || !_v2Household) return [];
var n = typeof limit === 'number' ? limit : 40;
try {
var q = client
.from('household_audit_log')
.select('id, action, target_id, meta, category, created_at, actor_id')
.eq('household_id', _v2Household.id)
.order('created_at', { ascending: false })
.limit(n);
if(category && category !== 'all') q = q.eq('category', category);
var r = await q;
if(r.error) throw r.error;
_activityFeedCache = (r.data || []).map(function(row) {
return formatActivityItem(row);
});
dbg('[fetchActivityFeed] loaded ' + _activityFeedCache.length);
return _activityFeedCache;
} catch(e) {
dbg('[fetchActivityFeed] error: ' + e.message);
return [];
}
}
function formatActivityItem(row) {
var mapped   = ACTIVITY_ACTION_MAP[row.action] || { label: row.action, category: row.category || 'general' };
var category = row.category || mapped.category || 'general';
var meta     = row.meta || {};
var detail = '';
if(meta.email)      detail = meta.email;
else if(meta.name)  detail = meta.name;
else if(meta.label) detail = meta.label;
else if(meta.role)  detail = '\u2192 ' + meta.role;
else if(meta.format)detail = meta.format.toUpperCase();
else if(meta.plan)  detail = meta.plan;
else if(meta.newPlan) detail = meta.oldPlan + ' \u2192 ' + meta.newPlan;
else if(meta.url)   detail = meta.url;
else if(meta.itemCount !== undefined) detail = meta.itemCount + ' items';
else if(meta.tx_count !== undefined) detail = meta.tx_count + ' transactions';
else if(meta.rows !== undefined) detail = meta.rows + ' rows';
return {
id:        row.id,
action:    row.action,
label:     mapped.label,
category:  category,
catIcon:   ACTIVITY_CAT_ICONS[category] || '&#8226;',
detail:    detail,
actor:     row.actor_id || null,
timestamp: row.created_at
};
}
function renderActivityFeedV2() {
var el = document.getElementById('activity-feed-v2');
if(!el) return;
var CATS = ['all','members','transactions','billing','backup','export','sharing','webhooks','insights','anomalies','forecasting','vault','health','goals','advisor','networth','subscriptions','taxprep','investments','negotiations','insurance','retirement','cash','estate','risk','lifeevents','scenarios','orchestrator','masterbrain'];
var chips = CATS.map(function(c) {
var on = _activityFeedFilter === c;
return '<button class="afv2-chip' + (on ? ' on' : '') + '"'
+ ' onclick="_afv2SetFilter(\'' + c + '\')"'
+ ' aria-pressed="' + on + '">'
+ (c === 'all' ? 'All' : esc(c))
+ '</button>';
}).join('');
var items = _activityFeedFilter === 'all'
? _activityFeedCache
: _activityFeedCache.filter(function(e){ return e.category === _activityFeedFilter; });
var rowsHtml = '';
if(!items.length) {
rowsHtml = '<div class="afv2-empty">'
+ (_activityFeedCache.length ? 'No ' + _activityFeedFilter + ' events yet.' : 'No activity recorded yet.')
+ '</div>';
if(!_activityFeedCache.length && (sb || sbInit()) && _v2Household) {
fetchActivityFeed().then(function(rows) { if(rows.length) renderActivityFeedV2(); });
}
} else {
rowsHtml = items.map(function(e) {
var timeStr = '';
try {
var d = new Date(e.timestamp);
timeStr = d.toLocaleDateString([], { month:'short', day:'numeric' })
+ ' ' + d.toLocaleTimeString([], { hour:'2-digit', minute:'2-digit' });
} catch(ex) {}
return '<div class="activity-item">'
+ '<div class="activity-cat-dot ' + esc(e.category) + '">' + e.catIcon + '</div>'
+ '<div class="activity-text">'
+ '<div class="activity-label">' + esc(e.label) + (e.detail ? ' <span style="font-weight:400;color:var(--sub)">\u00B7 ' + esc(e.detail) + '</span>' : '') + '</div>'
+ '</div>'
+ '<div class="activity-ts">' + esc(timeStr) + '</div>'
+ '</div>';
}).join('');
}
el.innerHTML = '<div class="afv2-filter-row">' + chips + '</div>' + rowsHtml;
}
function _afv2SetFilter(cat) {
_activityFeedFilter = cat || 'all';
renderActivityFeedV2();
}
var _presenceHeartbeatTimer = null;  // setInterval handle
var _presenceCache          = [];    // latest online member rows
var _presenceRealtimeSub    = null;  // Supabase Realtime channel reference
function ensureDeviceId() {
if(AppState.deviceId) return AppState.deviceId;
try {
var stored = localStorage.getItem('kvt_device_id');
if(stored) { AppState.deviceId = stored; return stored; }
} catch(e2) {}
var id = (function() {
  try {
    var arr = new Uint8Array(8);
    crypto.getRandomValues(arr);
    return 'dev_' + Array.from(arr).map(function(b){ return b.toString(16).padStart(2,'0'); }).join('').slice(0,8)
         + '_' + Array.from(arr).map(function(b){ return b.toString(16).padStart(2,'0'); }).join('').slice(8,16);
  } catch(e) {
    return 'dev_' + Date.now().toString(36) + '_' + (Math.random()*0xFFFFFFFF|0).toString(16);
  }
})();
AppState.deviceId = id;
try { localStorage.setItem('kvt_device_id', id); } catch(e2) {}
dbg('[ensureDeviceId] generated: ' + id);
return id;
}
function sendPresenceHeartbeat() {
var client = sb || sbInit();
if(!client || !_v2Household || !_v2User) return;
var deviceId    = ensureDeviceId();
var displayName = (AppState.authUser && (AppState.authUser.display_name || AppState.authUser.email))
|| (_v2User && _v2User.email)
|| 'Member';
client.from('household_presence').upsert({
household_id: _v2Household.id,
user_id:      _v2User.id,
device_id:    deviceId,
display_name: displayName,
last_seen:    new Date().toISOString()
}, { onConflict: 'household_id,user_id,device_id' })
.then(function(r) {
if(r && r.error) dbg('[sendPresenceHeartbeat] error: ' + r.error.message);
})
.catch(function(e) { dbg('[sendPresenceHeartbeat] catch: ' + e.message); });
}
function startPresenceHeartbeat() {
if(_presenceHeartbeatTimer) {
clearInterval(_presenceHeartbeatTimer);
_presenceHeartbeatTimer = null;
}
if(!_v2Household || !_v2User) return;
sendPresenceHeartbeat();
_presenceHeartbeatTimer = setInterval(function() {
sendPresenceHeartbeat();
fetchOnlinePresence().then(function() { renderPresence(); });
}, 15000);
fetchOnlinePresence().then(function() { renderPresence(); });
_subscribePresenceRealtime();
dbg('[startPresenceHeartbeat] started for household ' + _v2Household.id);
}
function _subscribePresenceRealtime() {
var client = sb || sbInit();
if(!client || !_v2Household) return;
if(_presenceRealtimeSub) {
try { client.removeChannel(_presenceRealtimeSub); } catch(e) {}
_presenceRealtimeSub = null;
}
try {
_presenceRealtimeSub = client
.channel('presence:' + _v2Household.id)
.on('postgres_changes', {
event:  '*',
schema: 'public',
table:  'household_presence',
filter: 'household_id=eq.' + _v2Household.id
}, function() {
fetchOnlinePresence().then(function() { renderPresence(); });
})
.subscribe(function(status) {
dbg('[presenceRealtime] status=' + status);
});
} catch(e) {
dbg('[_subscribePresenceRealtime] error: ' + e.message);
}
}
async function fetchOnlinePresence() {
var client = sb || sbInit();
if(!client || !_v2Household) return [];
var cutoff = new Date(Date.now() - 30000).toISOString(); // 30s window
try {
var r = await client
.from('household_presence')
.select('user_id, display_name, last_seen, device_id')
.eq('household_id', _v2Household.id)
.gt('last_seen', cutoff)
.order('last_seen', { ascending: false });
if(r.error) throw r.error;
var seen   = {};
var online = [];
(r.data || []).forEach(function(row) {
if(!seen[row.user_id]) { seen[row.user_id] = true; online.push(row); }
});
_presenceCache = online;
return online;
} catch(e) {
dbg('[fetchOnlinePresence] error: ' + e.message);
return [];
}
}
function renderPresence() {
var el = document.getElementById('presence-indicator');
if(!el) return;
var hasHousehold = !!(_v2Household && _v2Household.id);
var hasSession   = !!(_v2User && !_v2GuestMode);
if(!hasHousehold || !hasSession) {
el.className   = '';
el.textContent = '';
return;
}
var online = _presenceCache;
var myDeviceId = AppState.deviceId;
var others = online.filter(function(p) {
return !(p.user_id === (_v2User && _v2User.id) && p.device_id === myDeviceId);
});
if(!others.length) {
el.className = 'visible';
el.innerHTML = '<span class="presence-none">Only you</span>';
return;
}
var MAX_PILLS = 3;
var pills = others.slice(0, MAX_PILLS).map(function(p) {
var name = (p.display_name || 'Member').split('@')[0];
name = name.charAt(0).toUpperCase() + name.slice(1, 10);
return '<span class="presence-pill">'
+ '<span class="presence-dot"></span>'
+ esc(name)
+ '</span>';
}).join('');
var extra = others.length > MAX_PILLS
? '<span class="presence-pill" style="background:rgba(255,255,255,.08)">+' + (others.length - MAX_PILLS) + '</span>'
: '';
el.className = 'visible';
el.innerHTML = '<span class="presence-label">Online:</span>' + pills + extra;
}
var _autopilotSettings = null;   // household_autopilot_settings row or null
var _autopilotActions  = [];     // array of household_autopilot_actions rows
var _autopilotRunning  = false;  // prevent concurrent runs
function requireAutopilot() {
// Local Autopilot engine runs client-side and does not require Pro.
// Pro gating removed: was causing hspOpen() to fire and cover the tab.
return true;
}
async function loadAutopilotSettings() {
var client = sb || sbInit();
if(!client || !_v2Household) return null;
try {
var r = await client
.from('household_autopilot_settings')
.select('enabled, mode, last_run_at, last_run_status, last_run_summary')
.eq('household_id', _v2Household.id)
.maybeSingle();
if(r.error) throw r.error;
_autopilotSettings = r.data || null;
if(_autopilotSettings) {
AppState.autopilotEnabled = !!_autopilotSettings.enabled;
AppState.autopilotMode    = _autopilotSettings.mode || 'suggest';
AppState.autopilotLastRun = _autopilotSettings.last_run_at || null;
}
return _autopilotSettings;
} catch(e) {
dbg('[loadAutopilotSettings] error: ' + e.message);
return null;
}
}
async function saveAutopilotSettings(enabled, mode) {
if(AppState.currentUserRole !== 'owner') { toast('Only the household owner can manage autopilot.'); return; }
var client = sb || sbInit();
if(!client || !_v2Household) return;
try {
var r = await client.from('household_autopilot_settings').upsert({
household_id: _v2Household.id,
enabled:      !!enabled,
mode:         mode || 'suggest',
updated_at:   new Date().toISOString()
}, { onConflict: 'household_id' });
if(r.error) throw r.error;
AppState.autopilotEnabled = !!enabled;
AppState.autopilotMode    = mode || 'suggest';
_autopilotSettings = _autopilotSettings || {};
_autopilotSettings.enabled = !!enabled;
_autopilotSettings.mode    = mode || 'suggest';
dbg('[saveAutopilotSettings] enabled=' + enabled + ' mode=' + mode);
renderAutopilotSettings();
} catch(e) {
toast('&#9888; Settings save failed: ' + e.message);
dbg('[saveAutopilotSettings] error: ' + e.message);
}
}

// ── D19 Autopilot Settings Panel (full settings, distinct from the simple
//    enable/mode toggle in renderAutopilotSettings above) ──────────────────
var _settingsPanelDraft = null; // working copy of settings while panel is open

var _settingsPanelTrigger = null;
async function openSettingsPanel() {
if(AppState.currentUserRole !== 'owner') { toast('Only the household owner can manage settings.'); return; }
_settingsPanelTrigger = _captureFocusTrigger();
enableScrollLock();
await loadSettingsForPanel();
_settingsPanelDraft = Object.assign({
risk_level: 2, auto_transfer:false, auto_categorize:true, auto_savings:false,
overdraft_prevention:true, min_balance:500, max_daily_spend:200,
notify_budget_alerts:true, notify_goal_milestones:true, notify_weekly_summary:true,
notify_autopilot_actions:false, income_smoothing_enabled:false, income_smoothing_window:3,
cash_buffer_target:1000, bill_priority_order:'due_date', bill_autopay:false
}, _autopilotSettings || {});
renderSettingsPanel();
document.getElementById('ap-settings-panel-overlay').classList.add('open');
setTimeout(function(){ var closeBtn=document.querySelector('.ap-sp-close'); if(closeBtn) closeBtn.focus(); }, 50);
}
function closeSettingsPanel() {
disableScrollLock();
document.getElementById('ap-settings-panel-overlay').classList.remove('open');
_settingsPanelDraft = null;
if (_settingsPanelTrigger && typeof _settingsPanelTrigger.focus === 'function' && document.contains(_settingsPanelTrigger)) _settingsPanelTrigger.focus();
_settingsPanelTrigger = null;
}
function apSpOverlayClick(evt) {
if(evt.target && evt.target.id === 'ap-settings-panel-overlay') closeSettingsPanel();
}
function d19RiskLabel(v) {
v = parseInt(v,10);
return v===1 ? 'Conservative' : v===3 ? 'Aggressive' : 'Balanced';
}
function d19UpdateRiskLabel(v) {
if(!_settingsPanelDraft) return;
_settingsPanelDraft.risk_level = parseInt(v,10) || 2;
var lbl = document.getElementById('d19-risk-label');
if(lbl) lbl.textContent = d19RiskLabel(v);
}
function d19UpdateSmoothLabel(v) {
if(!_settingsPanelDraft) return;
v = parseInt(v,10) || 3;
_settingsPanelDraft.income_smoothing_window = v;
var lbl = document.getElementById('d19-smooth-val');
if(lbl) lbl.textContent = v + (v===1 ? ' month' : ' months');
}
function d19ToggleBtn(btn) {
if(!btn || !_settingsPanelDraft) return;
var field = btn.getAttribute('data-field');
if(!field) return;
var on = !btn.classList.contains('on');
btn.classList.toggle('on', on);
btn.setAttribute('aria-pressed', String(on));
_settingsPanelDraft[field] = on;
}
function d19FieldInput(field, val, isNumber) {
if(!_settingsPanelDraft) return;
_settingsPanelDraft[field] = isNumber ? (parseFloat(val)||0) : val;
}
function renderSettingsPanel() {
var d = _settingsPanelDraft;
if(!d) return;

// Risk slider
var riskSlider = document.getElementById('d19-risk-slider');
if(riskSlider) riskSlider.value = d.risk_level;
var riskLbl = document.getElementById('d19-risk-label');
if(riskLbl) riskLbl.textContent = d19RiskLabel(d.risk_level);

// Toggle rows — wire data-field + initial state
var toggleMap = {
'd19-auto-transfer':'auto_transfer', 'd19-auto-cat':'auto_categorize', 'd19-auto-savings':'auto_savings',
'd19-overdraft':'overdraft_prevention', 'd19-notif-budget':'notify_budget_alerts',
'd19-notif-goals':'notify_goal_milestones', 'd19-notif-weekly':'notify_weekly_summary',
'd19-notif-actions':'notify_autopilot_actions', 'd19-income-smooth':'income_smoothing_enabled',
'd19-autopay':'bill_autopay'
};
Object.keys(toggleMap).forEach(function(id){
var el = document.getElementById(id);
if(!el) return;
var field = toggleMap[id];
el.setAttribute('data-field', field);
var on = !!d[field];
el.classList.toggle('on', on);
el.setAttribute('aria-pressed', String(on));
});

// Numeric / select inputs
var minBal = document.getElementById('d19-min-balance');
if(minBal){ minBal.value = d.min_balance; minBal.oninput = function(){ d19FieldInput('min_balance', this.value, true); }; }
var maxDaily = document.getElementById('d19-max-daily');
if(maxDaily){ maxDaily.value = d.max_daily_spend; maxDaily.oninput = function(){ d19FieldInput('max_daily_spend', this.value, true); }; }
var smoothSlider = document.getElementById('d19-smooth-slider');
if(smoothSlider) smoothSlider.value = d.income_smoothing_window;
var smoothVal = document.getElementById('d19-smooth-val');
if(smoothVal) smoothVal.textContent = d.income_smoothing_window + (d.income_smoothing_window===1 ? ' month' : ' months');
var cashBuf = document.getElementById('d19-cash-buffer');
if(cashBuf){ cashBuf.value = d.cash_buffer_target; cashBuf.oninput = function(){ d19FieldInput('cash_buffer_target', this.value, true); }; }
var billPri = document.getElementById('d19-bill-priority');
if(billPri){ billPri.value = d.bill_priority_order; billPri.onchange = function(){ d19FieldInput('bill_priority_order', this.value, false); }; }

// Monthly Budgets — read/write AppState.budgets directly (same source as the Budget tab)
var budgetRows = document.getElementById('d19-budget-rows');
if(budgetRows) {
var cats = (typeof CATS !== 'undefined' && CATS.expense) ? CATS.expense : Object.keys(AppState.budgets||{});
budgetRows.innerHTML = cats.length ? cats.map(function(c){
var v = AppState.budgets[c] || 0;
return '<div class="ap-sp-row">'
+ '<div class="ap-sp-row-label">' + esc(c) + '</div>'
+ '<input type="number" class="ap-sp-input ap-sp-input-sm" min="0" step="10" value="' + v + '"'
+ ' aria-label="' + esc(c) + ' budget" onchange="AppState.budgets[\'' + esc(c).replace(/'/g,"\\'") + '\']=parseFloat(this.value)||0;">'
+ '</div>';
}).join('') : '<div class="sm" style="padding:6px 0">No categories yet — add one from the Budget tab.</div>';
}

// Savings Goals — read-only summary (editing lives on the Goals tab)
var goalRows = document.getElementById('d19-goals-rows');
if(goalRows) {
var goals = AppState.goals || [];
goalRows.innerHTML = goals.length ? goals.map(function(g){
var pct = g.target>0 ? Math.min(Math.round(g.saved/g.target*100),100) : 0;
return '<div class="ap-sp-row">'
+ '<div class="ap-sp-row-label">' + esc(g.name) + '</div>'
+ '<div style="font-size:var(--fs-caption);color:var(--sub)">' + fmt(g.saved) + ' / ' + fmt(g.target) + ' (' + pct + '%)</div>'
+ '</div>';
}).join('') : '<div class="sm" style="padding:6px 0">No goals yet — add one from the Goals tab.</div>';
}

// Category Rules — merchant → category memory, editable inline
var catRuleRows = document.getElementById('d19-cat-rules-rows');
if(catRuleRows) {
var mem = AppState.merchantMem || {};
var names = Object.keys(mem).filter(function(k){ return mem[k] && mem[k].category; }).sort();
var catOptions = (typeof CATS !== 'undefined' ? (CATS.expense||[]).concat(CATS.income||[]) : []);
catRuleRows.innerHTML = names.length ? names.slice(0,50).map(function(name){
var current = mem[name].category || '';
var opts = catOptions.map(function(c){ return '<option' + (c===current?' selected':'') + '>' + esc(c) + '</option>'; }).join('');
return '<div class="ap-sp-row">'
+ '<div class="ap-sp-row-label" style="text-transform:capitalize">' + esc(name) + '</div>'
+ '<select class="ap-sp-select" aria-label="Category for ' + esc(name) + '"'
+ ' onchange="if(AppState.merchantMem[\'' + esc(name).replace(/'/g,"\\'") + '\'])AppState.merchantMem[\'' + esc(name).replace(/'/g,"\\'") + '\'].category=this.value;">'
+ opts + '</select>'
+ '</div>';
}).join('') : '<div class="sm" style="padding:6px 0">No learned merchant rules yet.</div>';
}

var status = document.getElementById('settings-status');
if(status) status.textContent = '';
}
async function saveSettings() {
if(AppState.currentUserRole !== 'owner') { toast('Only the household owner can manage settings.'); return; }
var d = _settingsPanelDraft;
if(!d) return;
var client = sb || sbInit();
if(!client || !_v2Household) { toast('Sign in to save settings.'); return; }
var status = document.getElementById('settings-status');
var saveBtn = document.getElementById('settings-save-btn');
if(saveBtn) saveBtn.disabled = true;
if(status) status.textContent = 'Saving…';
try {
var r = await client.from('household_autopilot_settings').upsert({
household_id: _v2Household.id,
risk_level: d.risk_level, auto_transfer: !!d.auto_transfer, auto_categorize: !!d.auto_categorize,
auto_savings: !!d.auto_savings, overdraft_prevention: !!d.overdraft_prevention,
min_balance: d.min_balance, max_daily_spend: d.max_daily_spend,
notify_budget_alerts: !!d.notify_budget_alerts, notify_goal_milestones: !!d.notify_goal_milestones,
notify_weekly_summary: !!d.notify_weekly_summary, notify_autopilot_actions: !!d.notify_autopilot_actions,
income_smoothing_enabled: !!d.income_smoothing_enabled, income_smoothing_window: d.income_smoothing_window,
cash_buffer_target: d.cash_buffer_target, bill_priority_order: d.bill_priority_order,
bill_autopay: !!d.bill_autopay, updated_at: new Date().toISOString()
}, { onConflict: 'household_id' });
if(r.error) throw r.error;
_autopilotSettings = Object.assign(_autopilotSettings || {}, d);
saveMeta();
lsSave();
if(typeof writeAudit === 'function') writeAudit('autopilot_settings_updated', null, { risk_level: d.risk_level });
dbg('[saveSettings] saved');
toast('Settings saved!');
closeSettingsPanel();
} catch(e) {
if(status) status.textContent = '';
toast('&#9888; Save failed: ' + e.message);
dbg('[saveSettings] error: ' + e.message);
} finally {
if(saveBtn) saveBtn.disabled = false;
}
}
function resetSettingsToDefaults() {
_settingsPanelDraft = {
risk_level:2, auto_transfer:false, auto_categorize:true, auto_savings:false,
overdraft_prevention:true, min_balance:500, max_daily_spend:200,
notify_budget_alerts:true, notify_goal_milestones:true, notify_weekly_summary:true,
notify_autopilot_actions:false, income_smoothing_enabled:false, income_smoothing_window:3,
cash_buffer_target:1000, bill_priority_order:'due_date', bill_autopay:false
};
renderSettingsPanel();
toast('Reset to defaults — tap Save to apply.');
}
async function loadSettingsForPanel() {
// Ensures _autopilotSettings has the new columns before openSettingsPanel() is called;
// loadAutopilotSettings() only selects the original 5 columns, so this extends that.
var client = sb || sbInit();
if(!client || !_v2Household) return;
try {
var r = await client.from('household_autopilot_settings').select('*').eq('household_id', _v2Household.id).maybeSingle();
if(r.error) throw r.error;
if(r.data) _autopilotSettings = r.data;
} catch(e) { dbg('[loadSettingsForPanel] error: ' + e.message); }
}
async function runAutopilotNow() {
if(!requireAutopilot()) return { ok: false, error: 'plan_gate' };
if(_autopilotRunning) { toast('Autopilot is already running.'); return { ok: false, error: 'in_flight' }; }
if(AppState.currentUserRole !== 'owner') { toast('Only the household owner can run autopilot.'); return { ok: false, error: 'not_owner' }; }
var client = sb || sbInit();
if(!client || !_v2Household || !_v2Session) return { ok: false, error: 'not_signed_in' };
if(typeof checkAutopilotGuardrails === 'function') {
var _guardResult = await checkAutopilotGuardrails();
if(!_guardResult.allowed) return { ok: false, error: _guardResult.reason };
}
// Local engine runs client-side — no cloud AI credits consumed, skip billing limit check.
_autopilotRunning = true;
renderAutopilotSettings();
writeNotification('autopilot_started', 'Autopilot running',
'AI Autopilot is analysing your household finances…', null);
try {
var _autopilotMemory = [];
if(typeof fetchRelevantMemory === 'function') {
try {
_autopilotMemory = await fetchRelevantMemory(['budget','pattern','risk'], null, 8);
_autopilotMemory = _memoryGuardrailFilter(_autopilotMemory);
_autopilotMemory = _memoryRetentionPrune(_autopilotMemory);
} catch(memErr) { dbg('[runAutopilotNow] memory fetch error: ' + memErr.message); }
}
var resp = await fetch(SUPABASE_URL + '/functions/v1/run-household-autopilot', {
method:  'POST',
headers: {
'Content-Type':  'application/json',
'Authorization': 'Bearer ' + ((_v2Session && _v2Session.access_token) || '')
},
body: JSON.stringify({
household_id:   _v2Household.id,
memory_context: _autopilotMemory.length ? _autopilotMemory : undefined,
vault_context:  (typeof _fetchVaultSummaries === 'function' && _fetchVaultSummaries().length)
? _fetchVaultSummaries() : undefined,
health_score:   (_healthScoreCache && _healthScoreCache.overall_score !== undefined)
? _healthScoreCache.overall_score : undefined,
active_goals:   (AppState.goals && AppState.goals.length)
? AppState.goals.map(function(g){ return { name: g.name, target: g.target, saved: g.saved, pct: g.target > 0 ? Math.round(g.saved/g.target*100) : 0 }; })
: undefined,
net_worth:      (typeof _nwGetSummary === 'function' && _nwGetSummary())
? _nwGetSummary() : undefined,
tax_year:       (typeof _taxYear !== 'undefined') ? _taxYear : undefined,
portfolio:      (typeof _invPortfolioSummary === 'function' && _invPortfolioSummary())
? _invPortfolioSummary() : undefined,
insurance_monthly_premium: (typeof _insPremiumMonthly === 'function' && _insPremiumMonthly() > 0)
? _insPremiumMonthly() : undefined,
retirement_age:   (_retProfileCache && _retProfileCache.retirement_age)
? _retProfileCache.retirement_age : undefined,
cash_runway_months: (_cashInsightCache && _cashInsightCache.insights && _cashInsightCache.insights.months_of_runway)
? _cashInsightCache.insights.months_of_runway : undefined,
risk_score:       (_riskInsightCache && _riskInsightCache.insights && _riskInsightCache.insights.risk_score !== undefined)
? _riskInsightCache.insights.risk_score : undefined,
life_events_count:(typeof _lifeEventsCache !== 'undefined' && _lifeEventsCache.length > 0)
? _lifeEventsCache.length : undefined,
scenario_type:    (typeof _scenarioType !== 'undefined' && _scenarioType !== 'custom')
? _scenarioType : undefined,
global_risk_score: (_mBrainStateCache && _mBrainStateCache.global_risk_score !== undefined)
? _mBrainStateCache.global_risk_score : undefined,
global_opp_score:  (_mBrainStateCache && _mBrainStateCache.global_opportunity_score !== undefined)
? _mBrainStateCache.global_opportunity_score : undefined
})
});
if(!resp.ok) {
// Cloud layer unavailable — local engine results are already rendered, continue gracefully.
dbg('[runAutopilotNow] edge function returned ' + resp.status + ' — local engine results preserved.');
} else {
var data = await resp.json();
if(data && data.error) dbg('[runAutopilotNow] edge function error: ' + data.error);
}
await loadAutopilotSettings();
await fetchAutopilotActions();
sendPushEventAdvanced('autopilot_suggestions_ready', 'Autopilot suggestions ready',
_autopilotActions.length + ' suggestion' + (_autopilotActions.length !== 1 ? 's' : '') + ' generated.',
null, null, { actions: [{ id:'view', label:'View suggestions' }] });
toast('&#129504; Autopilot complete — ' + _autopilotActions.length + ' suggestion' + (_autopilotActions.length !== 1 ? 's' : '') + '.');
renderAutopilotSettings();
dbg('[runAutopilotNow] done — ' + _autopilotActions.length + ' actions');
if(typeof runAnomalyDetection === 'function') runAnomalyDetection();
return { ok: true, error: null };
} catch(e) {
dbg('[runAutopilotNow] error: ' + e.message);
toast('&#9888; Autopilot failed: ' + e.message);
renderAutopilotSettings();
return { ok: false, error: e.message };
} finally {
_autopilotRunning = false;
}
}
async function fetchAutopilotActions(statusFilter) {
var client = sb || sbInit();
if(!client || !_v2Household) return [];
var status = statusFilter || 'pending';
try {
var r = await client
.from('household_autopilot_actions')
.select('id, run_id, type, title, body, payload, status, created_at')
.eq('household_id', _v2Household.id)
.eq('status', status)
.order('created_at', { ascending: false })
.limit(20);
if(r.error) throw r.error;
_autopilotActions = r.data || [];
dbg('[fetchAutopilotActions] loaded ' + _autopilotActions.length + ' (' + status + ')');
return _autopilotActions;
} catch(e) {
dbg('[fetchAutopilotActions] error: ' + e.message);
return [];
}
}
async function applyAutopilotAction(actionId) {
if(AppState.currentUserRole !== 'owner') { toast('Only the owner can apply autopilot suggestions.'); return; }
var client = sb || sbInit();
if(!client || !actionId) return;
var action = _autopilotActions.find(function(a){ return a.id === actionId; });
if(!action) return;
try {
var p = action.payload || {};
var auditAction = 'autopilot_run';
if(action.type === 'categorize' && p.txId && p.category) {
var txIdx = AppState.transactions.findIndex(function(t){ return t.id === p.txId; });
if(txIdx >= 0) {
AppState.transactions[txIdx].category = p.category;
AppState.transactions[txIdx]._userEditedCategory = true;
if(typeof touchRecord === 'function') touchRecord(AppState.transactions[txIdx]);
if(typeof lsSave === 'function') lsSave();
if(typeof invalidateAllCaches === 'function') invalidateAllCaches();
auditAction = 'autopilot_categorized';
}
} else if(action.type === 'budget_adjust' && p.category && p.amount !== undefined) {
if(!AppState.budgets) AppState.budgets = {};
AppState.budgets[p.category] = p.amount;
if(typeof lsSave === 'function') lsSave();
if(typeof invalidateAllCaches === 'function') invalidateAllCaches();
auditAction = 'autopilot_budget_adjusted';
}
var r = await client.from('household_autopilot_actions').update({
status:     'applied',
applied_by: _v2User && _v2User.id,
applied_at: new Date().toISOString()
}).eq('id', actionId);
if(r.error) throw r.error;
var idx = _autopilotActions.findIndex(function(a){ return a.id === actionId; });
if(idx >= 0) _autopilotActions[idx].status = 'applied';
writeAudit(auditAction, actionId, { type: action.type, title: action.title });
toast('&#10003; Applied: ' + esc(action.title));
if(typeof renderAll === 'function') renderAll();
renderAutopilotSettings();
dbg('[applyAutopilotAction] applied: ' + actionId);
} catch(e) {
toast('&#9888; Apply failed: ' + e.message);
dbg('[applyAutopilotAction] error: ' + e.message);
}
}
async function dismissAutopilotAction(actionId) {
var client = sb || sbInit();
if(!client || !actionId) return;
try {
var r = await client.from('household_autopilot_actions')
.update({ status: 'dismissed' })
.eq('id', actionId);
if(r.error) throw r.error;
var idx = _autopilotActions.findIndex(function(a){ return a.id === actionId; });
if(idx >= 0) _autopilotActions[idx].status = 'dismissed';
renderAutopilotSettings();
dbg('[dismissAutopilotAction] dismissed: ' + actionId);
} catch(e) {
dbg('[dismissAutopilotAction] error: ' + e.message);
}
}
function renderAutopilotSettings() {
var el = document.getElementById('hsp-autopilot');
if(!el) return;
var isOwner  = AppState.currentUserRole === 'owner';
var isPro    = AppState.billingPlan === 'pro' || AppState.billingPlan === 'team';
var enabled  = AppState.autopilotEnabled;
var mode     = AppState.autopilotMode || 'suggest';
if(!isPro) {
el.innerHTML = '<div class="autopilot-plan-gate">'
+ '&#128274; AI Autopilot is available on the Pro plan.'
+ (isOwner ? ' <button class="hsp-upgrade-btn" style="width:auto;padding:4px 12px;font-size:var(--fs-micro);margin:0" onclick="startCheckoutSession()">Upgrade</button>' : '')
+ '</div>';
return;
}
var toggleHtml = isOwner
? '<div class="autopilot-toggle-row">'
+ '<span class="autopilot-toggle-label">&#129504; Enable Autopilot</span>'
+ '<button class="autopilot-toggle' + (enabled ? ' on' : '') + '"'
+ ' onclick="saveAutopilotSettings(' + (!enabled) + ',\'' + esc(mode) + '\')"'
+ ' aria-pressed="' + enabled + '"'
+ ' aria-label="Toggle autopilot"></button>'
+ '</div>'
: '<div class="autopilot-toggle-row">'
+ '<span class="autopilot-toggle-label">&#129504; Autopilot</span>'
+ '<span style="font-size:var(--fs-caption);color:' + (enabled ? '#059669' : 'var(--sub)') + '">'
+ (enabled ? 'Enabled' : 'Disabled') + '</span>'
+ '</div>';
var controlsHtml = '';
if(isOwner && enabled) {
controlsHtml = '<div class="autopilot-mode-row">'
+ '<span class="autopilot-mode-label">Mode:</span>'
+ '<select class="autopilot-mode-select" onchange="saveAutopilotSettings(true,this.value)" aria-label="Autopilot mode">'
+ '<option value="suggest"' + (mode==='suggest'?' selected':'') + '>Suggest only</option>'
+ '<option value="auto"'    + (mode==='auto'   ?' selected':'') + '>Auto-apply</option>'
+ '</select>'
+ '</div>'
+ '<button class="autopilot-run-btn"' + (_autopilotRunning ? ' disabled' : '')
+ ' onclick="runAutopilotNow()"'
+ ' aria-label="Run autopilot now">'
+ (_autopilotRunning ? '&#9203; Running…' : '&#129504; Run Autopilot Now')
+ '</button>';
var lastRun = (_autopilotSettings && _autopilotSettings.last_run_at)
|| AppState.autopilotLastRun;
if(lastRun) {
var ts = '';
try { ts = new Date(lastRun).toLocaleString([], { month:'short', day:'numeric', hour:'2-digit', minute:'2-digit' }); } catch(ex) {}
controlsHtml += '<div class="autopilot-last-run">Last run: ' + esc(ts)
+ (_autopilotSettings && _autopilotSettings.last_run_status
? ' · ' + esc(_autopilotSettings.last_run_status) : '')
+ '</div>';
}
}
var pending = _autopilotActions.filter(function(a){ return a.status === 'pending'; });
var actionsHtml = '';
if(!pending.length && enabled) {
actionsHtml = '<div style="font-size:var(--fs-caption);color:var(--sub);margin-top:var(--sm);text-align:center">'
+ (isOwner ? 'Run autopilot to generate suggestions.' : 'No pending suggestions.') + '</div>';
} else {
var TYPE_ICONS = { categorize:'&#128196;', budget_adjust:'&#128200;',
goal_adjust:'&#127919;', suggestion:'&#128161;' };
actionsHtml = pending.map(function(a) {
var icon = TYPE_ICONS[a.type] || '&#128161;';
var isApplied = a.status === 'applied';
return '<div class="autopilot-action-item' + (isApplied ? ' autopilot-applied' : '') + '">'
+ '<div class="autopilot-action-hdr">'
+ '<span style="font-size:13px">' + icon + '</span>'
+ '<span class="autopilot-action-title">' + esc(a.title) + '</span>'
+ '<span class="ap-type-badge">' + esc(a.type) + '</span>'
+ '</div>'
+ (a.body ? '<div class="autopilot-action-body">' + esc(a.body) + '</div>' : '')
+ '<div class="autopilot-action-footer">'
+ (isOwner && !isApplied
? '<button class="ap-apply-btn" onclick="applyAutopilotAction(\'' + esc(a.id) + '\')" aria-label="Apply">Apply</button>'
+ '<button class="ap-dismiss-btn" onclick="dismissAutopilotAction(\'' + esc(a.id) + '\')" aria-label="Dismiss">Dismiss</button>'
: '<span style="font-size:var(--fs-micro);color:var(--sub)">'
+ (isApplied ? '&#10003; Applied' : esc(a.status))
+ '</span>')
+ '</div>'
+ '</div>';
}).join('');
}
el.innerHTML = toggleHtml + controlsHtml + actionsHtml;
}
