if(!client || !_v2Household || !_v2User) return;
var deviceId = (typeof ensureDeviceId === 'function') ? ensureDeviceId() : (AppState.deviceId || 'unknown');
client.from('household_sessions').update({ last_seen: new Date().toISOString() })
.eq('household_id', _v2Household.id)
.eq('user_id', _v2User.id)
.eq('device_id', deviceId)
.then(function(r){ if(r && r.error) dbg('[sessionHeartbeat] ' + r.error.message); })
.catch(function(e){ dbg('[sessionHeartbeat] catch: ' + e.message); });
