writeAudit('all_sessions_revoked', null, { except_device: myDevice });
writeNotification('all_sessions_revoked', 'All sessions revoked',
'All other device sessions have been signed out.', null);
sendPushEventAdvanced('all_sessions_revoked', 'Security alert', 'All other device sessions have been signed out of your household.', null, null, { highPriority: true });
