try { lastRun = new Date(_mBrainStateCache.last_run).toLocaleDateString([], { month:'short', day:'numeric', hour:'2-digit', minute:'2-digit' }); } catch(ex){}
stateBarHtml = '<div class="mb-state-bar">'
+ '<span class="mb-state-label">Last run</span><span class="mb-state-value">' + esc(lastRun) + '</span>'
