var runAllBtnLabel = _mbRunAllInProgress
? ('&#9203; ' + esc(_mbRunAllProgress.current || 'Running…') + ' (' + _mbRunAllProgress.done + '/' + _mbRunAllProgress.total + ')')
: '&#9889; Run All Engines + Synthesize';
var runAllBtn = '<button class="mb-run-all-btn"' + (_mbRunAllInProgress || _mBrainRunning ? ' disabled' : '')
+ ' onclick="runAllThenSynthesize()" aria-label="Run all engines then synthesize">'
