async function runScenarioSimulator(params) {
if(_scenarioRunning) { toast('A scenario is already running.'); return; }
var client = sb || sbInit();
if(!client || !_v2Household || !_v2Session) { toast('Sign in to run scenarios.'); return; }
if(AppState.currentUserRole !== 'owner') { toast('Only the owner can run scenarios.'); return; }
var scenarioType = _scenarioType;
var paramObj = params || {};
if(!params) {
var meta = SC_TYPE_META[scenarioType] || SC_TYPE_META.custom;
meta.params.forEach(function(p) {
var el = document.getElementById('sc-param-' + p.key);
if(el && el.value.trim()) paramObj[p.key] = el.value.trim();
});
}
if(typeof enforceLimitsOrThrow === 'function') {
try { await enforceLimitsOrThrow('ai_runs_this_month'); }
catch(limErr) { toast('&#128683; ' + limErr.message); return; }
}
_scenarioRunning = true;
renderScenarioInsights();
try {
var runIns = await client.from('household_scenario_runs').insert({
household_id:  _v2Household.id,
scenario_type: scenarioType,
parameters:    paramObj
}).select('id').single();
if(runIns.error) throw runIns.error;
var runId = runIns.data && runIns.data.id;
var insIns = await client.from('household_scenario_insights').insert({
household_id:    _v2Household.id,
scenario_run_id: runId,
status:          'pending'
}).select('id').single();
if(insIns.error) throw insIns.error;
var insightId = insIns.data && insIns.data.id;
_scenarioInsightCache = { id: insightId, status: 'pending', created_at: new Date().toISOString() };
renderScenarioInsights();
var resp = await fetch(SUPABASE_URL + '/functions/v1/run-household-scenario-simulator', {
method:  'POST',
headers: {
'Content-Type':  'application/json',
'Authorization': 'Bearer ' + (_v2Session.access_token || '')
},
body: JSON.stringify({
household_id:      _v2Household.id,
run_id:            runId,
insight_id:        insightId,
scenario_type:     scenarioType,
parameters:        paramObj,
net_worth_summary: (typeof _nwGetSummary === 'function' && _nwGetSummary()) || undefined,
portfolio:         (typeof _invPortfolioSummary === 'function' && _invPortfolioSummary()) || undefined,
forecast_summary:  (_forecastCache && _forecastCache.result_json)
? JSON.stringify(_forecastCache.result_json) : undefined,
retirement_age:    (_retProfileCache && _retProfileCache.retirement_age)
? _retProfileCache.retirement_age : undefined,
cash_runway_months:(_cashInsightCache && _cashInsightCache.insights && _cashInsightCache.insights.months_of_runway)
? _cashInsightCache.insights.months_of_runway : undefined,
health_score:      (_healthScoreCache && _healthScoreCache.overall_score !== undefined)
? _healthScoreCache.overall_score : undefined,
risk_score:        (_riskInsightCache && _riskInsightCache.insights && _riskInsightCache.insights.risk_score !== undefined)
? _riskInsightCache.insights.risk_score : undefined
})
});
if(!resp.ok) throw new Error('EF returned ' + resp.status);
var data = await resp.json();
if(data && data.error) throw new Error(data.error);
await fetchScenarioInsights();
await fetchScenarioRuns();
var typeMeta = SC_TYPE_META[scenarioType] || SC_TYPE_META.custom;
toast((SC_TYPE_META[scenarioType] ? SC_TYPE_META[scenarioType].icon : '') + ' Scenario ready!');
renderScenarioInsights();
dbg('[runScenarioSimulator] done — insight_id=' + insightId);
} catch(e) {
toast('&#9888; Scenario failed: ' + e.message);
if(_scenarioInsightCache) _scenarioInsightCache.status = 'error';
dbg('[runScenarioSimulator] error: ' + e.message);
} finally {
_scenarioRunning = false;
renderScenarioInsights();
}
}
