var _lifeEventsCache    = [];   // household_life_events rows
var _leInsightCache     = null; // latest household_life_event_insights row
var _leRunning          = false;
var LE_TYPE_META = {
marriage:      { label: 'Marriage',       icon: '&#128141;' },
child:         { label: 'New Child',       icon: '&#128118;' },
college:       { label: 'College',         icon: '&#127891;' },
home_purchase: { label: 'Home Purchase',   icon: '&#127968;' },
relocation:    { label: 'Relocation',      icon: '&#128666;' },
job_change:    { label: 'Job Change',      icon: '&#128188;' },
aging_parents: { label: 'Aging Parents',   icon: '&#128106;' },
retirement:    { label: 'Retirement',      icon: '&#128197;' },
major_expense: { label: 'Major Expense',   icon: '&#128176;' },
other:         { label: 'Other',           icon: '&#128196;' }
};
async function fetchLifeEvents() {
var client = sb || sbInit();
if(!client || !_v2Household) return [];
try {
var r = await client
.from('household_life_events')
.select('id, event_type, event_date, metadata, created_at')
.eq('household_id', _v2Household.id)
.order('event_date', { ascending: true })
.order('created_at', { ascending: false });
if(r.error) throw r.error;
_lifeEventsCache = r.data || [];
dbg('[fetchLifeEvents] loaded ' + _lifeEventsCache.length);
return _lifeEventsCache;
} catch(e) {
dbg('[fetchLifeEvents] error: ' + e.message);
return [];
}
}
async function addLifeEvent(eventType, eventDate, notes, estimatedCost) {
if(AppState.currentUserRole !== 'owner') { toast('Only the owner can add life events.'); return; }
var client = sb || sbInit();
if(!client || !_v2Household || !eventType) { toast('Select an event type.'); return; }
try {
var r = await client.from('household_life_events').insert({
household_id: _v2Household.id,
event_type:   eventType,
event_date:   eventDate || null,
metadata:     {
notes:          (notes || '').trim(),
estimated_cost: parseFloat(estimatedCost) || 0,
status:         'upcoming'
}
}).select('id, event_type, event_date, metadata, created_at').single();
if(r.error) throw r.error;
_lifeEventsCache.push(r.data);
_lifeEventsCache = _lifeEventsCache.slice().sort(function(a,b){
return (a.event_date || '9999') > (b.event_date || '9999') ? 1 : -1;
});
toast((LE_TYPE_META[eventType] ? LE_TYPE_META[eventType].icon + ' ' : '') + 'Life event added.');
renderLifeEventInsights();
dbg('[addLifeEvent] added: ' + eventType);
} catch(e) {
toast('&#9888; ' + e.message);
}
}
async function deleteLifeEvent(id) {
if(AppState.currentUserRole !== 'owner') return;
var client = sb || sbInit();
if(!client) return;
try {
await client.from('household_life_events').delete().eq('id', id);
_lifeEventsCache = _lifeEventsCache.filter(function(e){ return e.id !== id; });
renderLifeEventInsights();
} catch(e) { toast('&#9888; ' + e.message); }
}
async function fetchLifeEventInsights() {
var client = sb || sbInit();
if(!client || !_v2Household) return null;
try {
var r = await client
.from('household_life_event_insights')
.select('id, status, insights, error_msg, created_at')
.eq('household_id', _v2Household.id)
.order('created_at', { ascending: false })
.limit(1)
.maybeSingle();
if(r.error) throw r.error;
_leInsightCache = r.data || null;
dbg('[fetchLifeEventInsights] ' + (_leInsightCache ? 'loaded' : 'none'));
return _leInsightCache;
} catch(e) {
dbg('[fetchLifeEventInsights] error: ' + e.message);
return null;
}
}
async function runLifeEvents() {
if(_leRunning) { toast('Life events analysis already running.'); return; }
if(!guardToolRerun(_leInsightCache, { toolLabel: 'Life Events Analysis' })) return;
var client = sb || sbInit();
if(!client || !_v2Household || !_v2Session) { toast('Sign in to run life events analysis.'); return; }
if(AppState.currentUserRole !== 'owner') { toast('Only the owner can run life events analysis.'); return; }
if(typeof enforceLimitsOrThrow === 'function') {
try { await enforceLimitsOrThrow('ai_runs_this_month'); }
catch(limErr) { toast('&#128683; ' + limErr.message); return; }
}
_leRunning = true;
renderLifeEventInsights();
try {
var ins = await client.from('household_life_event_insights').insert({
household_id: _v2Household.id,
status:       'pending'
}).select('id').single();
if(ins.error) throw ins.error;
var insightId = ins.data && ins.data.id;
_leInsightCache = { id: insightId, status: 'pending', created_at: new Date().toISOString() };
renderLifeEventInsights();
var resp = await fetch(SUPABASE_URL + '/functions/v1/run-household-life-events', {
method:  'POST',
headers: {
'Content-Type':  'application/json',
'Authorization': 'Bearer ' + (_v2Session.access_token || '')
},
body: JSON.stringify({
household_id:      _v2Household.id,
insight_id:        insightId,
net_worth_summary: (typeof _nwGetSummary === 'function' && _nwGetSummary()) || undefined,
forecast_summary:  (_forecastCache && _forecastCache.result_json)
? JSON.stringify(_forecastCache.result_json) : undefined,
retirement_age:    (_retProfileCache && _retProfileCache.retirement_age)
? _retProfileCache.retirement_age : undefined,
insurance_monthly_premium: (typeof _insPremiumMonthly === 'function' && _insPremiumMonthly() > 0)
? _insPremiumMonthly() : undefined,
cash_runway_months:(_cashInsightCache && _cashInsightCache.insights && _cashInsightCache.insights.months_of_runway)
? _cashInsightCache.insights.months_of_runway : undefined,
health_score:      (_healthScoreCache && _healthScoreCache.overall_score !== undefined)
? _healthScoreCache.overall_score : undefined
})
});
if(!resp.ok) throw new Error('EF returned ' + resp.status);
var data = await resp.json();
if(data && data.error) throw new Error(data.error);
await fetchLifeEventInsights();
var ins2     = _leInsightCache && _leInsightCache.insights;
var evCount  = _lifeEventsCache.length;
var upcomCount = (ins2 && Array.isArray(ins2.upcoming_events)) ? ins2.upcoming_events.length : 0;
toast('&#128141; Life events analysis ready! ' + upcomCount + ' event' + (upcomCount !== 1 ? 's' : '') + ' projected.');
renderLifeEventInsights();
dbg('[runLifeEvents] done — insight_id=' + insightId);
} catch(e) {
toast('&#9888; Life events analysis failed: ' + e.message);
if(_leInsightCache) _leInsightCache.status = 'error';
dbg('[runLifeEvents] error: ' + e.message);
} finally {
_leRunning = false;
renderLifeEventInsights();
}
}
