var _estateDocsCache   = [];   // household_estate_documents rows
var _estateInsightCache= null; // latest household_estate_insights row
var _estateRunning     = false;
var ESTATE_DOC_PATTERNS = [
{ pattern: /\bwill\b/i,                docType: 'will',        label: 'Will' },
{ pattern: /last.*testament|testament/i, docType: 'will',      label: 'Last Will & Testament' },
{ pattern: /\btrust\b/i,               docType: 'trust',       label: 'Trust Document' },
{ pattern: /living.*trust|revocable/i, docType: 'trust',       label: 'Living Trust' },
{ pattern: /beneficiar/i,             docType: 'beneficiary',  label: 'Beneficiary Designation' },
{ pattern: /power.*attorney|poa\b/i,  docType: 'POA',          label: 'Power of Attorney' },
{ pattern: /healthcare.*proxy|medical.*directive|advance.*directive/i, docType: 'healthcare', label: 'Healthcare Directive' },
{ pattern: /letter.*instruction|letter.*wishes/i, docType: 'letter', label: 'Letter of Instruction' }
];
function detectEstateDocFromVaultFile(fileName, fileId) {
var client = sb || sbInit();
if(!client || !_v2Household || !_v2User || !fileName) return;
if(AppState.currentUserRole !== 'owner') return;
var match = null;
for(var i = 0; i < ESTATE_DOC_PATTERNS.length; i++) {
if(ESTATE_DOC_PATTERNS[i].pattern.test(fileName)) { match = ESTATE_DOC_PATTERNS[i]; break; }
}
if(!match) return;
var yearMatch = fileName.match(/20\d{2}/);
var docYear   = yearMatch ? parseInt(yearMatch[0], 10) : new Date().getFullYear();
client.from('household_estate_documents').insert({
household_id:  _v2Household.id,
user_id:       _v2User.id,
doc_type:      match.docType,
year:          docYear,
storage_path:  fileId || null,
extracted:     {}
})
.then(function(r){
if(r && r.error) { dbg('[detectEstateDocFromVaultFile] error: ' + r.error.message); return; }
writeAudit('estate_doc_detected', fileId, { doc_type: match.docType, year: docYear, file_name: fileName });
writeNotification('estate_doc_detected', 'Estate document detected',
match.label + ' (' + docYear + ') detected in your vault.', null);
fetchEstateDocs().then(function(){ renderEstateInsights(); });
dbg('[detectEstateDocFromVaultFile] detected: ' + match.label);
})
.catch(function(e){ dbg('[detectEstateDocFromVaultFile] catch: ' + e.message); });
}
async function fetchEstateDocs() {
var client = sb || sbInit();
if(!client || !_v2Household) return [];
try {
var r = await client
.from('household_estate_documents')
.select('id, doc_type, year, storage_path, extracted, created_at')
.eq('household_id', _v2Household.id)
.order('created_at', { ascending: false });
if(r.error) throw r.error;
_estateDocsCache = r.data || [];
dbg('[fetchEstateDocs] loaded ' + _estateDocsCache.length);
return _estateDocsCache;
} catch(e) {
dbg('[fetchEstateDocs] error: ' + e.message);
return [];
}
}
async function fetchEstateInsights() {
var client = sb || sbInit();
if(!client || !_v2Household) return null;
try {
var r = await client
.from('household_estate_insights')
.select('id, status, insights, error_msg, created_at')
.eq('household_id', _v2Household.id)
.order('created_at', { ascending: false })
.limit(1)
.maybeSingle();
if(r.error) throw r.error;
_estateInsightCache = r.data || null;
dbg('[fetchEstateInsights] ' + (_estateInsightCache ? 'loaded' : 'none'));
return _estateInsightCache;
} catch(e) {
dbg('[fetchEstateInsights] error: ' + e.message);
return null;
}
}
