async function runCashManagement() {
if(_cashRunning) { toast('Cash analysis already running.'); return; }
if(!guardToolRerun(_cashInsightCache, { toolLabel: 'Cash Analysis', freshAfterMs: 1800000 })) return;
var client = sb || sbInit();
if(!client || !_v2Household || !_v2Session) { toast('Sign in to run cash analysis.'); return; }
if(AppState.currentUserRole !== 'owner') { toast('Only the owner can run cash analysis.'); return; }
if(typeof enforceLimitsOrThrow === 'function') {
try { await enforceLimitsOrThrow('ai_runs_this_month'); }
catch(limErr) { toast('&#128683; ' + limErr.message); return; }
}
_cashRunning = true;
renderCashInsights();
try {
var ins = await client.from('household_cash_insights').insert({
household_id: _v2Household.id,
status:       'pending'
}).select('id').single();
if(ins.error) throw ins.error;
var insightId = ins.data && ins.data.id;
_cashInsightCache = { id: insightId, status: 'pending', created_at: new Date().toISOString() };
renderCashInsights();
var today    = new Date();
var in14days = new Date(today.getTime() + 14 * 86400000).toISOString().split('T')[0];
var upcomingRenewals = (typeof _subscriptionsCache !== 'undefined' ? _subscriptionsCache : [])
.filter(function(s){ return s.active && s.next_renewal && s.next_renewal <= in14days; })
.reduce(function(sum, s){ return sum + (parseFloat(s.amount) || 0); }, 0);
var resp = await fetch(SUPABASE_URL + '/functions/v1/run-household-cash-management', {
method:  'POST',
headers: {
'Content-Type':  'application/json',
'Authorization': 'Bearer ' + (_v2Session.access_token || '')
},
body: JSON.stringify({
household_id:           _v2Household.id,
insight_id:             insightId,
forecast_summary:       (_forecastCache && _forecastCache.result_json)
? JSON.stringify(_forecastCache.result_json) : undefined,
health_score:           (_healthScoreCache && _healthScoreCache.overall_score !== undefined)
? _healthScoreCache.overall_score : undefined,
subscription_monthly_total: (typeof _subMonthlyTotal === 'function' && _subMonthlyTotal() > 0)
? _subMonthlyTotal() : undefined,
upcoming_renewals_total:upcomingRenewals || undefined
})
});
if(!resp.ok) throw new Error('EF returned ' + resp.status);
var data = await resp.json();
if(data && data.error) throw new Error(data.error);
await fetchCashInsights();
var ins2  = _cashInsightCache && _cashInsightCache.insights;
var lScore = (ins2 && ins2.liquidity_score) || 0;
toast('&#128181; Cash analysis ready! Liquidity: ' + lScore + '/100.');
renderCashInsights();
dbg('[runCashManagement] done — insight_id=' + insightId);
} catch(e) {
toast('&#9888; Cash analysis failed: ' + e.message);
if(_cashInsightCache) _cashInsightCache.status = 'error';
dbg('[runCashManagement] error: ' + e.message);
} finally {
_cashRunning = false;
renderCashInsights();
}
}
