var toggleBtn = '<button style="background:none;border:1.5px solid var(--border);border-radius:8px;padding:4px 12px;font-size:var(--fs-micro);font-weight:700;cursor:pointer;color:var(--sub);margin-bottom:var(--xs);-webkit-tap-highlight-color:transparent" onclick="_negToggleForm()">' + toggleLabel + '</button>';
