async function sendAdvisorMessage(userText) {
userText = (userText || '').trim();
if(!userText) return;
var client = sb || sbInit();
if(!client || !_v2Household || !_v2Session) { toast('Sign in to use the AI Advisor.'); return; }
if(_advisorSending) return;
if(_guardrailsCache && _guardrailsCache.household_locked) {
toast('&#128683; AI features are locked for this household.');
return;
}
if(typeof enforceLimitsOrThrow === 'function') {
try { await enforceLimitsOrThrow('ai_runs_this_month'); }
catch(limErr) { toast('&#128683; ' + limErr.message); return; }
}
_advisorSending = true;
var userMsg = { role: 'user', content: userText, ts: new Date().toISOString() };
_advisorMessages.push(userMsg);
renderAdvisorThread();
try {
var resp = await fetch(SUPABASE_URL + '/functions/v1/household-ai-advisor', {
method:  'POST',
headers: {
'Content-Type':  'application/json',
'Authorization': 'Bearer ' + (_v2Session.access_token || '')
},
body: JSON.stringify({
household_id:  _v2Household.id,
user_message:  userText,
session_id:    _advisorSessionId || undefined
})
});
if(!resp.ok) throw new Error('EF returned ' + resp.status);
var data = await resp.json();
if(data && data.error) throw new Error(data.error);
if(data.session_id) _advisorSessionId = data.session_id;
var assistantMsg = {
role:       'assistant',
content:    data.reply || '(no reply)',
ts:         new Date().toISOString(),
actions:    data.actions    || [],
insights:   data.insights   || [],
risk_flags: data.risk_flags || []
};
_advisorMessages.push(assistantMsg);
renderAdvisorThread();
dbg('[sendAdvisorMessage] reply received, session=' + _advisorSessionId);
} catch(e) {
_advisorMessages.pop();
toast('&#9888; Advisor error: ' + e.message);
dbg('[sendAdvisorMessage] error: ' + e.message);
renderAdvisorThread();
} finally {
_advisorSending = false;
}
}
