+ ' ondragover="event.preventDefault();this.classList.add(\'drag-over\')"'
+ ' ondragleave="this.classList.remove(\'drag-over\')"'
+ ' ondrop="_vaultOnDrop(event)">'
+ '<span class="vault-upload-label">&#128190; Tap to upload or drag a file here</span>'
+ '<span style="font-size:10px;color:var(--sub);display:block;margin-top:3px">PDF, CSV, image · max 10 MB</span>'
+ '</div>'
+ '<input type="file" id="vault-file-input" class="vault-upload-input"'
