var canDel  = isOwner;
return '<div class="vault-file-item">'
+ '<div class="vault-file-icon">' + icon + '</div>'
+ '<div style="min-width:0">'
+ '<div class="vault-file-name">' + esc(f.file_name) + '</div>'
+ '<div class="vault-file-meta">' + (size ? esc(size) + ' · ' : '') + esc(ts) + '</div>'
+ (f.ai_summary ? '<div class="vault-file-summary">' + esc(f.ai_summary.slice(0, 80)) + '…</div>' : '')
+ '</div>'
+ '<div class="vault-file-actions">'
