writeNotification('anomaly_resolved', 'Anomaly ' + newStatus,
'An anomaly has been marked as ' + newStatus + '.', null);
toast('&#10003; Anomaly ' + newStatus + '.');
renderAnomalies();
dbg('[resolveAnomaly] ' + newStatus + ': ' + anomalyId);
