async function runDataRetentionPurge() {
if(AppState.currentUserRole !== 'owner') {
toast('Only the household owner can trigger a data purge.');
return;
}
if(_retentionPurging) { toast('A purge is already running.'); return; }
if(!(_retentionCache && _retentionCache.purge_enabled)) {
toast('&#9888; Enable purge first, then save settings before running.');
return;
}
var client = sb || sbInit();
if(!client || !_v2Household || !_v2Session) return;
showCfm(
'This will permanently delete data older than your retention horizons. This cannot be undone.',
'Run Purge',
async function() {
_retentionPurging = true;
renderDataRetention();
writeNotification('purge_started', 'Data purge started',
'Household data purge is running. This may take a moment.', null);
try {
var resp = await fetch(SUPABASE_URL + '/functions/v1/run-data-retention-purge', {
method:  'POST',
headers: {
'Content-Type':  'application/json',
'Authorization': 'Bearer ' + ((_v2Session && _v2Session.access_token) || '')
},
body: JSON.stringify({ household_id: _v2Household.id })
});
if(!resp.ok) throw new Error('Edge Function returned ' + resp.status);
var data = await resp.json();
if(data && data.error) throw new Error(data.error);
var rows = (data && data.rows_deleted) || 0;
await loadDataRetention();
writeAudit('data_purged', null, { rows_deleted: rows });
writeNotification('data_purged', 'Data purge complete',
rows + ' row' + (rows !== 1 ? 's' : '') + ' deleted.', null);
toast('&#128465; Purge complete — ' + rows + ' row' + (rows !== 1 ? 's' : '') + ' removed.');
renderDataRetention();
dbg('[runDataRetentionPurge] done — ' + rows + ' rows deleted');
} catch(e) {
toast('&#9888; Purge failed: ' + e.message);
dbg('[runDataRetentionPurge] error: ' + e.message);
} finally {
_retentionPurging = false;
renderDataRetention();
}
}
);
}
