function classifyAuthError(e) {
if(!e) return { type:'unknown', message:'An unknown error occurred.' };
var msg = (e.message||'').toLowerCase();
if(!navigator.onLine || msg.indexOf('fetch') >= 0 || msg.indexOf('network') >= 0)
return { type:'network', message:'No internet connection. Please try again.' };
if(msg.indexOf('invalid') >= 0 || msg.indexOf('credentials') >= 0 || msg.indexOf('password') >= 0)
return { type:'invalid_credentials', message:'Incorrect email or password.' };
if(msg.indexOf('already registered') >= 0 || msg.indexOf('already exists') >= 0)
return { type:'email_in_use', message:'An account with this email already exists.' };
if(msg.indexOf('weak') >= 0 || msg.indexOf('short') >= 0)
return { type:'weak_password', message:'Password is too weak. Use 8+ characters.' };
if(msg.indexOf('rate') >= 0 || msg.indexOf('too many') >= 0)
return { type:'rate_limit', message:'Too many attempts. Please wait a moment.' };
if(msg.indexOf('expired') >= 0 || msg.indexOf('session') >= 0)
return { type:'session_expired', message:'Your session expired. Please log in again.' };
return { type:'unknown', message: e.message || 'Something went wrong. Please try again.' };
}
