var failures=[];
if(inp.fHabit<0.50)    failures.push('Habit success probability '+Math.round(inp.fHabit*100)+'% — below 50% failure threshold.');
if(inp.impulse>0.60)   failures.push('High impulse is breaking trigger→action links in habit loops.');
