var scenarios=[];
scenarios.push({name:'Drift surge + momentum crash',risk:Math.round((simResults.driftSurge.risk+simResults.momentumCrash.risk)/2*amplification)});
scenarios.push({name:'Goal overload + cashflow shock',risk:Math.round((simResults.goalOverload.risk+simResults.cashflowShock.risk)/2*amplification)});
scenarios.push({name:'Behavioral collapse + savings drain',risk:Math.round((simResults.behavioralCollapse.risk+simResults.savingsCollapse.risk)/2*amplification)});
return { risk:stackedRisk100, amplification:Math.round(amplification*100)/100,
stackedScenarios:scenarios,
worstCase:'System-wide failure if drift>70 AND momentum=0 AND cashflow shock simultaneously.' };
