var MST_KEY = 'kevt_v4_multi_scale_trend';
var multiScaleTrendEngine = {
_c: function(v){ return Math.max(0, Math.min(100, Math.round(v||0))); },
_mean: function(arr){
if(!arr||!arr.length) return 0;
return arr.reduce(function(s,v){return s+v;},0)/arr.length;
},
_std: function(arr){
if(!arr||arr.length<2) return 0;
var m = multiScaleTrendEngine._mean(arr);
var variance = arr.reduce(function(s,v){return s+Math.pow(v-m,2);},0)/(arr.length-1);
return Math.sqrt(variance);
},
_slope: function(arr){
if(!arr||arr.length<2) return 0;
var n = arr.length;
var sumX = (n*(n-1))/2;
var sumXY = arr.reduce(function(s,v,i){return s+i*v;},0);
var sumX2 = (n*(n-1)*(2*n-1))/6;
var denominator = n*sumX2 - sumX*sumX;
if(denominator===0) return 0;
return (n*sumXY - sumX*arr.reduce(function(s,v){return s+v;},0))/denominator;
},
_buildWindows: function(){
var txs = (AppState.transactions||[]).filter(function(t){return t&&!t._deleted;});
var now = Date.now();
var windows = {
w7: [], w14: [], w30: [], w60: [], w90: [], w180: [], w365: []
};
var windowMs = {
w7: 7*86400000, w14: 14*86400000, w30: 30*86400000,
w60: 60*86400000, w90: 90*86400000, w180: 180*86400000, w365: 365*86400000
};
Object.keys(windowMs).forEach(function(wk){
var ms = windowMs[wk];
windows[wk] = txs.filter(function(t){
var ts = new Date(t.date+'T12:00:00').getTime();
return ts >= now - ms && ts < now;
}).map(function(t){
return parseFloat(t.amount)||0;
});
});
return windows;
},
computeWindowSlopes: function(windows){
var slopes = {};
Object.keys(windows).forEach(function(wk){
var arr = windows[wk];
slopes[wk] = multiScaleTrendEngine._slope(arr);
});
return slopes;
},
computeWindowVolatility: function(windows){
var volatility = {};
Object.keys(windows).forEach(function(wk){
var arr = windows[wk];
var std = multiScaleTrendEngine._std(arr);
var mean = multiScaleTrendEngine._mean(arr);
volatility[wk] = mean>0 ? (std/mean)*100 : 0;
});
return volatility;
},
computeDirections: function(slopes){
var directions = {};
Object.keys(slopes).forEach(function(wk){
var s = slopes[wk];
directions[wk] = s > 0.01 ? 'up' : s < -0.01 ? 'down' : 'flat';
});
return directions;
},
computeStrengths: function(slopes, windows){
var strengths = {};
Object.keys(slopes).forEach(function(wk){
var s = Math.abs(slopes[wk]);
var arr = windows[wk];
var mean = multiScaleTrendEngine._mean(arr);
strengths[wk] = mean>0 ? Math.min(100, (s/mean)*100) : 0;
});
return strengths;
},
computeStabilities: function(volatility){
var stabilities = {};
Object.keys(volatility).forEach(function(wk){
stabilities[wk] = multiScaleTrendEngine._c(100 - volatility[wk]);
});
return stabilities;
},
computeHarmonization: function(directions){
var upCount=0, downCount=0, flatCount=0;
Object.keys(directions).forEach(function(wk){
if(directions[wk]==='up') upCount++;
else if(directions[wk]==='down') downCount++;
else flatCount++;
});
var maxAlign = Math.max(upCount, downCount, flatCount);
return multiScaleTrendEngine._c((maxAlign/7)*100);
},
synthesizeTrendVectors: function(slopes, windows){
var n = Object.keys(windows).length;
var allSlopes = Object.keys(slopes).map(function(k){return slopes[k];});
var allSpends = [];
Object.keys(windows).forEach(function(wk){
windows[wk].forEach(function(v){allSpends.push(v);});
});
return {
shortTerm:  multiScaleTrendEngine._mean([slopes.w7, slopes.w14]),
mediumTerm: multiScaleTrendEngine._mean([slopes.w30, slopes.w60, slopes.w90]),
longTerm:   multiScaleTrendEngine._mean([slopes.w180, slopes.w365]),
overall:    multiScaleTrendEngine._mean(allSlopes)
};
},
computeMomentum: function(vectors){
var weighted =
vectors.shortTerm * 0.4 +
vectors.mediumTerm * 0.35 +
vectors.longTerm * 0.25;
return multiScaleTrendEngine._c(50 + weighted * 10);
},
computeConfidence: function(harmonization, volatility, directions){
var dirConsistency = 0;
var expectedDir = directions.w365;
Object.keys(directions).forEach(function(wk){
if(directions[wk]===expectedDir) dirConsistency++;
});
var avgVolatility = multiScaleTrendEngine._mean(Object.keys(volatility).map(function(k){
return volatility[k];
}));
return multiScaleTrendEngine._c(
(harmonization * 0.4) +
((7-avgVolatility)/7 * 100 * 0.4) +
((dirConsistency/7)*100 * 0.2)
);
},
detectReversals: function(slopes, windows){
var w7slope = slopes.w7;
var w14slope = slopes.w14;
var w30slope = slopes.w30;
var shortMediumReverse = (w7slope > 0.01 && w30slope < -0.01) ||
(w7slope < -0.01 && w30slope > 0.01);
var accelChange = Math.abs(w7slope - w14slope);
var reversalProb = shortMediumReverse ? 65 + (accelChange*20) : 20 + (accelChange*10);
return {
detected: shortMediumReverse,
probability: multiScaleTrendEngine._c(reversalProb),
reason: shortMediumReverse ? 'short-vs-medium divergence' : 'normal oscillation'
};
},
computeMetaTrend: function(vectors, confidence){
var longTermDir = vectors.longTerm > 0.01 ? 'up' :
vectors.longTerm < -0.01 ? 'down' : 'flat';
var metaTrendScore = 50;
if(longTermDir==='up') {
metaTrendScore = 50 + (Math.min(vectors.longTerm*20, 30));
} else if(longTermDir==='down') {
metaTrendScore = 50 - (Math.min(-vectors.longTerm*20, 30));
}
return {
direction: longTermDir,
score: multiScaleTrendEngine._c(metaTrendScore),
confidence: confidence,
driftType: vectors.longTerm > 0.05 ? 'accelerating-up' :
vectors.longTerm < -0.05 ? 'accelerating-down' :
vectors.longTerm > 0 ? 'steady-up' :
vectors.longTerm < 0 ? 'steady-down' : 'stable'
};
},
analyze: function(){
var windows = multiScaleTrendEngine._buildWindows();
var slopes = multiScaleTrendEngine.computeWindowSlopes(windows);
var volatility = multiScaleTrendEngine.computeWindowVolatility(windows);
var directions = multiScaleTrendEngine.computeDirections(slopes);
var strengths = multiScaleTrendEngine.computeStrengths(slopes, windows);
var stabilities = multiScaleTrendEngine.computeStabilities(volatility);
var harmonization = multiScaleTrendEngine.computeHarmonization(directions);
var vectors = multiScaleTrendEngine.synthesizeTrendVectors(slopes, windows);
var momentum = multiScaleTrendEngine.computeMomentum(vectors);
var confidence = multiScaleTrendEngine.computeConfidence(harmonization, volatility, directions);
var reversals = multiScaleTrendEngine.detectReversals(slopes, windows);
var metaTrend = multiScaleTrendEngine.computeMetaTrend(vectors, confidence);
return {
timestamp: new Date().toISOString(),
windows: windows,
slopes: slopes,
directions: directions,
strengths: strengths,
volatility: volatility,
stabilities: stabilities,
harmonization: harmonization,
trendVectors: vectors,
momentum: momentum,
confidence: confidence,
reversals: reversals,
metaTrend: metaTrend
};
},
run: function(){
try {
var result = multiScaleTrendEngine.analyze();
cachePut(MST_KEY, result);
dbg('[V4 MST] analysis complete, confidence='+result.confidence);
} catch(e) {
dbg('[V4 MST] error: '+e.message);
}
}
};
