var slope = v4ProjectionEngine.computeProjectionSlope(harmonized.compositeScore, harmonized.direction);
var decayFactor = 0.5; // 50% reversion to mean
var projectedValue = baseValue * (1 + (slope * 12.0 * decayFactor)); // 6x effective slope
var band = v4ProjectionEngine.computeVolatilityBand(baseValue, harmonized.volatility, periods);
