var identityAtPhase = Math.min(100, Math.max(0, iae_m.coherence + identityShift));
var purposeShift = pve_purpose.trajectory * (endYr - startYr) / 100;
var purposeAtPhase = Math.min(100, Math.max(0, pve_purpose.clarity + purposeShift));
var ls = cacheGet('v3_lifestyle_stability') || {};
var lifestyleAtPhase = (ls.stabilityScore || 50) + identityShift * 0.3;
var wp = cacheGet('v4_wealth_projection') || {};
var wealthMidpoint = startYr + (endYr - startYr) / 2;
var wealthAtPhase = wealthMidpoint <= 5 ? (wp.projections && wp.projections.year5) :
wealthMidpoint <= 10 ? (wp.projections && wp.projections.year10) :
wealthMidpoint <= 20 ? (wp.projections && wp.projections.year20) :
(wp.projections && wp.projections.year30);
var hs = cacheGet('v4_household_sync') || {};
var householdAtPhase = {
expectedMembers: (hs.households || []).length,
likelyChanges: endYr > 10 ? 'family formation' : endYr > 20 ? 'empty nest' : 'stable'
};
var gw = cacheGet('v4_generational_wealth') || {};
var genAtPhase = gw.plan && gw.plan.year100NominalNW || 0;
var le = cacheGet('v4_life_events') || {};
