IMP.preview.filter(function(t){return !t._isDupe;}).forEach(function(t){
if(detectRecurring && detectRecurring(t)) recurCount++;
});
var parts = [];
if(newTxs>0)     parts.push(newTxs+' new transactions to import');
if(dupes>0)      parts.push(dupes+' duplicates will be skipped');
if(recurCount>0) parts.push(recurCount+' possible recurring patterns detected');
if(parts.length){ el.style.display='block'; el.className='bills-insight bic-slide-in-up bic-slide-d0'; el.innerHTML=parts.join(' &nbsp;&middot;&nbsp; '); }
else el.style.display='none';
