var hhId = _v2Household.id;
var cloudOk = true;
var cloudErrMsg = '';
try {
// Delete every sync_items row for this household across the tables
// clearAll() resets locally — transactions, goals, budgets,
// recurring_rules, accounts. Scoped strictly to this household_id;
// RLS also enforces the caller can only ever touch their own household.
var r = await client.from('sync_items')
.delete()
.eq('household_id', hhId)
.in('table_name', ['transactions','goals','budgets','recurring_rules','accounts']);
if(r.error) throw r.error;
writeAudit('cloud_data_cleared', null, { household_id: hhId });
} catch(e) {
cloudOk = false;
cloudErrMsg = e.message || 'Unknown error';
dbg('[_clearAllWithCloud] cloud delete failed: ' + cloudErrMsg);
}
if(!cloudOk) {
// Don't silently wipe local state if the cloud delete failed — that
// would leave local empty and cloud full, guaranteeing the exact
// "cleared data reappears after sync" problem this fix exists to
// prevent. Tell the user plainly and stop here.
toast('&#9888; Could not delete cloud data (' + cloudErrMsg + '). Local data was NOT cleared — please try again.');
return;
}
