      var aJson   = JSON.stringify(payload).replace(/"/g,'&quot;');
      return '<div class="ap-action-card blocked" id="action-card-' + actEsc(action.id||'blk') + '">'
        + '<div class="ap-action-card-hdr">'
          + '<div class="ap-action-card-left">'
            + '<div class="ap-action-badge blocked">&#128683; Blocked</div>'
            + '<div class="ap-action-title">' + actEsc(action.description || action.type || 'Blocked Action') + '</div>'
            + '<div class="ap-action-desc">Rule: ' + actEsc(b.ruleCode||'SAFETY_RULE') + '</div>'
            + '<div class="ap-action-meta">' + actEsc(b.reason||'Blocked by safety engine') + '</div>'
          + '</div>'
          + (action.amount>0 ? '<div class="ap-action-amount" style="color:#f87171">'+actFmt(action.amount)+'</div>' : '')
