/* ---- originally inline <script>, source index.html lines 64450-64731 ---- */
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// COMPASS — bottom-sheet modal open/close + ESC handler
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
var _compassActiveModal = null;
var _compassRendered = {};

var _compassRenderMap = {
  'cmodal-analytics': ['renderAnomalies','renderAIInsights','renderForecast','renderFinancialHealthScore','renderNetWorth','renderCashInsights','renderLongTermRiskInsights'],
  'cmodal-advisor':   ['renderAIMemory','renderAdvisorThread','renderMilestones'],
  'cmodal-bills':     ['renderSubscriptions','renderBillNegotiations'],
  'cmodal-invest':    ['renderInvestmentInsights','renderRetirementInsights'],
  'cmodal-estate':    ['renderInsuranceInsights','renderEstateInsights','renderLifeEventInsights'],
  'cmodal-vault':     ['renderVault','renderTaxPrep']
};

var _compassTrigger = null;
window._compassOpen = function(id) {
  _compassClose(_compassActiveModal);
  var sheet = document.getElementById(id);
  var bd    = document.getElementById(id + '-bd');
  if (!sheet || !bd) return;
  _compassTrigger = _captureFocusTrigger();
  _compassActiveModal = id;
  bd.classList.add('open');
  sheet.classList.add('open');
  // Use CSS class only — never set touch-action on parent elements
  document.body.classList.add('cmodal-open');
  // Reset scroll to top so first tools are visible immediately
  var body = sheet ? sheet.querySelector('.cmodal-body') : null;
  if (body) body.scrollTop = 0;
  // NOTE: No body position:fixed — that causes iOS PWA touch coordinate offsets
  setTimeout(function() {
    var closeBtn = sheet.querySelector('.cmodal-close');
    if (closeBtn) closeBtn.focus();
  }, 50);
  var fns = _compassRenderMap[id] || [];
  if (fns.length) {
    setTimeout(function() {
      fns.forEach(function(fnName) {
        try { if (typeof window[fnName] === 'function') window[fnName](); }
        catch(e) { dbg('[compass] ' + fnName + ': ' + e.message); }
      });
    }, 300);
  }
};

window._compassClose = function(id) {
  if (!id) return;
  var sheet = document.getElementById(id);
  var bd    = document.getElementById(id + '-bd');
  if (sheet) sheet.classList.remove('open');
  if (bd)    bd.classList.remove('open');
  if (_compassActiveModal === id) {
    _compassActiveModal = null;
    document.body.classList.remove('cmodal-open');
    if (_compassTrigger && typeof _compassTrigger.focus === 'function' && document.contains(_compassTrigger)) _compassTrigger.focus();
    _compassTrigger = null;
  }
};


document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape' && _compassActiveModal) {
    _compassClose(_compassActiveModal);
  }
});

// ── Fast-tap for modal buttons ──────────────────────────────────────
// Inside a touch-action:pan-y scroll container, iOS cancels the click
// if the finger drifts even a few px (ambiguous scroll vs tap). This
// delegated handler fires clicks directly for small-movement touches,
// making buttons respond on the first tap every time.
(function() {
  var startX = 0, startY = 0, startT = 0, tracking = false;
  document.addEventListener('touchstart', function(e) {
    var body = e.target.closest ? e.target.closest('.cmodal-body, .cmodal-hdr') : null;
    if (!body) { tracking = false; return; }
    var t = e.touches[0];
    startX = t.clientX; startY = t.clientY; startT = Date.now();
    tracking = true;
  }, {passive: true});
  document.addEventListener('touchend', function(e) {
    if (!tracking) return;
    tracking = false;
    var t = e.changedTouches[0];
    var dx = Math.abs(t.clientX - startX);
    var dy = Math.abs(t.clientY - startY);
    if (dx > 12 || dy > 12) return;               // was a scroll/drag
    if (Date.now() - startT > 600) return;         // long press, not a tap
    var el = e.target;
    // Let native behavior handle form controls (keyboard focus, pickers)
    var tag = (el.tagName || '').toLowerCase();
    if (tag === 'input' || tag === 'select' || tag === 'textarea' || tag === 'label') return;
    // Find nearest actionable element
    var target = el.closest ? el.closest('button, [onclick], a') : null;
    if (!target) return;
    e.preventDefault();                            // suppress delayed synthetic click
    try { target.click(); } catch(err) { dbg('[fastTap] ' + err.message); }
  }, {passive: false});
})();

// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// INSIGHTS PAGE — scoring, grouping, rendering
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

var _insShowAll = false;
var _insAllItems = [];
var INS_TOP_N = 5;

// Group config
var INS_GROUPS = [
  { key: 'overspend',  label: 'Overspending',    icon: '&#128308;', keywords: ['over', 'exceed', 'limit', 'overspend', 'above budget'] },
  { key: 'trending_up',label: 'Trending Up',     icon: '&#128200;', keywords: ['increas', 'higher', 'up ', 'rising', 'trending up', 'grew'] },
  { key: 'trending_dn',label: 'Trending Down',   icon: '&#128201;', keywords: ['decreas', 'lower', 'down ', 'fell', 'trending down', 'reduc'] },
  { key: 'volatility', label: 'Volatility',      icon: '&#9889;',   keywords: ['volatil', 'unusual', 'spike', 'swing', 'inconsist'] },
  { key: 'drift',      label: 'Category Drift',  icon: '&#128260;', keywords: ['categor', 'shift', 'drift', 'moved to', 'reclassif'] },
  { key: 'other',      label: 'Other',            icon: '&#128161;', keywords: [] }
];

function _insClassify(text) {
  if (!text) return 'other';
  var t = text.toLowerCase();
  for (var i = 0; i < INS_GROUPS.length - 1; i++) {
    var g = INS_GROUPS[i];
    for (var j = 0; j < g.keywords.length; j++) {
      if (t.indexOf(g.keywords[j]) !== -1) return g.key;
    }
  }
  return 'other';
}

function _insScore(item) {
  var severity     = (item.severity     || 0); // 0-5
  var actionability= (item.actionability|| 0); // 0-5
  var recency      = (item.recency      || 0); // 0-3
  var uniqueness   = (item.uniqueness   || 0); // 0-2
  // Infer severity from text if not provided
  if (!item.severity) {
    var t = (item.text || item.message || '').toLowerCase();
    if (t.indexOf('over') !== -1 || t.indexOf('exceed') !== -1) severity = 4;
    else if (t.indexOf('high') !== -1 || t.indexOf('spike') !== -1) severity = 3;
    else severity = 2;
  }
  return severity + actionability + recency + uniqueness;
}

function _insExpired(item) {
  if (!item.date && !item.timestamp && !item.created_at) return false;
  var d = new Date(item.date || item.timestamp || item.created_at);
  if (isNaN(d)) return false;
  return (Date.now() - d.getTime()) > 30 * 24 * 60 * 60 * 1000;
}

function _insDedupe(items) {
  var seen = {};
  return items.filter(function(item) {
    var key = (item.text || item.message || '').trim().toLowerCase().substring(0, 60);
    if (seen[key]) return false;
    seen[key] = true;
    return true;
  });
}

window.rInsightsPage = function() {
  var root = document.getElementById('ins-groups-root');
  var strip = document.getElementById('ins-summary-strip');
  var showWrap = document.getElementById('ins-showmore-wrap');
  var totalSpan = document.getElementById('ins-total-count');
  if (!root) return;

  // Gather raw insights from AppState or DOM
  var raw = [];
  try {
    if (typeof AppState !== 'undefined' && AppState.insights && AppState.insights.length) {
      raw = AppState.insights;
    } else if (typeof AppState !== 'undefined' && AppState.alerts && AppState.alerts.length) {
      raw = AppState.alerts;
    }
  } catch(e) {}

  // Fallback: scrape from alerts panel if empty
  if (!raw.length) {
    var alertsEl = document.getElementById('alerts-insights-panel') || document.getElementById('ap-insights');
    if (alertsEl && alertsEl.children.length) {
      root.innerHTML = '<div class="ins-empty">&#128161; Navigate to Alerts to seed insights, then return here.</div>';
      if (strip) strip.innerHTML = '';
      if (showWrap) showWrap.style.display = 'none';
      return;
    }
    root.innerHTML = '<div class="ins-empty">&#10003; No insights right now. Check back after syncing transactions.</div>';
    if (strip) strip.innerHTML = '';
    if (showWrap) showWrap.style.display = 'none';
    return;
  }

  // Filter expired + dedupe
  var items = _insDedupe(raw.filter(function(i) { return !_insExpired(i); }));

  // Score + sort
  items.sort(function(a, b) { return _insScore(b) - _insScore(a); });
  _insAllItems = items;

  var showing = _insShowAll ? items : items.slice(0, INS_TOP_N);

  // Summary strip
  if (strip) {
    var overCount = items.filter(function(i) {
      return _insClassify(i.text || i.message || '') === 'overspend';
    }).length;
    strip.innerHTML =
      '<span class="ins-summary-pill ' + (overCount > 0 ? 'warn' : 'ok') + '">' +
        (overCount > 0 ? '&#9888; ' + overCount + ' overspend' : '&#10003; No overspend') +
      '</span>' +
      '<span class="ins-summary-pill">' + items.length + ' total insights</span>' +
      '<span class="ins-summary-pill">Top ' + Math.min(INS_TOP_N, items.length) + ' shown</span>';
  }

  // Group
  var grouped = {};
  INS_GROUPS.forEach(function(g) { grouped[g.key] = []; });
  showing.forEach(function(item) {
    var k = _insClassify(item.text || item.message || '');
    grouped[k].push(item);
  });

  // Render
  var html = '';
  INS_GROUPS.forEach(function(g) {
    var grpItems = grouped[g.key];
    if (!grpItems || !grpItems.length) return;
    html += '<div class="ins-group" id="ins-grp-' + g.key + '">';
    html += '<div class="ins-group-hdr" data-grpkey="' + g.key + '" onclick="window._insToggleGroup(this.getAttribute(\'data-grpkey\'))">';
    html += '<div class="ins-group-left">';
    html += '<span class="ins-group-icon">' + g.icon + '</span>';
    html += '<span class="ins-group-title">' + g.label + '</span>';
    html += '<span class="ins-group-badge">' + grpItems.length + '</span>';
    html += '</div>';
    html += '<span class="ins-group-chevron">&#9660;</span>';
    html += '</div>';
    html += '<div class="ins-group-body">';
    grpItems.forEach(function(item) {
      var score = _insScore(item);
      var sevClass = score >= 9 ? 'sev-high' : score >= 6 ? 'sev-med' : 'sev-low';
      var text = item.text || item.message || item.description || '';
      html += '<div class="ins-item ' + sevClass + '">';
      html += '<div class="ins-item-row">';
      html += '<span class="ins-item-icon">&#8226;</span>';
      html += '<div><div class="ins-item-text">' + text + '</div>';
      html += '<div class="ins-item-score">Score: ' + score + '</div></div>';
      html += '</div></div>';
    });
    html += '</div></div>';
  });

  root.innerHTML = html || '<div class="ins-empty">&#10003; All clear — no grouped insights to show.</div>';

  // Show more toggle
  if (showWrap && totalSpan) {
    if (items.length > INS_TOP_N && !_insShowAll) {
      showWrap.style.display = 'block';
      totalSpan.textContent = '(' + items.length + ')';
    } else {
      showWrap.style.display = 'none';
    }
  }
};

window._insToggleGroup = function(key) {
  var el = document.getElementById('ins-grp-' + key);
  if (el) el.classList.toggle('open');
};

window._insShowAll = function() {
  _insShowAll = true;
  rInsightsPage();
};

// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
// WIRE new pages into rPage dispatch map
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
(function() {
  var _origRPage = window.rPage;
  window.rPage = function(n) {
    if (n === 'Insights') { try { rInsightsPage(); } catch(e) {} return; }
    if (n === 'Compass')  { return; } // Compass is static hub, no render needed
    if (_origRPage) _origRPage(n);
  };
})();
/* ---- originally inline <script>, source index.html lines 64822-64834 ---- */
window._loadPlaidSDK = function(callback) {
  if (window.Plaid) { if(callback) callback(); return; }
  var s = document.createElement('script');
  s.src = 'https://cdn.plaid.com/link/v2/stable/link-initialize.js';
  s.onload = function() { if(callback) callback(); };
  s.onerror = function() {
    window._plaidLoadError = true;
    if(typeof toast === 'function') toast('Could not load bank connection. Check your connection.');
  };
  document.head.appendChild(s);
};
